function Addcantsleep()
	local G = getconnections or get_signal_cons
	if G then
		for G, V in pairs((G)(y.LocalPlayer.Idled)) do
			if V.Disable then
				V.Disable(V)
			elseif V.Disconnect then
				V.Disconnect(V)
			end
		end
	end
end
pcall(function()
	Addcantsleep()
end)
