u.formatShecklesNumber = function(G)
	G = tonumber(G)
	if not G then
		return "0"
	end
	local V = {
		"K";
		"M",
		"B",
		"T";
		"Qa";
		"Qi";
		"Sx",
		"Sp",
		"Oc";
		"No",
		"Dc"
	}
	local y = math.abs(G)
	if y < 1000 then
		return string.format("%.2f", G)
	end
	local Z = math.log10(y)
	local j = math.floor(Z / 3)
	if j > # V then
		return string.format("%.2e", G)
	end
	local i = 10 ^ ((j * 3))
	local c = G / i
	return string.format("%.2f%s", c, V[j])
end
