g.Currency = {
	ParseMoney = function(G)
		if not G or type(G) ~= "string" then
			return 0
		end
		local V = G:gsub("[$,%s]", "")
		V = (V:gsub("/s", "")):gsub("/min", "")
		local y, Z = V:match("^([%d%.]+)(%a*)$")
		local j = tonumber(y) or 0
		if Z and Z ~= "" then
			local V = K[Z]
			if V then
				j = j * V
			else
				warn("Ulti: Unknown suffix \'" .. (Z .. ("\' in text: " .. G)))
			end
		end
		return j
	end;
	FormatMoney = function(G)
		local V = tonumber(G)
		if not V then
			V = g.Currency.ParseMoney(G)
		end
		if not V or V == 0 then
			return "0"
		end
		if V < 1000 then
			return tostring(math.floor(V))
		end
		local y = 0
		local Z = V
		while Z >= 1000 and y < # b do
			Z = Z / 1000
			y = y + 1
		end
		local j = string.format("%.2f", Z)
		j = j:gsub("%.?0+$", "")
		return j .. b[y]
	end
}
