E.DataReplica = {
	AllBigDataKeys = {};
	Load = function(G, V)
		local Z = y.ReplicaClient
		V = tonumber(V) or 10
		if type(Z) ~= "table" or type(Z.OnNew) ~= "function" or type(Z.RequestData) ~= "function" then
			return false
		end
		if type(G) ~= "string" or G == "" then
			return false
		end
		if q.LiveReplicaConnection then
			q.LiveReplicaConnection:Disconnect()
			q.LiveReplicaConnection = nil
		end
		q.LiveReplicaData = nil
		q.LiveReplicaConnection = Z.OnNew(G, function(G)
			if type(G) ~= "table" or type(G.Data) ~= "table" then
				return
			end
			q.LiveReplicaData = G.Data
			for G in pairs(G.Data) do
				table.insert(E.DataReplica.AllBigDataKeys, G)
			end
		end)
		Z.RequestData()
		local j = os.clock()
		repeat
			task.wait()
		until q.LiveReplicaData ~= nil or os.clock() - j >= V
		if q.LiveReplicaData == nil then
			return false
		end
		return true
	end;
	GetData = function(G, V)
		local y = q.LiveReplicaData
		if type(y) ~= "table" then
			return V or nil
		end
		local Z = y[G]
		if Z == nil then
			return V or nil
		end
		return Z
	end
}
