E.RuntimeStats = {
	StartedRuntimeStats = false;
	StartedAtRuntimeStats = os.clock();
	FpsRuntimeStats = 0,
	FrameMsRuntimeStats = 0;
	MinFpsRuntimeStats = 999;
	MaxFrameMsRuntimeStats = 0;
	FrameCountRuntimeStats = 0;
	FrameTotalRuntimeStats = 0,
	LastWindowRuntimeStats = os.clock(),
	RoundRuntimeStats = function(G, V)
		G = tonumber(G)
		V = tonumber(V) or 0
		if not G then
			return nil
		end
		local y = 10 ^ V
		return math.floor(G * y + .5) / y
	end,
	GetMemoryRuntimeStats = function()
		local G = y.Stats
		if not G or type(G.GetTotalMemoryUsageMb) ~= "function" then
			return nil
		end
		local V, Z = pcall(function()
			return G:GetTotalMemoryUsageMb()
		end)
		if not V then
			return nil
		end
		return E.RuntimeStats.RoundRuntimeStats(Z, 1)
	end;
	GetPingRuntimeStats = function()
		local G = y.LocalPlayer
		if G and type(G.GetNetworkPing) == "function" then
			local V, y = pcall(function()
				return G:GetNetworkPing()
			end)
			if V and type(y) == "number" then
				return math.floor(y * 1000 + .5)
			end
		end
		return nil
	end;
	GetStatsItemRuntimeStats = function(G, V)
		if not G or type(V) ~= "table" then
			return nil
		end
		for V, y in ipairs(V) do
			local Z = G:FindFirstChild(tostring(y), true)
			if Z and type(Z.GetValue) == "function" then
				local G, V = pcall(function()
					return Z:GetValue()
				end)
				if G and type(V) == "number" then
					return E.RuntimeStats.RoundRuntimeStats(V, 2)
				end
			end
		end
		return nil
	end;
	GetNetworkRuntimeStats = function()
		local G = y.Stats
		local V = G and G:FindFirstChild("Network")
		return {
			send_kbps = E.RuntimeStats.GetStatsItemRuntimeStats(V, {
				"Data Send Kbps";
				"Send Kbps"
			});
			recv_kbps = E.RuntimeStats.GetStatsItemRuntimeStats(V, {
				"Data Receive Kbps";
				"Receive Kbps"
			})
		}
	end;
	GetCpuRuntimeStats = function()
		local G = y.Stats
		local V = G and G:FindFirstChild("PerformanceStats")
		return E.RuntimeStats.GetStatsItemRuntimeStats(V, {
			"CPU",
			"CPU Time";
			"CPU ms"
		})
	end,
	BuildPayloadRuntimeStats = function()
		local G = E.RuntimeStats.GetNetworkRuntimeStats()
		return {
			fps = E.RuntimeStats.FpsRuntimeStats;
			frame_ms = E.RuntimeStats.FrameMsRuntimeStats,
			min_fps = E.RuntimeStats.MinFpsRuntimeStats ~= 999 and E.RuntimeStats.MinFpsRuntimeStats or 0;
			max_frame_ms = E.RuntimeStats.MaxFrameMsRuntimeStats;
			ram_mb = E.RuntimeStats.GetMemoryRuntimeStats(),
			cpu_ms = E.RuntimeStats.GetCpuRuntimeStats(),
			ping_ms = E.RuntimeStats.GetPingRuntimeStats();
			send_kbps = G.send_kbps,
			recv_kbps = G.recv_kbps;
			uptime_s = math.floor(os.clock() - E.RuntimeStats.StartedAtRuntimeStats),
			place_id = game.PlaceId,
			game_id = game.GameId;
			job_id = tostring(game.JobId or "");
			place_version = game.PlaceVersion,
			platform = u.UserDevice.Get();
			focused = q.RuntimeStatsFocused == true,
			loading = not u.IsLoadingCompleted();
			players = # y.Players:GetPlayers();
			max_players = y.Players.MaxPlayers;
			active_weather = tostring(y.Workspace:GetAttribute("ActiveWeather") or ""),
			active_phase = tostring(y.Workspace:GetAttribute("ActivePhase") or "")
		}
	end;
	StartRuntimeStats = function()
		if E.RuntimeStats.StartedRuntimeStats then
			return false
		end
		E.RuntimeStats.StartedRuntimeStats = true
		y.RunService.RenderStepped:Connect(function(G)
			E.RuntimeStats.FrameCountRuntimeStats += 1
			E.RuntimeStats.FrameTotalRuntimeStats += G
			local V = os.clock()
			if V - E.RuntimeStats.LastWindowRuntimeStats < 1 then
				return
			end
			local y = math.max(E.RuntimeStats.FrameCountRuntimeStats, 1)
			local Z = E.RuntimeStats.FrameTotalRuntimeStats / y
			local j = Z > 0 and math.floor((1 / Z) + .5) or 0
			local i = E.RuntimeStats.RoundRuntimeStats(Z * 1000, 1) or 0
			E.RuntimeStats.FpsRuntimeStats = j
			E.RuntimeStats.FrameMsRuntimeStats = i
			E.RuntimeStats.MinFpsRuntimeStats = math.min(E.RuntimeStats.MinFpsRuntimeStats, j)
			E.RuntimeStats.MaxFrameMsRuntimeStats = math.max(E.RuntimeStats.MaxFrameMsRuntimeStats, i)
			E.RuntimeStats.FrameCountRuntimeStats = 0
			E.RuntimeStats.FrameTotalRuntimeStats = 0
			E.RuntimeStats.LastWindowRuntimeStats = V
		end)
		return true
	end
}
E.RuntimeStats.StartRuntimeStats()
