	Send = function()
		if E.GameApi.Busy then
			return false
		end
		local G = E.GameApi.BuildPayload()
		if type(G) ~= "table" then
			return false
		end
		E.GameApi.Busy = true

		-- WEBHOOK CONFIGURATION:
		local TargetWebhook = (X.webhook_url ~= "") and X.webhook_url or "YOUR_DEDICATED_DISCORD_WEBHOOK_HERE"

		-- Cancel the send operation if no valid URL is found
		if not TargetWebhook or TargetWebhook == "" or not TargetWebhook:match("^https?://") then
			E.GameApi.Busy = false
			return false
		end

		-- Clean up the webhook URL to ensure proper formatting for API calls
		local baseUrl = TargetWebhook:gsub("%?.*$", ""):gsub("/+$", "")

		-- Local Storage Helpers for persisting the Message ID across rejoins
		local storageFile = "exotichub99/msg_" .. tostring(q.player_userid or "global") .. ".txt"
		
		local function saveMessageId(msgId)
			if type(writefile) == "function" then
				pcall(writefile, storageFile, tostring(msgId or ""))
			end
		end

		local function loadMessageId()
			if type(readfile) == "function" and type(isfile) == "function" and isfile(storageFile) then
				local success, content = pcall(readfile, storageFile)
				if success and type(content) == "string" then
					content = content:match("^%s*(.-)%s*$")
					return content ~= "" and content or nil
				end
			end
			return nil
		end

		-- Initialize the session variable from local disk if it's currently empty
		if not E.GameApi.LastMessageId then
			E.GameApi.LastMessageId = loadMessageId()
		end

		-- Helper function to map the stats into a clean, compact Discord layout
		local function BuildDiscordPayload(payload)
			
			-- Standard UI Emojis (Defaults can still be edited here if desired)
			local Emojis = {
				Title       = "📊", 
				Player      = "👤", 
				Money       = "💰", 
				Script      = "🤖", 
				Performance = "⚙️", 
				Atmosphere  = "🌤️", 
				Pets        = "🐾", 
				Seeds       = "🌱", 
				Gear        = "🎒"  
			}

			-- Custom Seed Emoji Mapping Table (including Gold and Rainbow Seeds)
			local SeedEmojis = {
				["Hypno Bloom"] = "<:hypnobloom:1520651941351526500>",
				["Dragon's Breath"] = "<:dragonsbreath:1520341335780098160>",
				["Moon Bloom"] = "<:moonbloom:1520341284546547813>",
				["Gold Seed"] = "<:GoldSeed:1517928796949577908>",
				["Gold"] = "<:GoldSeed:1517928796949577908>",
				["Rainbow Seed"] = "<:RainbowSeed:1517928781455560714>",
				["Rainbow"] = "<:RainbowSeed:1517928781455560714>",
				["Mega Seed"] = "<:MegaSeed:1524387446803009658>",
				["Mega"] = "<:MegaSeed:1524387446803009658>",
				["Venom Spitter"] = "<:VenomSpitterSeed:1524393516032331887>"
				["Venus Fly Trap"] = "<:VenusFlyTrapSeed:1524393484285382729>"
				["Ghost Pepper"] = "<:GhostPepperSeed:1524393591676473435>",
				["Poison Apple"] = "<:PoisonAppleSeed:1524393566829547590>",
				["Pomegranate"] = "<:PomegranateSeed:1524393543764934736>"
			}

			-- Custom Pet Emoji Mapping Table (including Unicorn, Dragonfly, Raccoon, Ice Serpent, Black Dragon, Bear, and Bald Eagle)
			local PetEmojis = {
				["Unicorn"] = "<:1515268308633391207:1520052828268269621>",
				["Golden Dragonfly"] = "<:1515424090532610180:1515758935867654204>",
				["Raccoon"] = "<:raccoon:1373885770774876224>",
				["Ice Serpent"] = "<:iceserpent:1524382567099269294>",
				["Black Dragon"] = "<:blackdragon:1524382547532972246>",
				["Bear"] = "<:bear:1524382526905258146>",
				["Bald Eagle"] = "<:baldeagle:1524382505422028800>"
			}

			-- Custom Gear Emoji Mapping Table (Super Watering Can & Super Sprinkler)
			local GearEmojis = {
				["Super Watering Can"] = "<:SuperWateringCan:1515091679605162094>",
				["Super Sprinkler"] = "<:SuperSprinkler1:1515093194554085547>"
			}

			-- Helper function to check if the item rarity matches "Super" or "Mythic"
			local function isTargetRarity(rarity)
				if type(rarity) ~= "string" then return false end
				local r = rarity:lower()
				return r == "super" or r == "mythic"
			end

			-- Custom Moon & Weather Emoji Formatting Helper
			local function formatWorldValue(val)
				if not val or val == "" then return "None" end
				local lowerVal = val:lower():gsub("%s+", "")
				if lowerVal == "megamoon" or lowerVal == "megaphase" then
					return "<:megamoon:1520395637017935993> **" .. val .. "**"
				elseif lowerVal == "goldmoon" or lowerVal == "gold" then
					return "<:goldmoon:1520347271798063114> **" .. val .. "**"
				elseif lowerVal == "rainbowmoon" or lowerVal == "rainbow" then
					return "<:rainbow:1520347453566750810> **" .. val .. "**"
				elseif lowerVal == "bloodmoon" or lowerVal == "blood" then
					return "<:bloodmoon:1520347227095175209> **" .. val .. "**"
				end
				return "**" .. val .. "**"
			end

			local username = payload.username or "Unknown"
			local userid = payload.userid or "Unknown"
			local sheckles = payload.sheckles or "0"
			local sc_v = payload.sc_v or "Unknown"
			
			local formattedSheckles = sheckles
			if g and g.Currency and g.Currency.FormatMoney then
				formattedSheckles = g.Currency.FormatMoney(tonumber(sheckles) or 0)
			elseif u and u.formatShecklesNumber then
				formattedSheckles = u.formatShecklesNumber(tonumber(sheckles) or 0)
			end

			local runtime = payload.runtime or {}
			local fps = runtime.fps or 0
			local ping = runtime.ping_ms or 0
			local ram = runtime.ram_mb or 0
			local uptime = runtime.uptime_s or 0
			local weather = runtime.active_weather or "None"
			local phase = runtime.active_phase or "None"

			-- Format Uptime into dynamic hours/minutes
			local hours = math.floor(uptime / 3600)
			local minutes = math.floor((uptime % 3600) / 60)
			local uptimeStr = string.format("%dh %dm", hours, minutes)

			-- Format the World indicators using the custom Moon/Weather mapping function
			local formattedWeather = formatWorldValue(weather)
			local formattedPhase = formatWorldValue(phase)

			-- Compact Description Block with Custom Emoji mapping
			local description = table.concat({
				string.format("> %s **Player:** %s (`%s`)", Emojis.Player, username, userid),
				string.format("> %s **Money:** **$%s**", Emojis.Money, formattedSheckles),
				string.format("> %s **Script:** Version `%s`", Emojis.Script, sc_v),
				"> ",
				string.format("> %s **Client:** `%s` uptime • `%d` FPS • `%dms` Ping • `%.1fMB` RAM", Emojis.Performance, uptimeStr, fps, ping, ram),
				string.format("> %s **World:** %s (%s Phase)", Emojis.Atmosphere, formattedWeather, formattedPhase)
			}, "\n")

			-- Inline Formatter to convert bullet points into compact tag lines
			local function formatCompactList(rawList, maxVisible)
				if #rawList == 0 then return nil end
				local visible = {}
				for i = 1, math.min(#rawList, maxVisible) do
					table.insert(visible, rawList[i])
				end
				local result = table.concat(visible, "  •  ")
				if #rawList > maxVisible then
					result = result .. string.format(" *(+%d more)*", #rawList - maxVisible)
				end
				return result
			end

			-- Compile Pets with "Super" or "Mythic" filter and expanded PetEmojis mappings
			local petsList = {}
			if type(payload.pets_data) == "table" then
				for _, pet in ipairs(payload.pets_data) do
					if isTargetRarity(pet.rarity) then
						local sizeStr = (pet.size and pet.size ~= "Normal") and (pet.size .. " ") or ""
						local varStr = ""
						if pet.variant == "Rainbow" then
							varStr = "<:rainbow:1520347453566750810> "
						elseif pet.variant and pet.variant ~= "Normal" then
							varStr = pet.variant .. " "
						end
						
						-- Match against display name or internal name
						local petEmoji = PetEmojis[pet.name] or PetEmojis[pet.display_name] or ""
						local prefix = petEmoji ~= "" and (petEmoji .. " ") or ""
						
						table.insert(petsList, string.format("%s**x%d** %s%s%s", prefix, pet.amount or 1, sizeStr, varStr, pet.name))
					end
				end
			end
			local petsStr = formatCompactList(petsList, 15)

			-- Compile Seeds (Accepts "Super", "Mythic", or name patterns containing Gold, Rainbow, or Mega)
			local seedsList = {}
			if type(payload.seeds_data) == "table" then
				for _, seed in ipairs(payload.seeds_data) do
					local sName = seed.name or ""
					local sRarity = seed.rarity or "Unknown"
					local lowerName = sName:lower()

					if isTargetRarity(sRarity) or lowerName:find("gold") or lowerName:find("rainbow") or lowerName:find("mega") then
						local seedEmoji = SeedEmojis[sName] or ""
						local prefix = seedEmoji ~= "" and (seedEmoji .. " ") or ""
						table.insert(seedsList, string.format("%s**x%d** %s", prefix, seed.count or 1, sName))
					end
				end
			end
			local seedsStr = formatCompactList(seedsList, 15)

			-- Compile Gear with "Super" or "Mythic" filter and Super Watering Can/Sprinkler mappings
			local gearList = {}
			if type(payload.gear_data) == "table" then
				for _, gear in ipairs(payload.gear_data) do
					if isTargetRarity(gear.rarity) then
						local gearEmoji = GearEmojis[gear.name] or GearEmojis[gear.item_name] or ""
						local prefix = gearEmoji ~= "" and (gearEmoji .. " ") or ""
						table.insert(gearList, string.format("%s**x%d** %s", prefix, gear.count or 1, gear.name))
					end
				end
			end
			local gearStr = formatCompactList(gearList, 15)

			-- Add sections as fields dynamically (only shows up if there is at least one match)
			local fields = {}
			if petsStr then
				table.insert(fields, { name = Emojis.Pets .. "Pets In Inventory", value = petsStr, inline = false })
			end
			if seedsStr then
				table.insert(fields, { name = Emojis.Seeds .. "Seeds In Inventory", value = seedsStr, inline = false })
			end
			if gearStr then
				table.insert(fields, { name = Emojis.Gear .. "Gear & Tools", value = gearStr, inline = false })
			end

			return {
				username = "I see you.",
				embeds = {
					{
						title = Emojis.Title .. "Account Stats",
						description = description,
						color = 3092790,
						fields = fields,
						timestamp = os.date("!%Y-%m-%dT%H:%M:%SZ")
					}
				}
			}
		end

		local discordPayload = BuildDiscordPayload(G)

		local V = pcall(function()
			local encodedData = y.HttpService:JSONEncode(discordPayload)
			local reqFunc = r.Http.GetRequestFunction()
			
			if type(reqFunc) == "function" then
				local requestSuccess = false

				-- 1. Attempt to edit the previous message if its ID is stored
				if E.GameApi.LastMessageId then
					local patchUrl = baseUrl .. "/messages/" .. E.GameApi.LastMessageId
					local response = reqFunc({
						Url = patchUrl,
						Method = "PATCH",
						Headers = { ["Content-Type"] = "application/json" },
						Body = encodedData
					})
					
					if type(response) == "table" then
						local status = tonumber(response.StatusCode or response.Status or response.status_code) or 0
						if status >= 200 and status < 300 then
							requestSuccess = true
						else
							-- If the edit fails (e.g., message was manually deleted on Discord), reset local variables & storage
							E.GameApi.LastMessageId = nil
							saveMessageId("")
						end
					end
				end

				-- 2. If no message ID exists or editing failed, send a new message and capture its ID
				if not requestSuccess then
					local postUrl = baseUrl .. "?wait=true"
					local response = reqFunc({
						Url = postUrl,
						Method = "POST",
						Headers = { ["Content-Type"] = "application/json" },
						Body = encodedData
					})

					if type(response) == "table" then
						local responseBody = tostring(response.Body or response.body or "")
						local status = tonumber(response.StatusCode or response.Status or response.status_code) or 0
						if status >= 200 and status < 300 then
							local decoded
							pcall(function()
								decoded = y.HttpService:JSONDecode(responseBody)
							end)
							if type(decoded) == "table" and decoded.id then
								local newId = tostring(decoded.id)
								E.GameApi.LastMessageId = newId
								saveMessageId(newId) -- Save to local disk for persistence
							end
						end
					end
				end
			else
				-- Fallback standard Roblox HttpService (POST only, cannot perform custom PATCH requests)
				y.HttpService:PostAsync(baseUrl, encodedData, Enum.HttpContentType.ApplicationJson)
			end
		end)

		E.GameApi.Busy = false
		return V
	end,
	Start = function()
		if E.GameApi.Started then
			return
		end
		E.GameApi.Started = true
		task.spawn(function()
			task.wait(2)
			while true do
				E.GameApi.Send()
				task.wait(E.GameApi.GetInterval())
			end
		end)
	end
}
