E.Data = {
	GetRarityColor = function(G)
		local V = "#FFFFFF"
		local Z = y and y.RarityVisuals
		if type(Z) ~= "table" or type(Z.GetStaticColor) ~= "function" or type(G) ~= "string" or G == "" then
			return V
		end
		local j = Z.GetStaticColor(G)
		if typeof(j) ~= "Color3" then
