u.GetAssetId = function(G)
	if G == nil then
		return 0
	end
	if type(G) == "number" then
		return math.floor(G)
	end
	if typeof(G) == "Instance" then
		if G:IsA("StringValue") then
			G = G.Value
		elseif G:IsA("ImageLabel") or G:IsA("ImageButton") then
			G = G.Image
		else
			return 0
		end
	end
	G = tostring(G or "")
	if G == "" then
		return 0
	end
	return tonumber(G:match("%d+")) or 0
end
