			local Z = q.RarityRank[tostring(V.rarity or "")] or 0
			if y ~= Z then
				return y > Z
			end
			if tonumber(G.price) ~= tonumber(V.price) then
				return ((tonumber(G.price) or 0)) > ((tonumber(V.price) or 0))
			end
