	GetToolPriceBackpackFruitPriceEsp = function(G)
		local V = E.BackpackFruitPriceEsp.BuildFruitDataBackpackFruitPriceEsp(G)
		if not V or V.calcName == "" or type(E.BuySelectFruit) ~= "table" or type(E.BuySelectFruit.GetEstimatedPriceBuySelectFruit) ~= "function" then
			return 0, 1, "none"
		end
		local y, Z, j = E.BuySelectFruit.GetEstimatedPriceBuySelectFruit(V.calcName, V.sourceData, V.mutation)
		return math.max(math.floor(tonumber(y) or 0), 0), tonumber(Z) or 1, tostring(j or "none")
	end;
	BuildToolBucketsBackpackFruitPriceEsp = function()
		local G = {}
		local V = {}
		for y, Z in ipairs(E.Backpack.GetBackpackAllItems()) do
			if typeof(Z) ~= "Instance" or V[Z] then
				continue
			end
			V[Z] = true
			local j = E.BackpackFruitPriceEsp.BuildFruitDataBackpackFruitPriceEsp(Z)
			if not j then
				continue
			end
			local i, c, J = E.BackpackFruitPriceEsp.GetToolPriceBackpackFruitPriceEsp(Z)
			local T = tostring(j.displayName) .. ("||" .. tostring(j.weightText))
			local d = tostring(j.displayName) .. "||"
			local u = {
				item = Z;
				displayName = j.displayName,
				weightText = j.weightText;
				price = i,
				multiplier = c;
				tier = J;
				signature = tostring(j.id) .. ("|" .. (tostring(i) .. ("|" .. (tostring(c) .. ("|" .. tostring(J))))))
			}
			if not G[T] then
				G[T] = {}
			end
			table.insert(G[T], u)
			if T ~= d then
				if not G[d] then
					G[d] = {}
				end
				table.insert(G[d], u)
			end
		end
		for G, V in pairs(G) do
			table.sort(V, function(G, V)
				return tostring(G.signature or "") < tostring(V.signature or "")
			end)
			V._index = 0
		end
		return G
	end;
	GetSlotFruitKeyBackpackFruitPriceEsp = function(G)
