		local Z = E.BackpackFruitPriceEsp.CleanTextBackpackFruitPriceEsp(V and V.Text or "")
		local j = E.BackpackFruitPriceEsp.CleanTextBackpackFruitPriceEsp(y and y.Text or "")
		if Z == "" or j == "" or not (j:lower()):find("kg", 1, true) then
			return "", ""
		end
		return Z .. ("||" .. j), Z .. "||"
	end,
