	BuildInventoryTotalBackpackFruitPriceEsp = function()
		local G = 0
		local V = 0
		local y = 0
		local Z = {}
		if type(E.BuySelectFruit) == "table" and type(E.BuySelectFruit.EnsureFruitStockReadyBuySelectFruit) == "function" then
			E.BuySelectFruit.EnsureFruitStockReadyBuySelectFruit(false)
		end
		for j, i in ipairs(E.Backpack.GetBackpackAllItems()) do
			if typeof(i) ~= "Instance" or Z[i] then
				continue
			end
			Z[i] = true
			local c = E.BackpackFruitPriceEsp.BuildFruitDataBackpackFruitPriceEsp(i)
			if not c then
				continue
			end
			V += 1
			local J = E.BackpackFruitPriceEsp.GetToolPriceBackpackFruitPriceEsp(i)
			J = math.max(math.floor(tonumber(J) or 0), 0)
			if J > 0 then
				y += 1
				G += J
			end
		end
		return G, V, y
	end,
	RefreshTotalValueBackpackFruitPriceEsp = function()
		if X.backpack_fruit_total_value_esp_enabled ~= true then
			E.BackpackFruitPriceEsp.ClearTotalLabelBackpackFruitPriceEsp()
			return false
		end
		local G, V, y = E.BackpackFruitPriceEsp.BuildInventoryTotalBackpackFruitPriceEsp()
		local Z = E.BackpackFruitPriceEsp.FormatPriceBackpackFruitPriceEsp(G)
		local j = E.BackpackFruitPriceEsp.GetOrCreateTotalLabelBackpackFruitPriceEsp()
		if j then
			j.Text = string.format("<font color=\'#FFD700\'>Inventory Value:</font> <font color=\'#7CFC00\'>$%s</font> <font color=\'#FFFFFF\'>(%d fruits)</font>", Z, V)
			j.Visible = true
		end
		E.BackpackFruitPriceEsp.LastTotalShownBackpackFruitPriceEsp = V
		E.BackpackFruitPriceEsp.SetTotalStatusBackpackFruitPriceEsp(string.format("$%s from %d fruit%s", Z, V, V == 1 and "" or "s"), y > 0 and "#7CFC00" or "#FFCC66")
		return true
	end,
	RefreshBackpackFruitPriceEsp = function()
		if X.backpack_fruit_price_esp_enabled ~= true then
			if E.BackpackFruitPriceEsp.LastShownBackpackFruitPriceEsp > 0 then
				E.BackpackFruitPriceEsp.ClearLabelsBackpackFruitPriceEsp()
			end
			E.BackpackFruitPriceEsp.RefreshTotalValueBackpackFruitPriceEsp()
			return false
		end
		if type(E.BuySelectFruit) == "table" and type(E.BuySelectFruit.EnsureFruitStockReadyBuySelectFruit) == "function" then
			E.BuySelectFruit.EnsureFruitStockReadyBuySelectFruit(false)
		end
		local G = E.BackpackFruitPriceEsp.BuildToolBucketsBackpackFruitPriceEsp()
		local V = 0
		for y, Z in ipairs(E.BackpackFruitPriceEsp.GetSlotsBackpackFruitPriceEsp()) do
			local j, i = E.BackpackFruitPriceEsp.GetSlotFruitKeyBackpackFruitPriceEsp(Z)
			local c = j ~= "" and G[j] or nil
			if ((not c or c._index >= # c)) and i ~= "" then
				c = G[i]
			end
			if not c or c._index >= # c then
				E.BackpackFruitPriceEsp.RemoveSlotLabelBackpackFruitPriceEsp(Z)
				continue
			end
			c._index += 1
			local J = c[c._index]
			if not J or ((tonumber(J.price) or 0)) <= 0 then
				E.BackpackFruitPriceEsp.RemoveSlotLabelBackpackFruitPriceEsp(Z)
				continue
			end
			local T = E.BackpackFruitPriceEsp.GetOrCreateLabelBackpackFruitPriceEsp(Z)
			if T then
				local G = E.BackpackFruitPriceEsp.FormatPriceBackpackFruitPriceEsp(J.price)
				local y = tonumber(J.multiplier) or 1
				T.Text = y ~= 1 and string.format("$%s x%s", G, tostring(math.floor(y * 100 + .5) / 100)) or "$" .. G
				T.Visible = true
				V += 1
			end
		end
		E.BackpackFruitPriceEsp.LastShownBackpackFruitPriceEsp = V
		E.BackpackFruitPriceEsp.SetStatusBackpackFruitPriceEsp(V > 0 and string.format("Showing %d fruit prices", V) or "No fruit slots found", V > 0 and "#7CFC00" or "#FFCC66")
		E.BackpackFruitPriceEsp.RefreshTotalValueBackpackFruitPriceEsp()
		return true
	end,
	StartBackpackFruitPriceEsp = function()
		local G = E.BackpackFruitPriceEsp
		if G.StartedBackpackFruitPriceEsp then
			return false
		end
		G.StartedBackpackFruitPriceEsp = true
		task.spawn(function()
			while G.StartedBackpackFruitPriceEsp and not q.is_forced_stop do
				local V, y = pcall(G.RefreshBackpackFruitPriceEsp)
				if not V then
					warn("[BackpackFruitPriceEsp]", y)
				end
				task.wait(.75)
			end
			G.ClearLabelsBackpackFruitPriceEsp()
			G.ClearTotalLabelBackpackFruitPriceEsp()
		end)
		return true
	end
}
E.WeatherTriggers = {
	CachedAllOptionsWeatherTriggers = nil,
	CachedTimeCycleOptionsWeatherTriggers = nil;
	CachedWeatherOptionsWeatherTriggers = nil;
	CachedPhaseLookupWeatherTriggers = nil,
	CachedTimeCycleLookupWeatherTriggers = nil,
	CachedWeatherLookupWeatherTriggers = nil;
	NormaliseWeatherTriggers = function(G)
		return ((tostring(G or "")):lower()):gsub("%s+", "")
	end,
	AddNameWeatherTriggers = function(G, V, y)
		y = (tostring(y or "")):match("^%s*(.-)%s*$") or ""
		if y == "" then
			return false
		end
		local Z = E.WeatherTriggers.NormaliseWeatherTriggers(y)
		if Z == "" or V[Z] then
			return false
		end
		V[Z] = y
		table.insert(G, y)
		return true
	end;
	AddInstanceNamesWeatherTriggers = function(G, V, y)
		if not y or not y.Parent then
			return false
		end
		local Z = y:GetChildren()
		table.sort(Z, function(G, V)
			return tostring(G.Name or "") < tostring(V.Name or "")
		end)
		for y, Z in ipairs(Z) do
			if Z:IsA("ModuleScript") or Z:IsA("Folder") then
				E.WeatherTriggers.AddNameWeatherTriggers(G, V, Z.Name)
			end
		end
		return true
	end;
	GetControllerRootWeatherTriggers = function(G)
		local V = y.LocalPlayer and y.LocalPlayer:FindFirstChild("PlayerScripts")
		local Z = V and V:FindFirstChild("Controllers")
		return Z and Z:FindFirstChild(G) or nil
	end;
	BuildTimeCycleOptionsWeatherTriggers = function()
		local G = {}
		local V = {}
		local Z = {}
		local j = y.TimeCycleData and y.TimeCycleData.Data
		local i = {}
		if type(j) == "table" then
			for G, V in pairs(j) do
				if type(G) == "string" and G ~= "" then
					table.insert(i, {
						name = G;
						order = type(V) == "table" and tonumber(V.StartOrder) or 999
					})
					Z[E.WeatherTriggers.NormaliseWeatherTriggers(G)] = true
				end
			end
			table.sort(i, function(G, V)
				if G.order ~= V.order then
					return G.order < V.order
				end
				return tostring(G.name or "") < tostring(V.name or "")
			end)
			for y, Z in ipairs(i) do
				E.WeatherTriggers.AddNameWeatherTriggers(G, V, Z.name)
			end
			for y, Z in ipairs(i) do
				local i = j[Z.name]
				local c = type(i) == "table" and i.Weathers or nil
				local J = {}
				if type(c) == "table" then
					for G in pairs(c) do
						table.insert(J, tostring(G or ""))
					end
				end
				table.sort(J)
				for y, Z in ipairs(J) do
					E.WeatherTriggers.AddNameWeatherTriggers(G, V, Z)
				end
			end
		end
		local c = E.WeatherTriggers.GetControllerRootWeatherTriggers("TimeCycleController")
		local J = c and c:FindFirstChild("Phases")
		E.WeatherTriggers.AddInstanceNamesWeatherTriggers(G, V, J)
		return G, V, Z
	end;
	BuildWeatherOptionsWeatherTriggers = function()
		local G = {}
		local V = {}
		local Z = y.WeatherData and y.WeatherData.Data
		if type(Z) == "table" then
			for y, Z in ipairs(Z) do
				if type(Z) == "table" then
					E.WeatherTriggers.AddNameWeatherTriggers(G, V, Z.Name)
				end
			end
		end
		local j = E.WeatherTriggers.GetControllerRootWeatherTriggers("WeatherController")
		E.WeatherTriggers.AddInstanceNamesWeatherTriggers(G, V, j)
		return G, V
	end,
	AddSavedOptionsWeatherTriggers = function(G, V)
		E.WeatherTriggers.AddNameWeatherTriggers(G, V, X.seed_shop_trigger_name)
		E.WeatherTriggers.AddNameWeatherTriggers(G, V, X.gear_shop_trigger_name)
		E.WeatherTriggers.AddNameWeatherTriggers(G, V, X.crate_shop_trigger_name)
		local y = {
			X.water_plant_weather_selected;
			X.sprinkler_place_weather_selected,
			X.potted_weather_guard_weather_selected
		}
		for y, Z in ipairs(y) do
			if type(Z) == "table" then
				for y, Z in pairs(Z) do
					E.WeatherTriggers.AddNameWeatherTriggers(G, V, Z == true and y or Z)
				end
			end
		end
		if type(X.pet_equip_rules) == "table" then
			for y, Z in ipairs(X.pet_equip_rules) do
				if type(Z) == "table" then
					E.WeatherTriggers.AddNameWeatherTriggers(G, V, Z.triggerName)
				end
			end
		end
		return true
	end;
	EnsureOptionsWeatherTriggers = function()
		if E.WeatherTriggers.CachedAllOptionsWeatherTriggers then
			return true
		end
		local G, V, y = E.WeatherTriggers.BuildTimeCycleOptionsWeatherTriggers()
		local Z, j = E.WeatherTriggers.BuildWeatherOptionsWeatherTriggers()
		local i = {}
		local c = {}
		E.WeatherTriggers.AddNameWeatherTriggers(i, c, "Any Time")
		for G, V in ipairs(G) do
			E.WeatherTriggers.AddNameWeatherTriggers(i, c, V)
		end
		for G, V in ipairs(Z) do
			E.WeatherTriggers.AddNameWeatherTriggers(i, c, V)
		end
		E.WeatherTriggers.AddSavedOptionsWeatherTriggers(i, c)
		E.WeatherTriggers.CachedAllOptionsWeatherTriggers = i
		E.WeatherTriggers.CachedTimeCycleOptionsWeatherTriggers = G
		E.WeatherTriggers.CachedWeatherOptionsWeatherTriggers = Z
		E.WeatherTriggers.CachedPhaseLookupWeatherTriggers = y
		E.WeatherTriggers.CachedTimeCycleLookupWeatherTriggers = V
		E.WeatherTriggers.CachedWeatherLookupWeatherTriggers = j
		return true
	end,
	GetOptionsWeatherTriggers = function()
		E.WeatherTriggers.EnsureOptionsWeatherTriggers()
		local G = {}
		for V, y in ipairs(E.WeatherTriggers.CachedAllOptionsWeatherTriggers or {
			"Any Time"
		}) do
			table.insert(G, y)
		end
		return G
	end,
	GetTimeCycleOptionsWeatherTriggers = function()
		E.WeatherTriggers.EnsureOptionsWeatherTriggers()
		local G = {}
		for V, y in ipairs(E.WeatherTriggers.CachedTimeCycleOptionsWeatherTriggers or {}) do
			table.insert(G, y)
		end
		return G
	end,
	GetWeatherOptionsWeatherTriggers = function()
		E.WeatherTriggers.EnsureOptionsWeatherTriggers()
		local G = {}
		for V, y in ipairs(E.WeatherTriggers.CachedWeatherOptionsWeatherTriggers or {}) do
			table.insert(G, y)
		end
		return G
	end;
	IsTimeCyclePhaseWeatherTriggers = function(G)
		E.WeatherTriggers.EnsureOptionsWeatherTriggers()
		local V = E.WeatherTriggers.NormaliseWeatherTriggers(G)
		return V ~= "" and (E.WeatherTriggers.CachedPhaseLookupWeatherTriggers and E.WeatherTriggers.CachedPhaseLookupWeatherTriggers[V] == true)
	end;
	IsTimeCycleNameWeatherTriggers = function(G)
		E.WeatherTriggers.EnsureOptionsWeatherTriggers()
		local V = E.WeatherTriggers.NormaliseWeatherTriggers(G)
		return V ~= "" and (E.WeatherTriggers.CachedTimeCycleLookupWeatherTriggers and E.WeatherTriggers.CachedTimeCycleLookupWeatherTriggers[V] ~= nil)
	end,
	IsWeatherNameWeatherTriggers = function(G)
		E.WeatherTriggers.EnsureOptionsWeatherTriggers()
		local V = E.WeatherTriggers.NormaliseWeatherTriggers(G)
		return V ~= "" and (E.WeatherTriggers.CachedWeatherLookupWeatherTriggers and E.WeatherTriggers.CachedWeatherLookupWeatherTriggers[V] ~= nil)
	end;
	IsSelectionEmptyWeatherTriggers = function(G)
		if type(G) ~= "table" then
			return true
		end
		for G, V in pairs(G) do
			if V == true or type(G) == "number" and tostring(V or "") ~= "" then
				return false
			end
		end
		return true
	end;
	IsSelectedWeatherTriggers = function(G, V)
		V = tostring(V or "")
		if V == "" or type(G) ~= "table" then
			return false
		end
		if G[V] == true then
			return true
		end
		for G, y in pairs(G) do
			if tostring(y or "") == V then
				return true
			end
		end
		return false
	end,
	ForEachSelectedWeatherTriggers = function(G, V)
		if type(G) ~= "table" or type(V) ~= "function" then
			return false
		end
		local y = {}
		for G, Z in pairs(G) do
			local j = Z == true and G or Z
			j = tostring(j or "")
			local i = E.WeatherTriggers.NormaliseWeatherTriggers(j)
			if j ~= "" and not y[i] then
				y[i] = true
				if V(j) == true then
					return true
				end
			end
		end
		return false
	end,
	NamesMatchWeatherTriggers = function(G, V)
		return E.WeatherTriggers.NormaliseWeatherTriggers(G) == E.WeatherTriggers.NormaliseWeatherTriggers(V)
	end,
	GetWeatherValuesWeatherTriggers = function()
		return y.ReplicatedStorage and y.ReplicatedStorage:FindFirstChild("WeatherValues") or nil
	end;
	GetDropdownWeatherTriggers = function()
		local G = {}
		for V, y in ipairs(E.WeatherTriggers.GetOptionsWeatherTriggers()) do
			table.insert(G, {
				Text = y,
				Value = y
			})
		end
		return G
	end;
	GetCurrentTextWeatherTriggers = function()
		local G = tostring(y.Workspace:GetAttribute("ActiveWeather") or "")
		local V = tostring(y.Workspace:GetAttribute("ActivePhase") or "")
		if G ~= "" and V ~= "" then
			return G .. (" / " .. V)
		end
		if G ~= "" then
			return G
		end
		if V ~= "" then
			return V
		end
		return "None"
	end;
	IsTriggerActiveWeatherTriggers = function(G)
		G = tostring(G or "")
