		local G = E.WeatherTriggers and (E.WeatherTriggers.GetWeatherValuesWeatherTriggers and E.WeatherTriggers.GetWeatherValuesWeatherTriggers())
		if G and (E.WeatherTriggers and type(E.WeatherTriggers.GetOptionsWeatherTriggers) == "function") then
			for V, y in ipairs(E.WeatherTriggers.GetOptionsWeatherTriggers()) do
