	GetSquareSortDataFarmGrid = function(G, V)
		if type(G) ~= "table" or typeof(V) ~= "Vector3" or typeof(G.areaCFrame) ~= "CFrame" then
			return math.huge, math.huge, math.huge, math.huge
		end
		local y = math.max(tonumber(E.FarmGrid.SpacingFarmGrid) or .5, .05)
		local Z = G.areaCFrame:PointToObjectSpace(V)
		local j = tonumber(G.gridMinX) or G.localPosition.X
		local i = tonumber(G.gridMaxX) or G.localPosition.X
		local c = tonumber(G.gridMinZ) or G.localPosition.Z
		local J = tonumber(G.gridMaxZ) or G.localPosition.Z
		Z = Vector3.new(math.clamp(Z.X, j, i), Z.Y, math.clamp(Z.Z, c, J))
		local T = E.FarmGrid.RoundGridOffsetFarmGrid(((G.localPosition.X - Z.X)) / y)
