		table.clear(q.FarmGridSpots)
		local y = E.FarmGrid.EdgePaddingFarmGrid
		local Z = E.FarmGrid.SpacingFarmGrid
		for V, j in ipairs(V) do
			local i = j.area
			local c = math.max(i.Size.X - y * 2, 0)
			local J = math.max(i.Size.Z - y * 2, 0)
			local T = math.max(math.floor(c / Z + .0001), 0)
			local d = math.max(math.floor(J / Z + .0001), 0)
			local u = 2
			local g = - ((((T - 1)) * Z)) / 2
			local a = - ((((d - 1)) * Z)) / 2 + u
			local H = g + ((T - 1)) * Z
			local r = a + ((d - 1)) * Z
			for V = 1, T, 1 do
				for y = 1, d, 1 do
					local c = Vector3.new(g + ((V - 1)) * Z, i.Size.Y / 2, a + ((y - 1)) * Z)
					local J = i.CFrame:PointToWorldSpace(c)
					local T = {
						index = 0,
						areaName = i.Name;
						areaSide = j.side,
