		if not V then
			return G
		end
		local Z, j = pcall(function()
			return V:GetFriendsOnlineAsync(200)
		end)
		if not Z or type(j) ~= "table" then
			return G
		end
		for V, y in ipairs(j) do
			if type(y) ~= "table" then
