			return nil
		end
		local Z = s.Hop.Random:NextInteger(1, # V)
		local j = V[Z]
		local i = tostring(j.id or "")
		if i == "" then
			return nil
		end
		s.Hop.TriedServers[i] = true
		print(string.format("[Hop] Random server: %s (%d/%d) | Pool: %d", i, tonumber(j.playing) or 0, tonumber(j.maxPlayers) or 0, # V))
		return i, j
	end;
