	RunDoubleOrNothingSeller = function(G, V)
		if E.DoubleOrNothingSeller.PendingCashOutDoubleOrNothingSeller then
			return E.DoubleOrNothingSeller.CashOutDoubleOrNothingSeller(E.DoubleOrNothingSeller.PendingInfoDoubleOrNothingSeller)
		end
		if X.auto_double_or_nothing ~= true then
			E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller("")
			return false, "disabled"
		end
		if not q.GetCheckIfPro() then
			E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller("Premium only", "#FF6666")
			return false, "not_pro"
		end
		if os.clock() < E.DoubleOrNothingSeller.RetryAtDoubleOrNothingSeller then
			return false, "retry_wait"
		end
		if not u.IsLoadingCompleted() then
			E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller("Waiting for loading", "#FFCC66")
			return false, "loading"
		end
		G = math.max(math.floor(tonumber(G or E.PlayerData.GetFruitCount()) or 0), 0)
		if G <= 0 then
			E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller("")
			return false, "no_fruits"
		end
		V = V == true or E.FruitCollect.IsMaxFruitInventory()
		if not V then
			E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller(string.format("Waiting full inventory %d/%d", G, E.PlayerData.GetMaxFruitCapacity()), "#FFD966")
			return false, "waiting_full"
		end
		if ((tonumber(E.Money.GetSheckles()) or 0)) <= 0 then
			E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller("Need sheckles first", "#FFCC66")
			return false, "no_sheckles"
		end
		local y = E.DoubleOrNothingSeller.PreviewDoubleOrNothingSeller(G)
		if y.fruitCount <= 0 then
			E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller("No fruits to double", "#FFCC66")
			return false, "preview_empty"
		end
		local Z = E.DoubleOrNothingSeller.GetTargetDoubleOrNothingSeller()
		local j = E.DoubleOrNothingSeller.GetDelayDoubleOrNothingSeller()
		local i = 0
		local c = y.totalValue
		local J = {
			target = Z;
			streak = 0,
			fruits = y.fruitCount,
			inventoryValue = y.totalValue;
			pot = c
		}
		E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller(string.format("Starting %d streak | %d fruits | $%s", Z, y.fruitCount, E.DoubleOrNothingSeller.FormatMoneyDoubleOrNothingSeller(y.totalValue)), "#66CCFF")
		for G = 1, Z, 1 do
			if X.auto_double_or_nothing ~= true then
				if i > 0 then
					E.DoubleOrNothingSeller.AbandonDoubleOrNothingSeller()
				end
				E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller("Stopped", "#FFCC66")
				return false, "stopped"
			end
			local V, T = E.DoubleOrNothingSeller.FireRemoteDoubleOrNothingSeller("DoubleOrNothing")
			if not V then
				E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller(tostring(T), "#FF6666")
				E.DoubleOrNothingSeller.RetryAtDoubleOrNothingSeller = os.clock() + 2
				return false, T
			end
			if type(T) == "table" and T.Busted == true then
				local G = {
					target = Z;
					streak = tonumber(T.Wins) or i,
					fruits = y.fruitCount,
					inventoryValue = tonumber(T.InventoryValue or y.totalValue) or 0;
					lostValue = tonumber(T.LostValue or T.InventoryValue or c) or 0;
					canRevive = T.CanRevive == true
				}
				E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller(string.format("Lost at streak %d | -$%s", G.streak, E.DoubleOrNothingSeller.FormatMoneyDoubleOrNothingSeller(G.lostValue)), "#FF6666")
				E.DoubleOrNothingSeller.AddLogDoubleOrNothingSeller(string.format("LOSS streak %d | -$%s | fruits %d", G.streak, E.DoubleOrNothingSeller.FormatMoneyDoubleOrNothingSeller(G.lostValue), G.fruits))
				E.DoubleOrNothingSeller.SendWebhookDoubleOrNothingSeller("loss", G)
				E.DoubleOrNothingSeller.ResetPendingDoubleOrNothingSeller()
				task.wait(.35)
				return false, {
					type = "double_or_nothing_loss",
					data = G,
					raw = T
				}
			end
			if not ((type(T) == "table" and T.Won == true)) then
				local G = type(T) == "table" and tostring(T.Reason or "Rejected") or "Rejected"
				E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller("Roll rejected: " .. G, "#FFCC66")
				E.DoubleOrNothingSeller.RetryAtDoubleOrNothingSeller = os.clock() + 2
				return false, {
					type = "double_or_nothing_rejected",
					reason = G,
					raw = T
				}
			end
			i = tonumber(T.Wins) or (i + 1)
			c = tonumber(T.Pot) or c
			J.streak = i
			J.pot = c
			E.DoubleOrNothingSeller.SetStatusDoubleOrNothingSeller(string.format("Won streak %d/%d | pot $%s", i, Z, E.DoubleOrNothingSeller.FormatMoneyDoubleOrNothingSeller(c)), "#7CFC00")
			E.DoubleOrNothingSeller.AddLogDoubleOrNothingSeller(string.format("Roll won %d/%d | pot $%s", i, Z, E.DoubleOrNothingSeller.FormatMoneyDoubleOrNothingSeller(c)))
			if i >= Z then
