		return E.DoubleOrNothingSeller.CashOutDoubleOrNothingSeller(J)
	end;
	TryRunDoubleOrNothingSeller = function(G, V)
		if E.DoubleOrNothingSeller.BusyDoubleOrNothingSeller then
