			}
		end
		local Z = E.FruitFiltersDataSync.GetBaseWeight(G, y) or 0
		local j = tonumber(V.SizeMultiplier or V.SizeMulti) or 1
		local i = E.FruitFiltersDataSync.GetOvertimeForWeight(V, y)
		local c = (Z * j) * i
		return {
			weight = E.FruitFiltersDataSync.RoundWeight(c);
			grams = c;
			text = E.FruitFiltersDataSync.FormatKg(c);
