	end,
	GetPlantGrowthRate = function(G)
		if type(G) ~= "table" then
			return 0
		end
		local V = E.FruitFiltersDataSync.Now()
		local y = tonumber(G.BoostExpiresClock) or 0
		if y > 0 and V >= y then
			G.StableGrowthAmount = tonumber(G.PostBoostRate) or tonumber(G.StableGrowthAmount) or 0
			G.BoostExpiresClock = 0
		end
		return tonumber(G.StableGrowthAmount or G.GrowthRate or G.GrowRate) or 0
	end;
	EstimateStartingAge = function(G)
		if type(G) ~= "table" then
			return 0
		end
		local V = E.FruitFiltersDataSync.N(G.Age, 0)
		local y = E.FruitFiltersDataSync.N(G.MaxAge, 0)
		if y <= 0 then
			return V
		end
		local Z = E.FruitFiltersDataSync.N(G.FinishedGrowingAt, 0)
		local j = E.FruitFiltersDataSync.N(G.GrowRate or G.StableGrowthAmount or G.GrowthRate, 0)
		if Z > 0 then
			local G = E.FruitFiltersDataSync.WallNow()
			if G >= Z then
