		end
		return math.clamp(V, 0, y)
	end,
	EnsurePlant = function(G, V)
		G = tostring(G or "")
		if G == "" then
			return nil
		end
		local y = E.FruitFiltersDataSync
		local Z = y.Plants[G]
		if not Z then
			Z = {
				Id = G,
				PlantId = G;
				Fruits = {},
				CurrentAge = 0;
				StableGrowthAmount = 0;
				LastClock = y.Now(),
				AddedAt = y.Now();
				LastUpdate = y.Now()
