		q.PlantFruitEspStatusText = G ~= "" and string.format("<font color=\'%s\'>%s</font>", V, G) or ""
		local y = q.PlantFruitEspUi
		if type(y) == "table" and (y.StatusLabel and type(y.StatusLabel.SetText) == "function") then
