			return E.PlantFruitEsp.GuiFolderPlantFruitEsp
		end
		local G = y.PlayerGui and y.PlayerGui:FindFirstChild("ExoPlantFruitEsp")
		if G then
			G:Destroy()
		end
		local V = Instance.new("Folder")
