		E.PlantFruitEsp.GuiFolderPlantFruitEsp = V
		return V
	end;
	IsAnyEnabledPlantFruitEsp = function()
		return X.plant_fruit_esp_fruit_enabled == true or X.plant_fruit_esp_plant_enabled == true
	end,
	EscapeRichTextPlantFruitEsp = function(G)
		G = tostring(G or "")
		G = G:gsub("&", "&amp;")
		G = G:gsub("<", "&lt;")
		G = G:gsub(">", "&gt;")
		return G
	end;
	IsSelectionEmptyPlantFruitEsp = function(G)
		if type(G) ~= "table" then
			return true
		end
		for G, V in pairs(G) do
			if type(G) == "number" and tostring(V or "") ~= "" then
				return false
			end
			if type(G) ~= "number" and (V ~= nil and (V ~= false and tostring(G or "") ~= "")) then
				return false
			end
		end
		return true
	end,
	IsSelectedPlantFruitEsp = function(G, V)
		V = tostring(V or "")
		if V == "" or type(G) ~= "table" then
			return false
		end
		if G[V] ~= nil and G[V] ~= false then
			return true
		end
		for G, y in pairs(G) do
			if type(G) == "number" and tostring(y or "") == V then
				return true
			end
			if tostring(G or "") == V and (y ~= nil and y ~= false) then
				return true
			end
		end
		return false
	end,
	PassesNamePlantFruitEsp = function(G)
		G = tostring(G or "")
		if G == "" then
			return false
		end
		if E.PlantFruitEsp.IsSelectionEmptyPlantFruitEsp(X.plant_fruit_esp_names) then
			return true
		end
		return E.PlantFruitEsp.IsSelectedPlantFruitEsp(X.plant_fruit_esp_names, G)
	end;
	GetAllNameSelectionPlantFruitEsp = function()
		local G = {}
		for V, y in ipairs(q.AllSeedsDataTable or {}) do
			local Z = type(y) == "table" and tostring(y.name or "") or ""
			if Z ~= "" then
				G[Z] = true
			end
		end
		return G
	end;
	PassesKgPlantFruitEsp = function(G)
		G = tonumber(G) or 0
		local V = math.max(tonumber(X.plant_fruit_esp_min_kg) or 0, 0)
		local y = tonumber(X.plant_fruit_esp_max_kg) or 1000000000
		if y < V then
			return false
		end
		return G >= V and G <= y
	end;
