		G.LastCountPlantFruitEsp = {
			plants = V;
			fruits = y
		}
		G.SetStatusPlantFruitEsp(string.format("Showing %d plants / %d fruits", V, y), "#7CFC00")
		return true
	end;
	StartPlantFruitEsp = function()
		local G = E.PlantFruitEsp
		if G.StartedPlantFruitEsp then
