			if y ~= nil and (y ~= false and tostring(y) ~= "") then
				if type(G) == "number" then
					V[tostring(y)] = true
				else
					V[tostring(G)] = true
				end
			end
		end
		return V
	end;
	IsValidFruitNameFruitCollectOverrides = function(G)
