	end;
	GetOverrideSummaryFruitCollectOverrides = function(G, V)
		G = tostring(G or "")
		V = type(V) == "table" and V or E.FruitCollectOverrides.GetOverrideFruitCollectOverrides(G)
		if G == "" or type(V) ~= "table" then
			return "Invalid fruit override"
		end
		local function y(G, V)
			local y = {}
			if type(G) == "table" then
				for G, V in pairs(G) do
					if V ~= nil and (V ~= false and tostring(G or "") ~= "") then
						table.insert(y, tostring(G))
					end
				end
			end
			table.sort(y)
			return # y > 0 and table.concat(y, ", ") or V
		end
		local Z = y(V.collect_if_mutations, "Any")
		local j = y(V.dont_collect_if_mutations, "None")
		local i = V.enabled == false and "Off" or "On"
		local c = V.collect_lower_kg_fruits == true and "Yes" or "No"
		local J = V.protect_kg_range == true and "Yes" or "No"
		return string.format("%s | %s | If: %s | Block: %s | %.2f-%.2fKG | Lower: %s | Protect: %s", G, i, Z, j, tonumber(V.min_weight) or 0, tonumber(V.max_weight) or 99, c, J)
	end;
	GetSortedOverridesFruitCollectOverrides = function()
		local G = {}
		local V = type(X.collect_fruit_overrides) == "table" and X.collect_fruit_overrides or {}
		for V, y in pairs(V) do
			V = tostring(V or "")
			if V ~= "" and type(y) == "table" then
				local y = E.FruitCollectOverrides.GetOverrideFruitCollectOverrides(V)
				if y then
					table.insert(G, {
						fruitName = V,
						rule = y
					})
				end
			end
		end
		table.sort(G, function(G, V)
			return tostring(G.fruitName or "") < tostring(V.fruitName or "")
		end)
		return G
	end;
	GetOverrideUiKeyFruitCollectOverrides = function(G)
		G = tostring(G or "")
		local V = 0
		for y = 1, # G, 1 do
			V = ((V * 31 + string.byte(G, y))) % 100000000
		end
		local y = (G:gsub("[^%w_]", "_")):sub(1, 40)
		if y == "" then
			y = "fruit"
		end
		return "fruit_collect_override_active_" .. (y .. ("_" .. tostring(V)))
	end,
	SaveOverrideFruitCollectOverrides = function(G, V, y, Z, j, i, c)
		G = tostring(G or "")
		if not E.FruitCollectOverrides.IsValidFruitNameFruitCollectOverrides(G) then
			return false, "Select a fruit first"
		end
		Z = E.FruitFilters.RoundWeight(tonumber(Z) or 0)
		j = E.FruitFilters.RoundWeight(tonumber(j) or 99)
		if Z < 0 then
			return false, "Minimum KG must be 0 or more"
		end
		if j < Z then
			return false, "Maximum KG must be higher than minimum KG"
		end
		if type(X.collect_fruit_overrides) ~= "table" then
			X.collect_fruit_overrides = {}
		end
		X.collect_fruit_overrides[G] = {
			enabled = true,
			collect_if_mutations = E.FruitCollectOverrides.CopySelectionFruitCollectOverrides(V);
			dont_collect_if_mutations = E.FruitCollectOverrides.CopySelectionFruitCollectOverrides(y),
			min_weight = Z,
			max_weight = j;
			collect_lower_kg_fruits = i == true,
			protect_kg_range = c == true
		}
		E.FruitCollect.ResetBucket()
		a.Save.SaveDataSync()
		E.FruitCollectOverrides.RefreshOverridesFruitCollectOverrides()
		return true, "Fruit override saved"
	end,
	RemoveOverrideFruitCollectOverrides = function(G)
		G = tostring(G or "")
		if G == "" or type(X.collect_fruit_overrides) ~= "table" then
			return false
		end
		X.collect_fruit_overrides[G] = nil
		E.FruitCollect.ResetBucket()
		a.Save.SaveDataSync()
		E.FruitCollectOverrides.RefreshOverridesFruitCollectOverrides()
		return true
	end;
	ToggleOverrideFruitCollectOverrides = function(G, V)
		G = tostring(G or "")
		if G == "" or type(X.collect_fruit_overrides) ~= "table" or type(X.collect_fruit_overrides[G]) ~= "table" then
			return false
		end
		X.collect_fruit_overrides[G].enabled = V == true
		E.FruitCollect.ResetBucket()
		a.Save.SaveDataSync()
		E.FruitCollectOverrides.RefreshOverridesFruitCollectOverrides()
		return true
	end;
	RefreshOverridesFruitCollectOverrides = function()
		local G = q.FruitCollectOverrideUiRefs
		if type(G) == "table" and type(G.RefreshOverridesFruitCollectOverrides) == "function" then
			G.RefreshOverridesFruitCollectOverrides()
		end
		return true
	end,
	PassesOverrideFruitCollectOverrides = function(G, V, y)
		if type(G) ~= "table" or type(y) ~= "table" then
			return true
		end
		local Z = tonumber(G.w) or 0
		local j = tonumber(y.min_weight) or 0
		local i = tonumber(y.max_weight) or 99
		if y.protect_kg_range == true then
			if not E.FruitFilters.PassesWeightRange(Z, j, i) then
				return nil
			end
			local c = E.FruitCollectOverrides.GetCombinedMutationLookupFruitCollectOverrides(G, V)
			local J = not E.FruitFilters.IsSelectionEmpty(y.dont_collect_if_mutations)
			local T = not E.FruitFilters.IsSelectionEmpty(y.collect_if_mutations)
			if J and E.FruitFilters.HasSelectedMutation(y.dont_collect_if_mutations, c) then
				return false
			end
			if T and E.FruitFilters.HasSelectedMutation(y.collect_if_mutations, c) then
				return false
			end
			if J or T then
				return nil
			end
			return false
		end
		if Z < j and y.collect_lower_kg_fruits == true then
			return nil
		end
		if not E.FruitFilters.PassesWeightRange(Z, j, i) then
			return false
		end
		local c = E.FruitCollectOverrides.GetCombinedMutationLookupFruitCollectOverrides(G, V)
		if not E.FruitFilters.IsSelectionEmpty(y.dont_collect_if_mutations) then
			if E.FruitFilters.HasSelectedMutation(y.dont_collect_if_mutations, c) then
				return false
			end
		end
		if not E.FruitFilters.IsSelectionEmpty(y.collect_if_mutations) then
			return E.FruitFilters.HasSelectedMutation(y.collect_if_mutations, c)
		end
		return true
	end
}
E.ShovelTool = {
	GetTool = function()
		local G = E.Player.GetTool_Holding()
		if G and G:IsA("Tool") then
			local V = G:GetAttribute("Shovel")
			if type(V) == "string" and V ~= "" then
				return G
			end
		end
		local V = y.LocalPlayer and y.LocalPlayer:FindFirstChild("Backpack")
		if not V then
			return nil
		end
		for G, V in ipairs(V:GetChildren()) do
			if not V:IsA("Tool") then
				continue
			end
			local y = V:GetAttribute("Shovel")
			if type(y) == "string" and y ~= "" then
				return V
			end
		end
		return nil
	end,
	Equip = function()
		local G = E.ShovelTool.GetTool()
		if not G then
			return nil, false
		end
		if E.Player.IsToolHeld(G) then
			return G, false
		end
		if not E.Player.EquipTool(G) then
			return nil, false
		end
		task.wait(.3)
		if not E.Player.IsToolHeld(G) then
			return nil, false
		end
		return G, true
	end;
	Use = function(G, V, Z)
		if type(G) ~= "string" or G == "" then
			return false
		end
		if type(V) ~= "string" then
			return false
		end
		if not Z or not Z:IsA("Tool") then
			return false
		end
		if not y.Character or Z.Parent ~= y.Character then
			return false
		end
		local j = Z:GetAttribute("Shovel")
		if type(j) ~= "string" or j == "" then
			return false
		end
		local i = y.Networking and (y.Networking.Shovel and y.Networking.Shovel.UseShovel)
		if not i or type(i.Fire) ~= "function" then
			return false
		end
		local c = pcall(function()
			i:Fire(G, V, j, Z)
		end)
		task.wait(.8)
		return c
	end,
	Cleanup = function(G)
		if not G then
			return
		end
		E.Player.UnequipTools()
	end
}
q.ShovelStatusText = ""
E.ShovelFruits = {
	MaxPerLoop = 60,
	RequestDelay = .1,
	EquippedBySystem = false;
	TotalRemoved = 0;
	LastLoopRemoved = 0,
	SetStatus = function(G, V)
		G = tostring(G or "Waiting")
		V = tostring(V or "#FFFFFF")
		q.ShovelStatusText = string.format("<stroke color=\'#000000\' thickness=\'1\'><font color=\'#FFFFFF\'>\226\154\160\239\184\143 [Fruit Shovel]</font> <font color=\'%s\'>%s</font></stroke>", V, G)
	end;
	ClearStatus = function()
		q.ShovelStatusText = ""
	end,
	SetWaitingStatus = function()
		E.ShovelFruits.SetStatus(string.format("Waiting | Removed: %d", E.ShovelFruits.TotalRemoved), "#CFCFCF")
	end;
	GetMutationNames = function()
		return E.FruitFilters.GetMutationNames()
	end,
	GetVariantNames = function()
		return E.FruitFilters.GetVariantNames()
	end,
	GetFruitTypeDropdown = function()
		local G = {}
		for V, y in ipairs(q.AllSeedsDataTable) do
			if type(y) ~= "table" then
				continue
			end
			local Z = y.name
			local j = y.single == true
			if type(Z) ~= "string" or Z == "" or j then
				continue
			end
			local i = tostring(y.rarity or "Common")
			local c = E.Data.GetRarityColor(i)
			table.insert(G, {
				Text = string.format("<font color=\"#FFFFFF\">%s</font> <font color=\"%s\">%s</font>", Z, c, i);
				Value = Z
			})
		end
		return G
	end,
	GetAllFruitTypeSelection = function()
		local G = {}
		for V, y in ipairs(q.AllSeedsDataTable) do
			if type(y) ~= "table" then
				continue
			end
			local Z = y.name
			local j = y.single == true
			if type(Z) == "string" and (Z ~= "" and not j) then
				G[Z] = true
			end
		end
		return G
	end;
	SplitMutations = function(G)
		return E.FruitFilters.SplitMutations(G)
	end,
	GetVariantFromMutations = function(G)
		return E.FruitFilters.GetVariantFromMutations(G)
	end;
	HasSelectedMutation = function(G, V)
		return E.FruitFilters.HasSelectedMutation(G, V)
	end;
	PassesMutationFilters = function(G)
		return E.FruitFilters.PassesMutationSelection(G, X.shovel_mutation_whitelist, X.shovel_mutation_blacklist)
	end;
	GetShovelTool = function()
		local G = E.Player.GetTool_Holding()
		if G and G:IsA("Tool") then
			local V = G:GetAttribute("Shovel")
			if type(V) == "string" and V ~= "" then
				return G
			end
		end
		local V = y.LocalPlayer
		local Z = V and V:FindFirstChild("Backpack")
		if not Z then
			return nil
		end
		for G, V in ipairs(Z:GetChildren()) do
			if not V:IsA("Tool") then
				continue
			end
			local y = V:GetAttribute("Shovel")
			if type(y) == "string" and y ~= "" then
				return V
			end
		end
		return nil
	end;
	IsValidFruitTarget = function(G)
		if type(G) ~= "table" then
			return false
		end
		local V = tostring(G.plantId or "")
		local y = tostring(G.fruitId or "")
		local Z = tostring(G.name or "")
		if V == "" or y == "" or Z == "" then
			return false
		end
		if E.SeedData.IsSingleHarvest(Z) then
			return false
		end
		return true
	end,
	ShouldShovelFruit = function(G)
		if type(G) ~= "table" then
			return false
		end
		if not E.ShovelFruits.IsValidFruitTarget(G) then
			return false
		end
		local V = G.name
		if type(V) ~= "string" or V == "" then
			return false
		end
		local y = X.shovel_fruit_types
		if type(y) ~= "table" or not E.FruitFilters.IsSelected(y, V) then
			return false
		end
		local Z = tonumber(G.w) or 0
		local j = tonumber(X.shovel_min_weight) or 0
		local i = tonumber(X.shovel_max_weight) or 1000000000
		if G.has_weight == false or Z <= 0 then
			return false
		end
		if not E.FruitFilters.PassesWeightRange(Z, j, i) then
			return false
		end
		local c = type(G.m) == "string" and G.m or ""
		local J, T = E.FruitFilters.SplitMutations(c)
		local d = E.FruitFilters.GetFruitVariant(G, T)
		local u = X.shovel_variants
		if type(u) ~= "table" or not E.FruitFilters.IsSelected(u, d) then
			return false
		end
		if not E.ShovelFruits.PassesMutationFilters(T) then
			return false
		end
		return true
	end;
	GetMatchingFruits = function()
		local G = {}
		local V = E.FruitFilters.GetAllFruits()
		if type(V) ~= "table" then
			return G
		end
		for V, y in ipairs(V) do
			if E.ShovelFruits.ShouldShovelFruit(y) then
				table.insert(G, y)
			end
		end
		table.sort(G, function(G, V)
			return ((tonumber(G.w) or 0)) < ((tonumber(V.w) or 0))
		end)
		return G
	end;
	ShovelFruit = function(G, V)
		if type(G) ~= "table" then
			return false
		end
		if not V or not V.Parent or not V:IsA("Tool") then
			return false
		end
		local Z = y.Character
		if not Z or V.Parent ~= Z then
			return false
		end
		local j = tostring(G.plantId or "")
		local i = tostring(G.fruitId or "")
		if j == "" or i == "" then
			return false
		end
		return E.ShovelTool.Use(j, i, V)
	end,
	CleanupTool = function()
		if not E.ShovelFruits.EquippedBySystem then
			return
		end
		E.ShovelFruits.EquippedBySystem = false
		E.Player.UnequipTools()
	end;
	Run = function()
		E.ShovelFruits.LastLoopRemoved = 0
		if not X.auto_shovel_fruits then
			E.ShovelFruits.ClearStatus()
			return 0
		end
		local G = X.shovel_fruit_types
		if type(G) ~= "table" or next(G) == nil then
			E.ShovelFruits.SetStatus("Paused: select fruit types", "#FFCC66")
			return 0
		end
		local V = X.shovel_variants
		if type(V) ~= "table" or next(V) == nil then
			E.ShovelFruits.SetStatus("Paused: select a variant", "#FFCC66")
			return 0
		end
		E.ShovelFruits.SetStatus("Scanning garden...", "#66CCFF")
		local y = E.ShovelFruits.GetMatchingFruits()
		if type(y) ~= "table" or # y == 0 then
			E.ShovelFruits.SetWaitingStatus()
			return 0
		end
		E.ShovelFruits.SetStatus(string.format("Found %d matching fruit%s", # y, # y == 1 and "" or "s"), "#66CCFF")
		local Z = E.ShovelFruits.GetShovelTool()
		if not Z then
			E.ShovelFruits.SetStatus("Paused: shovel not found", "#FF6B6B")
			return 0
		end
		local j = E.Player.IsToolHeld(Z)
		if not j then
			E.ShovelFruits.SetStatus("Equipping shovel...", "#FFD966")
			local G = E.Player.EquipTool(Z)
			if not G then
				E.ShovelFruits.SetStatus("Failed to equip shovel", "#FF6B6B")
				return 0
			end
			E.ShovelFruits.EquippedBySystem = true
			task.wait(.15)
		end
		if not E.Player.IsToolHeld(Z) then
			E.ShovelFruits.CleanupTool()
			E.ShovelFruits.SetStatus("Shovel was unequipped", "#FF6B6B")
			return 0
		end
		local i = 0
		for G, V in ipairs(y) do
			if not X.auto_shovel_fruits then
				break
			end
			if i >= E.ShovelFruits.MaxPerLoop then
				break
			end
			if not E.ShovelFruits.ShouldShovelFruit(V) then
				continue
			end
			if not E.Player.IsToolHeld(Z) then
				E.ShovelFruits.SetStatus("Stopped: shovel unequipped", "#FF6B6B")
				break
			end
			local j = tostring(V.name or "Fruit")
			local c = tonumber(V.w) or 0
			E.ShovelFruits.SetStatus(string.format("Removing %s %.2fkg (%d/%d)", j, c, G, # y), "#FFAA44")
			local J = E.ShovelFruits.ShovelFruit(V, Z)
			if J then
				i += 1
				E.ShovelFruits.TotalRemoved += 1
				E.ShovelFruits.LastLoopRemoved = i
				E.ShovelFruits.SetStatus(string.format("Removed %s %.2fkg | Total: %d", j, c, E.ShovelFruits.TotalRemoved), "#7CFC00")
				task.wait(E.ShovelFruits.RequestDelay)
			end
		end
		E.ShovelFruits.CleanupTool()
		if i > 0 then
			E.ShovelFruits.SetStatus(string.format("Removed %d | Total: %d | Waiting", i, E.ShovelFruits.TotalRemoved), "#7CFC00")
		elseif X.auto_shovel_fruits then
			E.ShovelFruits.SetWaitingStatus()
		end
		return i
	end,
	LoopShovelFruits = function()
		if not X.auto_shovel_fruits then
			E.ShovelFruits.ClearStatus()
			return 0
		end
		local G, V = pcall(function()
			return E.ShovelFruits.Run()
		end)
		if not G then
			E.ShovelFruits.CleanupTool()
			E.ShovelFruits.SetStatus("Error: shovel loop failed", "#FF4444")
			warn("[ShovelFruits] Loop error:", V)
			return 0
		end
		return tonumber(V) or 0
	end
}
E.FarmDetails = {
	Label = nil,
	Busy = false,
	Started = false,
	RefreshDelay = 3,
	FormatVariant = function(G)
		G = tostring(G or "Normal")
		if G == "Gold" then
			return "<font color=\'#FFD700\'>\240\159\140\159 Gold</font>"
		end
		if G == "Rainbow" then
			return "<font color=\'#FF66FF\'>\240\159\140\136 Rainbow</font>"
		end
		return "<font color=\'#FFFFFF\'>" .. (G .. "</font>")
	end;
	FormatCount = function(G)
		local V = tostring(math.max(math.floor(tonumber(G) or 0), 0))
		while true do
			local G, y = V:gsub("^(-?%d+)(%d%d%d)", "%1,%2")
			V = G
			if y == 0 then
				break
			end
		end
		return V
	end;
	FormatWeight = function(G)
		local V = string.format("%.2f", tonumber(G) or 0)
		return V:gsub("%.?0+$", "")
	end;
	SplitMutationTextFarmDetails = function(G)
		local V = {}
		if E.ShovelFruits and type(E.ShovelFruits.SplitMutations) == "function" then
			local V, y = pcall(function()
				return E.ShovelFruits.SplitMutations(G)
			end)
			if V and type(y) == "table" then
				return y
			end
		end
		G = tostring(G or "")
		for G in G:gmatch("[^,%s]+") do
			G = tostring(G or "")
			if G ~= "" then
				table.insert(V, G)
			end
		end
		return V
	end,
	GetVariantNamesFarmDetails = function()
		if E.ShovelFruits and type(E.ShovelFruits.GetVariantNames) == "function" then
			local G, V = pcall(E.ShovelFruits.GetVariantNames)
			if G and type(V) == "table" then
				return V
			end
		end
		return {
			"Normal";
			"Gold",
			"Rainbow"
		}
	end,
	IsSingleHarvestFarmDetails = function(G)
		local V = E.FruitFiltersDataSync
		if V and type(V.IsSingleHarvestPlant) == "function" then
			return V.IsSingleHarvestPlant(G) == true
		end
		return E.SeedData.IsSingleHarvest(G) == true
	end,
	IsReadyFarmDetails = function(G, V)
		local y = E.FruitFiltersDataSync
		if type(G) ~= "table" or G.Removed then
			return false
		end
		if V and (y and type(y.IsPlantReady) == "function") then
			return y.IsPlantReady(G) == true
		end
		if not V and (y and type(y.IsFruitReady) == "function") then
			return y.IsFruitReady(G) == true
		end
		local Z = tonumber(G.Age) or 0
		local j = tonumber(G.MaxAge) or 0
		return j > 0 and Z >= j
	end;
	GetWeightFarmDetails = function(G, V, y)
		local Z = E.FruitFiltersDataSync
		if not Z or type(Z.GetWeightData) ~= "function" then
			return 0
		end
		local j, i = pcall(function()
			return Z.GetWeightData(G, V, y)
		end)
		if not j or type(i) ~= "table" then
			return 0
		end
		return tonumber(i.weight) or 0
	end;
	AddFruitDataFarmDetails = function(G, V, y, Z, j, i, c)
		local J = E.FruitFiltersDataSync
		if not J or type(G) ~= "table" or G.Removed then
			return false
		end
		local T = tostring(G.PlantName or "")
		if T == "" then
			return false
		end
		local d = y and G or V
		if type(d) ~= "table" or d.Removed then
			return false
		end
		j.totalFruits += 1
		if E.FarmDetails.IsReadyFarmDetails(d, y) then
			j.totalReady += 1
		else
			j.totalGrowing += 1
		end
		local u = E.FarmDetails.GetWeightFarmDetails(T, d, y)
		if u > Z.maxWeight then
			Z.maxWeight = u
		end
		local q = tostring(d.Mutation or G.Mutation or "")
		local g = "Normal"
		if type(J.GetVariant) == "function" then
			g = J.GetVariant(q, d.Variant or G.Variant)
		elseif q:find("Rainbow") then
			g = "Rainbow"
		elseif q:find("Gold") then
			g = "Gold"
		end
		i[g] = ((i[g] or 0)) + 1
		for G, V in ipairs(E.FarmDetails.SplitMutationTextFarmDetails(q)) do
			V = tostring(V or "")
			if V ~= "" and (V ~= "Gold" and V ~= "Rainbow") then
				c[V] = ((c[V] or 0)) + 1
			end
		end
		return true
	end,
	BuildText = function()
		local G = E.FruitFiltersDataSync
		if not G or type(G.Plants) ~= "table" then
			return "<font color=\'#AFAFAF\'>Farm data is not ready yet.</font>"
		end
		if not G.Started and type(G.StartSync) == "function" then
			G.StartSync()
		end
		local V = {}
		local y = {}
		local Z = {}
		local j = {
			totalPlants = 0;
			totalFruits = 0,
			totalReady = 0;
			totalGrowing = 0
		}
		for G, i in pairs(G.Plants) do
			if type(i) ~= "table" or i.Removed then
				continue
			end
			local c = tostring(i.PlantName or "")
			if c == "" then
				continue
			end
			local J = tostring(q.SeedRarity[c] or "Unknown")
			local T = V[J]
			if not T then
				T = {}
				V[J] = T
			end
			local d = T[c]
			if not d then
				d = {
					name = c,
					plants = 0,
					maxWeight = 0
				}
				T[c] = d
			end
			d.plants += 1
			j.totalPlants += 1
			if E.FarmDetails.IsSingleHarvestFarmDetails(c) then
				E.FarmDetails.AddFruitDataFarmDetails(i, nil, true, d, j, Z, y)
			else
				for G, V in pairs(i.Fruits or {}) do
					E.FarmDetails.AddFruitDataFarmDetails(i, V, false, d, j, Z, y)
				end
			end
		end
		if j.totalPlants <= 0 then
			return "<font color=\'#AFAFAF\'>No farm data found yet. Wait for garden load or rejoin.</font>"
		end
		local i = {}
		local c = {}
		local J = {}
		for G, V in ipairs(E.FarmDetails.GetVariantNamesFarmDetails()) do
			i[V] = G
		end
		for G, V in pairs(Z) do
			table.insert(c, {
				name = G,
				amount = V;
				order = i[G] or 0
			})
		end
		table.sort(c, function(G, V)
			if G.order ~= V.order then
				return G.order < V.order
			end
			return G.name < V.name
		end)
		for G, V in ipairs(c) do
			table.insert(J, string.format("%s <font color=\'#FFA500\'>x%s</font>", E.FarmDetails.FormatVariant(V.name), E.FarmDetails.FormatCount(V.amount)))
		end
		local T = {
			"<b><font color=\'#7CFC00\'>Farm Summary</font></b> <font color=\'#66CCFF\'>(Data)</font>\n";
			string.format("<font color=\'#FFFFFF\'>Total Plants:</font> <font color=\'#FFA500\'>x%s</font>\n", E.FarmDetails.FormatCount(j.totalPlants));
			string.format("<font color=\'#FFFFFF\'>Total Fruits:</font> <font color=\'#66CCFF\'>x%s</font>\n", E.FarmDetails.FormatCount(j.totalFruits)),
			string.format("<font color=\'#FFFFFF\'>Ready:</font> <font color=\'#7CFC00\'>x%s</font> / <font color=\'#FFAA55\'>x%s</font>\n", E.FarmDetails.FormatCount(j.totalReady), E.FarmDetails.FormatCount(j.totalGrowing)),
			string.format("<font color=\'#FFFFFF\'>Variants:</font> %s\n\n", # J > 0 and table.concat(J, "  ") or "<font color=\'#AFAFAF\'>None</font>")
		}
		local d = {}
		for G, V in pairs(V) do
			table.insert(d, {
				name = G;
				plants = V,
				rank = q.RarityRank[G] or 0
			})
		end
		table.sort(d, function(G, V)
			if G.rank ~= V.rank then
				return G.rank > V.rank
			end
			return G.name < V.name
		end)
		for G, V in ipairs(d) do
			local y = E.Data.GetRarityColor(V.name)
			local Z = {}
			for G, V in pairs(V.plants) do
				table.insert(Z, V)
			end
			table.sort(Z, function(G, V)
				if G.plants ~= V.plants then
					return G.plants > V.plants
				end
				return G.name < V.name
			end)
			table.insert(T, string.format("<b><font color=\'%s\'>%s</font></b>\n", y, V.name))
			for G, V in ipairs(Z) do
				table.insert(T, string.format("<font color=\'#FFFFFF\'>%s</font> <font color=\'#FFA500\'>x%s</font> <font color=\'#FFFF00\'>(%skg Max)</font>\n", V.name, E.FarmDetails.FormatCount(V.plants), E.FarmDetails.FormatWeight(V.maxWeight)))
			end
			table.insert(T, "\n")
		end
		local u = {}
		for G, V in pairs(y) do
			table.insert(u, {
				name = G;
				amount = V
			})
		end
		table.sort(u, function(G, V)
			if G.amount ~= V.amount then
				return G.amount > V.amount
			end
			return G.name < V.name
		end)
		if # u > 0 then
			table.insert(T, "<b><font color=\'#FF66FF\'>Mutations In Farm</font></b>\n")
			for G, V in ipairs(u) do
				table.insert(T, string.format("<font color=\'#FFFFFF\'>%s</font>: <font color=\'#FFA500\'>x%d</font>\n", V.name, V.amount))
			end
		end
		return table.concat(T)
	end;
	Update = function()
		local G = E.FarmDetails.Label
		if E.FarmDetails.Busy or not G or type(G.SetText) ~= "function" then
			return false
		end
		E.FarmDetails.Busy = true
		local V, y = pcall(E.FarmDetails.BuildText)
		E.FarmDetails.Busy = false
		if not V then
			warn("[FarmDetails]", y)
			G:SetText("<font color=\'#FF6666\'>Farm details failed to refresh.</font>")
			return false
		end
		G:SetText(y)
		return true
	end;
	Start = function()
		if E.FarmDetails.Started then
			return
		end
		E.FarmDetails.Started = true
		task.spawn(function()
			while E.FarmDetails.Started do
				E.FarmDetails.Update()
				task.wait(E.FarmDetails.RefreshDelay)
			end
		end)
	end
}
q.PlantShovelStatusText = ""
E.PlantShovel = {
	MaxPerLoop = 50,
	RequestDelay = .9,
	SetStatus = function(G, V)
		G = tostring(G or "Waiting")
		V = tostring(V or "#FFFFFF")
		q.PlantShovelStatusText = string.format("<stroke color=\'#000000\' thickness=\'1\'><font color=\'#FF5555\'>\226\154\160\239\184\143 [Plant Shovel]</font> <font color=\'%s\'>%s</font></stroke>", V, G)
	end,
	ClearStatus = function()
		q.PlantShovelStatusText = ""
	end,
	GetPlantTypeDropdown = function()
		local G = {}
		local V = E.Farm.GetPlantedSeedCounts()
		for y, Z in ipairs(q.AllSeedsDataTable) do
			if type(Z) ~= "table" then
				continue
			end
			local j = Z.name
			if type(j) ~= "string" or j == "" then
				continue
			end
			if Z.single == true then
				continue
			end
			local i = tonumber(V[j]) or 0
			local c = i > 0 and "#FFD700" or "#FF5555"
			local J = tostring(Z.rarity or "")
			local T = E.Data.GetRarityColor(J)
			table.insert(G, {
				Text = string.format("<font color=\"%s\">x%d</font> <font color=\"#FFFFFF\">%s</font> <font color=\"%s\">%s</font>", c, i, j, T, J),
				Value = j
			})
		end
		table.sort(G, function(G, y)
			local Z = tonumber(V[G.Value]) or 0
			local j = tonumber(V[y.Value]) or 0
			if Z ~= j then
				return Z > j
			end
			return tostring(G.Value) < tostring(y.Value)
		end)
		return G
	end;
	GetAllPlantTypeSelection = function()
		local G = {}
		for V, y in ipairs(q.AllSeedsDataTable) do
			if type(y) ~= "table" then
				continue
			end
			local Z = y.name
			if type(Z) ~= "string" or Z == "" then
				continue
			end
			if y.single == true then
				continue
			end
			G[Z] = true
		end
		return G
	end,
	GetPlantIdPlantShovel = function(G, V)
		return E.FruitFiltersDataSync.GetPlantIdFruitFiltersDataSync(nil, G, V)
	end,
	GetPlantNamePlantShovel = function(G, V)
		if type(G) == "table" then
			local V = tostring(G.PlantName or G.SeedName or "")
			if V ~= "" then
				return V
			end
		end
		if typeof(V) == "Instance" and V.Parent then
			return tostring(V:GetAttribute("SeedName") or V:GetAttribute("PlantName") or "")
		end
		return ""
	end,
	IsValidPlant = function(G, V)
		local y = E.PlantShovel.GetPlantNamePlantShovel(G, V)
		if type(y) ~= "string" or y == "" then
			return false, nil
		end
		if E.SeedData.IsSingleHarvest(y) then
			return false, y
		end
		if E.PlantShovel.GetPlantIdPlantShovel(G, V) == "" then
			return false, y
		end
		return true, y
	end,
	IsFullyGrown = function(G, V)
		local y = E.FruitFiltersDataSync
		if type(G) == "table" and (y and type(y.IsPlantReady) == "function") then
			local V, Z = pcall(y.IsPlantReady, G)
			if V then
				return Z == true
			end
		end
		local Z = tonumber(type(G) == "table" and ((G.Age or G.CurrentAge)) or nil)
		local j = tonumber(type(G) == "table" and G.MaxAge or nil)
		if ((not Z or not j)) and (typeof(V) == "Instance" and V.Parent) then
			Z = tonumber(V:GetAttribute("Age") or V:GetAttribute("CurrentAge") or Z)
			j = tonumber(V:GetAttribute("MaxAge") or j)
		end
		if not Z or not j or j <= 0 then
			return false
		end
		return Z >= j
	end;
	GetPlantData = function(G, V)
		local y, Z = E.PlantShovel.IsValidPlant(G, V)
		if not y then
			return nil
		end
		local j = tonumber(type(G) == "table" and ((G.Height or G.Length or G.PlantLength)) or nil)
		if not j and (typeof(V) == "Instance" and V.Parent) then
			j = tonumber(V:GetAttribute("Height") or V:GetAttribute("Length") or V:GetAttribute("PlantLength"))
		end
		local i = ""
		if type(G) == "table" then
			i = tostring(G.Mutation or G.mutation or "")
			if i == "" or i == "Normal" then
				i = tostring(G.Variant or G.variant or "")
			end
		end
		if ((i == "" or i == "Normal")) and (typeof(V) == "Instance" and V.Parent) then
			i = tostring(V:GetAttribute("Mutation") or V:GetAttribute("Variant") or V:GetAttribute("PlantVariant") or "")
		end
		if i == "Normal" or i == "nil" then
			i = ""
		end
		return {
			ob = V,
			data = G;
			id = E.PlantShovel.GetPlantIdPlantShovel(G, V);
			name = Z,
			height = j,
			mutation = i,
			grown = E.PlantShovel.IsFullyGrown(G, V)
		}
	end,
	IsVariantBlacklisted = function(G)
		local V = X.shovel_plant_variant_blacklist
		if type(V) ~= "table" or next(V) == nil then
			return false
		end
		if type(G) ~= "string" or G == "" then
			return false
		end
		return V[G]
	end;
	PassesVariant = function(G)
		local V = X.shovel_plant_variants
		if type(V) ~= "table" or next(V) == nil then
			return true
		end
		if type(G) ~= "string" or G == "" then
			return false
		end
		return V[G]
	end;
	PassesFilters = function(G)
		if type(G) ~= "table" then
			return false
		end
		local V = X.shovel_plant_types
		if type(V) ~= "table" or not V[G.name] then
			return false
		end
		local y = tonumber(X.shovel_plant_min_height) or 0
		local Z = tonumber(X.shovel_plant_max_height) or 200
		local j = tonumber(G.height)
		if j then
			if j < y or j > Z then
				return false
			end
		elseif y > 0 or Z < 200 then
			return false
		end
		if not X.shovel_growing_plants and not G.grown then
			return false
		end
		if not E.PlantShovel.PassesVariant(G.mutation) then
			return false
		end
		if E.PlantShovel.IsVariantBlacklisted(G.mutation) then
			return false
		end
		return true
	end;
	GetPlantsToShovel = function()
		local G = {}
		local V = {}
		local y = X.shovel_plant_types
		local Z = E.FruitFiltersDataSync
		if type(y) ~= "table" or not Z or type(Z.GetPlantEntriesFruitFiltersDataSync) ~= "function" then
			return G, V
		end
		for Z, j in ipairs(Z.GetPlantEntriesFruitFiltersDataSync()) do
			local i = E.PlantShovel.GetPlantData(j.data, j.physical)
			if not i or not y[i.name] then
				continue
			end
			V[i.name] = ((V[i.name] or 0)) + 1
			if E.PlantShovel.PassesFilters(i) then
				table.insert(G, i)
			end
		end
		return G, V
	end;
	ShovelPlant = function(G, V)
		if type(G) ~= "table" or type(G.id) ~= "string" or G.id == "" then
			return false
		end
		if not E.Player.IsToolHeld(V) then
			return false
		end
		return E.ShovelTool.Use(G.id, "", V)
	end;
	Run = function()
		if not X.auto_shovel_plants then
			E.PlantShovel.ClearStatus()
			return 0
		end
		local G = X.shovel_plant_types
		if type(G) ~= "table" or next(G) == nil then
			E.PlantShovel.SetStatus("Paused: select plant types", "#FFCC66")
			return 0
		end
		local V, y = E.PlantShovel.GetPlantsToShovel()
		local Z = math.max(math.floor(tonumber(X.shovel_plants_keep) or 0), 0)
		if # V == 0 then
			E.PlantShovel.SetStatus("Nothing to shovel", "#CFCFCF")
			return 0
		end
		local j
		local i = false
		local c = 0
		for G, V in ipairs(V) do
			if not X.auto_shovel_plants then
				break
			end
			if c >= E.PlantShovel.MaxPerLoop then
				break
			end
			local J = V.name
			local T = y[J] or 0
			if T <= Z then
				continue
			end
			if not j then
				j, i = E.ShovelTool.Equip()
				if not j then
					E.PlantShovel.SetStatus("Paused: shovel not found", "#FF6B6B")
					return c
				end
			end
			if not E.Player.IsToolHeld(j) then
				j, i = E.ShovelTool.Equip()
				if not j then
					break
				end
			end
			E.PlantShovel.SetStatus(string.format("Shovelling %s %d/%d", J, T, Z), "#FF5555")
			if E.PlantShovel.ShovelPlant(V, j) then
				y[J] = T - 1
				c += 1
				task.wait(E.PlantShovel.RequestDelay)
			end
		end
		E.ShovelTool.Cleanup(i)
		if c == 0 then
			E.PlantShovel.SetStatus("Nothing above keep limit", "#CFCFCF")
		end
		return c
	end,
	LoopPlantShovel = function()
		if not X.auto_shovel_plants then
			E.PlantShovel.ClearStatus()
			return 0
		end
		local G, V = pcall(function()
			return E.PlantShovel.Run()
		end)
		if not G then
			E.Player.UnequipTools()
			E.PlantShovel.SetStatus("Error: plant shovel loop failed", "#FF4444")
			warn("[PlantShovel] Loop error:", V)
			return 0
		end
		return tonumber(V) or 0
	end
}
q.TrowelRunning = false
q.TrowelStatusText = ""
q.TrowelDebugEnabled = false
q.TrowelMovedPositionCacheById = q.TrowelMovedPositionCacheById or {}
E.Trowel = {
