	end,
	GetTool = function()
		for G, V in ipairs(E.Backpack.GetBackpackAllItems()) do
			if V:IsA("Tool") and V:GetAttribute("Trowel") ~= nil then
				local G = E.StackKeepOverrides.GetGearNameFromToolStackKeepOverrides(V, "Trowel")
				local y = E.Trowel.GetTrowelCount(V)
				if not E.StackKeepOverrides.ShouldSkipItemStackKeepOverrides("Gear", G, y) then
					return V
