		return nil
	end;
	GetTrowelCount = function(G)
		if typeof(G) == "Instance" and (G.Parent and (G:IsA("Tool") and G:GetAttribute("Trowel") ~= nil)) then
			return math.max(math.floor(tonumber(G:GetAttribute("Count")) or 0), 0)
		end
		local V = 0
		for G, y in ipairs(E.Backpack.GetBackpackAllItems()) do
			if y:IsA("Tool") and y:GetAttribute("Trowel") ~= nil then
				V += math.max(math.floor(tonumber(y:GetAttribute("Count")) or 0), 0)
