			c.Positions.Rotation = Z
			c.LastUpdate = i and (type(i.Now) == "function" and i.Now()) or os.clock()
			j.replacedDataCache = true
			j.replacedDataLocalPosition = J
			j.replacedDataWorldPosition = E.Trowel.GetDataWorldPositionTrowel(c)
			j.newDataLocalPosition = E.Trowel.GetDataLocalPositionTrowel(c)
			j.newDataWorldPosition = E.Trowel.GetDataWorldPositionTrowel(c)
		end
		return c, j
	end,
	GetPlants = function(G)
		local V = {}
		local y = X.trowel_plant_types
		local Z = type(y) == "table" and next(y) ~= nil
		local j = {}
		local i = E.FruitFiltersDataSync
