	MovePlant = function(G, V, Z)
		if type(G) ~= "table" or typeof(V) ~= "Vector3" then
			return false
		end
		local j = y.Networking and (y.Networking.Trowel and y.Networking.Trowel.MovePlant)
		if not j or type(j.Fire) ~= "function" then
			return false
		end
		local i = tostring(G.id or "")
		if i == "" then
			i = E.Trowel.GetPlantIdTrowel(nil, G.data, G.physical or G.ob)
		end
		if i == "" then
			return false
		end
		local c = E.Trowel.ResolvePlantPositionTrowel(i, G.data, G.physical or G.ob)
		local J = c.dataLocalPosition or E.Trowel.GetDataLocalPositionTrowel(G.data)
		local T = c.dataWorldPosition or E.Trowel.GetDataWorldPositionTrowel(G.data)
		local d = tonumber(G.rotation)
		if not d then
			d = tonumber(c.rotation) or E.Trowel.GetPlantRotationTrowel(G.data, G.physical or G.ob)
		end
		local u = E.Trowel.GetTrowelCount(Z)
		local q = E.StackKeepOverrides.GetGearNameFromToolStackKeepOverrides(Z, "Trowel")
		if E.StackKeepOverrides.ShouldSkipItemStackKeepOverrides("Gear", q, u) then
			return false
