		return a == true
	end;
	Start = function()
		if X.auto_trowel_plants == true then
			return false
		end
		X.auto_trowel_plants = true
		E.Trowel.SetStatus("Starting...", "#66CCFF")
		a.Save.SaveDataSync()
		return true
	end;
	Stop = function(G)
		X.auto_trowel_plants = false
		q.TrowelRunning = false
		E.Player.UnequipTools()
		E.Trowel.ClearStatus()
		a.Save.SaveDataSync()
		if type(G) == "string" and G ~= "" then
			q.Notify(G, 3)
		end
	end;
	Run = function()
		local G = E.TotalControl.ResolveTrowelEnabledTotalControl() == true
		if not G and X.auto_trowel_plants ~= true then
			q.TrowelRunning = false
			E.Trowel.ClearStatus()
			return 0
		end
		local V, y = E.Trowel.GetTargetPosition()
		if not V then
			E.Trowel.SetStatus("Paused: " .. tostring(y or "target not found"), "#FFCC66")
			return 0
		end
		local Z = E.Trowel.GetPlants(V)
		if # Z == 0 then
			E.Trowel.SetStatus("No plants to move", "#CFCFCF")
			return 0
		end
		local j, i = E.Trowel.EquipTool()
		if not j then
			E.Trowel.SetStatus("Paused: trowel not found", "#FFCC66")
			return 0
		end
		q.TrowelRunning = true
		local c = 0
		local J = false
		for y, i in ipairs(Z) do
			if (not G and X.auto_trowel_plants ~= true) or c >= E.Trowel.MaxPerLoop then
				break
			end
			if not E.Player.IsToolHeld(j) then
				E.Trowel.SetStatus("Paused: trowel unequipped or ran out", "#FFCC66")
				J = true
				break
			end
			local T = E.StackKeepOverrides.GetGearNameFromToolStackKeepOverrides(j, "Trowel")
			local d = E.Trowel.GetTrowelCount(j)
			if E.StackKeepOverrides.ShouldSkipItemStackKeepOverrides("Gear", T, d) then
				E.Trowel.SetStatus("Paused: trowel not found", "#FFCC66")
				J = true
				break
			end
			E.Trowel.SetStatus(string.format("Moving %s %d/%d", i.name, y, # Z), "#FFD966")
			if E.Trowel.MovePlant(i, V, j) then
				c += 1
				task.wait(E.Trowel.RequestDelay)
			end
		end
		if i then
			E.Player.UnequipTools()
		end
		q.TrowelRunning = false
		local T = G or X.auto_trowel_plants == true
		if T and (c > 0 and not J) then
			E.Trowel.SetStatus(string.format("Moved %d/%d | Waiting", c, # Z), "#7CFC00")
		elseif T and not J then
			E.Trowel.SetStatus("No plants moved | Waiting", "#FFCC66")
		elseif not T then
			E.Trowel.ClearStatus()
		end
		return c
	end;
	Loop = function()
		local G, V = pcall(E.Trowel.Run)
		if not G then
			q.TrowelRunning = false
			E.Player.UnequipTools()
			E.Trowel.SetStatus("Error: trowel loop failed", "#FF4444")
			warn("[Trowel]", V)
			return 0
		end
		return tonumber(V) or 0
	end
}
E.FruitCollect = {
