		if not E.Teleport.LockTeleport(Z, 4, false) then
			return false, false, "Waiting: teleport busy"
		end
		E.WaterPlants.SetStatus("Moving near watering target...", "#66CCFF")
		local j = Vector3.new(V.Position.X - G.X, 0, V.Position.Z - G.Z)
		if j.Magnitude <= .1 then
			j = Vector3.new(0, 0, 1)
		else
			j = j.Unit
		end
		local i = (G + j * 6) + Vector3.new(0, 3, 0)
		local c = E.Teleport.TeleportToCFrame(CFrame.lookAt(i, G), Z)
		if not c then
			E.Teleport.UnlockTeleport(Z)
			return false, false, "Could not reach watering target"
		end
		task.wait(.15)
		return true, true
	end;
	CleanupTool = function()
		if E.WaterPlants.EquippedBySystem then
			E.WaterPlants.EquippedBySystem = false
			E.Player.UnequipTools()
		end
	end;
	Use = function(G, V, Z)
		local j = y.Networking and (y.Networking.WateringCan and y.Networking.WateringCan.UseWateringCan)
		if typeof(G) ~= "Vector3" or type(V) ~= "string" or V == "" then
			return false
		end
		if not Z or not Z:IsA("Tool") or not E.Player.IsToolHeld(Z) then
			return false
		end
		if not j or type(j.Fire) ~= "function" then
			return false
		end
		return pcall(function()
			j:Fire(G - Vector3.new(0, .3, 0), V, Z)
		end)
	end;
	Run = function()
		local G = E.TotalControl.ResolveWaterPlantsEnabledTotalControl()
		local V = X.auto_water_plants == true
		if G ~= nil then
			V = G == true
		end
		if not V then
			E.WaterPlants.ClearStatus()
			return 0
		end
		local Z = E.TotalControl.ResolveWaterPlantsWeatherAllowedTotalControl()
		local j, i = Z == true, "Any Time"
		if Z == nil then
			j, i = E.WeatherTriggers.IsActiveWeatherTriggers(X.water_plant_weather_enabled, X.water_plant_weather_selected)
		end
		if not j then
			E.WaterPlants.SetStatus("Waiting for weather | Now: " .. tostring(i), "#CFCFCF")
			return 0
		end
		if type(y.WateringcanData) ~= "table" then
			E.WaterPlants.SetStatus("Watering data unavailable", "#FF5555")
			return 0
		end
		local c = E.TotalControl.ResolveWaterPlantsWaitEffectTotalControl()
		local J = X.water_plant_wait_effect == true
		if c ~= nil then
			J = c == true
		end
		if J then
			local G = math.max(math.ceil(E.WaterPlants.NextUseAt - os.clock()), 0)
			if G > 0 then
				E.WaterPlants.SetStatus(string.format("%s \226\134\146 %s | Wait %ds", E.WaterPlants.LastCanName, E.WaterPlants.LastTargetName, G), "#7CFC00")
				return 0
			end
		end
		local T, d, u = E.WaterPlants.GetTargetPosition()
		if typeof(T) ~= "Vector3" then
			E.WaterPlants.SetStatus(u or "Target not found", "#CFCFCF")
			return 0
		end
		local g, a = E.WaterPlants.GetTool()
		if not g or type(a) ~= "table" then
			E.WaterPlants.SetStatus("Watering can not found", "#FFCC66")
			return 0
		end
		local H = tostring(a.Name or "")
		if H == "" then
			E.WaterPlants.SetStatus("Invalid watering can", "#FF5555")
			return 0
		end
		local r = E.StackKeepOverrides.GetToolCountStackKeepOverrides(g)
		if E.StackKeepOverrides.ShouldSkipItemStackKeepOverrides("Gear", H, r) then
			E.WaterPlants.SetStatus("Watering can not found", "#FFCC66")
			return 0
		end
		if not E.Player.IsToolHeld(g) then
			E.Player.UnequipTools()
			if not E.Player.EquipTool(g) then
				E.WaterPlants.SetStatus("Could not equip watering can", "#FF5555")
				return 0
			end
			E.WaterPlants.EquippedBySystem = true
			task.wait(.15)
		end
		if not E.Player.IsToolHeld(g) then
			E.WaterPlants.CleanupTool()
			E.WaterPlants.SetStatus("Watering can was unequipped", "#FF5555")
			return 0
		end
		local Y, e, s = E.WaterPlants.EnsureNearTarget(T)
		if not Y then
			E.WaterPlants.CleanupTool()
			E.WaterPlants.SetStatus(s or "Could not reach target", "#FFCC66")
			return 0
		end
		E.WaterPlants.SetStatus("Watering " .. (tostring(d or "target") .. "..."), "#66CCFF")
		local N = E.WaterPlants.Use(T, H, g)
		task.wait(.15)
		E.WaterPlants.CleanupTool()
		if e then
			E.Teleport.UnlockTeleport(q.TeleportLockNames.WaterPlants)
		end
		if not N then
			E.WaterPlants.SetStatus("Watering failed", "#FF5555")
			return 0
		end
		local W = math.max(math.floor(tonumber(a.EffectTime) or 1), 1)
		E.WaterPlants.LastCanName = H
		E.WaterPlants.LastTargetName = tostring(d or "Target")
		if J then
			E.WaterPlants.NextUseAt = os.clock() + W
			E.WaterPlants.SetStatus(string.format("%s \226\134\146 %s | Wait %ds", H, E.WaterPlants.LastTargetName, W), "#7CFC00")
		else
			E.WaterPlants.NextUseAt = 0
			E.WaterPlants.SetStatus(string.format("%s \226\134\146 %s | Stacking", H, E.WaterPlants.LastTargetName), "#7CFC00")
		end
		return 1
	end,
	Loop = function()
		local G = E.TotalControl.ResolveWaterPlantsEnabledTotalControl()
		local V = X.auto_water_plants == true
		if G ~= nil then
			V = G == true
		end
		if not V then
			E.WaterPlants.ClearStatus()
			return 0
		end
		local y, Z = pcall(E.WaterPlants.Run)
		if not y then
			E.WaterPlants.CleanupTool()
			E.Teleport.UnlockTeleport(q.TeleportLockNames.WaterPlants)
			E.WaterPlants.SetStatus("Error: watering loop failed", "#FF4444")
			warn("[WaterPlants] Loop error:", Z)
			return 0
		end
		return tonumber(Z) or 0
	end
}
u.PositionGrid = {
	Create = function(G)
		G = math.max(tonumber(G) or 1, .1)
		return {
			CellSize = G,
			Buckets = {}
		}
	end;
	Add = function(G, V)
		if type(G) ~= "table" or type(G.Buckets) ~= "table" or typeof(V) ~= "Vector3" then
			return false
		end
		local y = math.max(tonumber(G.CellSize) or 1, .1)
		local Z = math.floor(V.X / y)
		local j = math.floor(V.Z / y)
		local i = G.Buckets[Z]
		if not i then
			i = {}
			G.Buckets[Z] = i
		end
		local c = i[j]
		if not c then
			c = {}
			i[j] = c
		end
		table.insert(c, V)
		return true
	end;
	IsOpen = function(G, V, y)
		if type(G) ~= "table" or type(G.Buckets) ~= "table" or typeof(V) ~= "Vector3" then
			return false
		end
		local Z = math.max(tonumber(G.CellSize) or 1, .1)
		y = math.max(tonumber(y) or Z, 0)
		local j = y * y
		local i = math.max(math.ceil(y / Z), 1)
		local c = math.floor(V.X / Z)
		local J = math.floor(V.Z / Z)
		for y = c - i, c + i, 1 do
			local Z = G.Buckets[y]
			if not Z then
				continue
			end
			for G = J - i, J + i, 1 do
				local y = Z[G]
				if not y then
					continue
				end
				for G, y in ipairs(y) do
					local Z = V.X - y.X
					local i = V.Z - y.Z
					local c = Z * Z + i * i
					if c < j then
						return false
					end
				end
			end
		end
		return true
	end
}
q.SeedPlaceStatusText = ""
q.SmartSeedProgressionStatusText = ""
q.SmartSeedProgressionPlainStatusText = "Not enabled"
q.SmartSeedProgressionDebugText = ""
q.SmartSeedProgressionDebug = false
q.SmartSeedProgressionUiRefs = q.SmartSeedProgressionUiRefs or {}
E.GardenSeedLimit = {
	PlantsPerSlotGardenSeedLimit = 200,
	FallbackMaximumSlotsGardenSeedLimit = 6,
	GetCurrentSlotGardenSeedLimit = function()
		local G = tonumber(E.DataReplica.GetData("OwnedExpansions", 0)) or 0
		G = math.max(math.floor(G), 0)
		return G + 1
	end;
	GetMaximumSlotGardenSeedLimit = function()
		local G = type(y.ExpansionPrices) == "table" and # y.ExpansionPrices or 0
		return math.max(G + 1, E.GardenSeedLimit.FallbackMaximumSlotsGardenSeedLimit)
	end;
	GetCurrentLimitGardenSeedLimit = function()
		local G = E.GardenSeedLimit.GetCurrentSlotGardenSeedLimit()
		local V = E.GardenSeedLimit.GetMaximumSlotGardenSeedLimit()
		local y = math.clamp(G, 1, V)
		return y * E.GardenSeedLimit.PlantsPerSlotGardenSeedLimit
	end,
	GetMaximumLimitGardenSeedLimit = function()
		return E.GardenSeedLimit.GetMaximumSlotGardenSeedLimit() * E.GardenSeedLimit.PlantsPerSlotGardenSeedLimit
	end;
	GetCurrentCountGardenSeedLimit = function()
