	end
}
E.Seeder = {
	MaxPerLoop = 30,
	MinPlantSpacing = .99;
	SpreadStep = 1.35,
	MaxPositionAttempts = 220,
	StackStep = .67,
	StackIndex = 0,
	HardGardenLimit = 1500,
	MaxFailedPlacements = 10,
	PrintCurrentStackLocation = function(G)
		local V = tostring(X.seed_place_mode or "Random")
		local y
		local Z
		local j
		if V == "Farm Middle" then
			local G, V, i = E.Farm.GetPermanentPlantPosition(.5)
			y = V
			Z = i and i.X
			j = i and i.Z
		elseif V == "Saved Position" then
			local G = X.seed_place_saved_position
			y = type(G) == "table" and E.Farm.GetPlantArea(G.area) or nil
			Z = type(G) == "table" and tonumber(G.x) or nil
			j = type(G) == "table" and tonumber(G.z) or nil
		end
		if not y or not Z or not j then
			return 0, 0
		end
		local i = E.Seeder.GetStackedPosition(y, Z, j, 0)
		if typeof(i) ~= "Vector3" then
			return 0, 0
		end
		local c = 0
		local J = 0
		local T = E.FruitFiltersDataSync.GetPlantEntriesFruitFiltersDataSync()
		for V, y in ipairs(T) do
			local Z = E.Seeder.GetPlantPosition(y)
			if typeof(Z) ~= "Vector3" then
				continue
			end
			if G and typeof(G) == "Vector3" then
				local V = Z.X - G.X
				local y = Z.Z - G.Z
				if V * V + y * y > 4 then
					continue
				end
			end
			local j = Z.Y - i.Y
			c = math.max(c, j)
			J = math.min(J, j)
		end
		c = math.round(c)
		J = math.round(J)
		return J, c
	end;
	GetDetectedStackIndex = function(G)
		local V, y = E.Seeder.PrintCurrentStackLocation(G)
		local Z = X.seed_place_stack_mode_underground and math.abs(V) or math.abs(y)
		local j = math.max(tonumber(E.Seeder.StackStep) or .67, .01)
