	GetPhysicalPlantPositionSeedPlacer = function(G)
		if typeof(G) ~= "Instance" or not G.Parent or G:GetAttribute("emove") == true then
			return nil
		end
		if G:IsA("Model") then
			local V, y = pcall(function()
				return G:GetPivot()
