	end;
	GetOccupiedPositions = function()
		local G = u.PositionGrid.Create(E.Seeder.MinPlantSpacing)
		local V = E.FruitFiltersDataSync.GetPlantEntriesFruitFiltersDataSync()
		for V, y in ipairs(V) do
