				u.PositionGrid.Add(G, Z)
			end
		end
		return G
	end,
	IsPositionOpen = function(G, V)
		return u.PositionGrid.IsOpen(V, G, E.Seeder.MinPlantSpacing)
	end;
	GetAreaPosition = function(G, V, y)
		if not G or not G:IsA("BasePart") then
			return nil
		end
		V = tonumber(V)
		y = tonumber(y)
		if not V or not y then
			return nil
		end
		return G.CFrame:PointToWorldSpace(Vector3.new(V, G.Size.Y / 2, y))
	end,
	IsInsidePlantArea = function(G, V, y, Z)
		if not G or not G:IsA("BasePart") then
			return false
		end
		Z = math.max(tonumber(Z) or .5, 0)
		local j = math.max(G.Size.X / 2 - Z, 0)
		local i = math.max(G.Size.Z / 2 - Z, 0)
		return math.abs(V) <= j and math.abs(y) <= i
	end,
	FindOpenPositionAround = function(G, V, y, Z)
		if not G or not G:IsA("BasePart") then
			return nil
		end
		V = tonumber(V)
		y = tonumber(y)
		if not V or not y then
			return nil
		end
		for j = 0, E.Seeder.MaxPositionAttempts, 1 do
			local i = V
			local c = y
			if j > 0 then
				local G = math.rad(j * 137.5)
				local V = E.Seeder.SpreadStep * math.sqrt(j)
				i += math.cos(G) * V
				c += math.sin(G) * V
			end
			if not E.Seeder.IsInsidePlantArea(G, i, c, .5) then
				continue
			end
			local J = E.Seeder.GetAreaPosition(G, i, c)
			if J and E.Seeder.IsPositionOpen(J, Z) then
