	end;
	BuildWallPositions = function()
		local G = {}
		local V = E.Seeder.SpreadStep
		for y, Z in ipairs(E.Farm.GetPlantAreas()) do
			local j = .75
			local i = math.max(Z.Size.X / 2 - j, 0)
			local c = math.max(Z.Size.Z / 2 - j, 0)
			local J = i * 2
			local T = c * 2
			local d = math.max(math.floor(J / V), 1)
			local u = math.max(math.floor(T / V), 1)
			for V = 0, d, 1 do
				for y = 0, u, 1 do
					local j = - i + J * ((V / d))
					local q = - c + T * ((y / u))
					local g = math.min(V, d - V, y, u - y)
					local a = E.Seeder.GetAreaPosition(Z, j, q)
					if a then
						table.insert(G, {
							position = a;
							depth = g;
							random = E.Farm._Random:NextNumber()
						})
					end
				end
			end
		end
		table.sort(G, function(G, V)
			if G.depth ~= V.depth then
				return G.depth < V.depth
			end
			return G.random < V.random
		end)
		return G
	end,
	GetWallPosition = function(G, V)
