			local y = tostring(V.rarity or "")
			local Z = q.RarityRank[y] or 0
			return 1000000000 + (Z * 10000)
		end
		local Z = E.SmartSeedProgression.SeedScoresSmartSeedProgression[G]
		if Z ~= nil then
			return Z ~= false and Z or nil
		end
		local j = type(y.SellValueData) == "table" and tonumber(y.SellValueData[G]) or nil
		local i = type(V) == "table" and tostring(V.rarity or "") or tostring(q.SeedRarity[G] or "")
		local c = q.RarityRank[i] or 0
		local J = E.SeedData and (type(E.SeedData.IsSingleHarvest) == "function" and E.SeedData.IsSingleHarvest(G) == true)
		local T = E.SmartSeedProgression.ManualPrioritySmartSeedProgression[G]
