		for V, y in ipairs(V:GetChildren()) do
			local Z = tostring(y:GetAttribute("PlantId") or y:GetAttribute("PlantID") or y:GetAttribute("Id") or y.Name or "")
			if Z == G then
				return y
			end
		end
		return nil
	end;
	GetGardenPlantsSmartSeedProgression = function()
		local G = {}
		local V = {}
		local y = E.FruitFiltersDataSync
		if y and (not y.Started and type(y.StartSync) == "function") then
			y.StartSync()
		end
		if y and type(y.Plants) == "table" then
			for y, Z in pairs(y.Plants) do
				if type(Z) ~= "table" or Z.Removed then
					continue
				end
				local j = tostring(Z.PlantName or "")
				local i = tostring(Z.Id or Z.PlantId or y or "")
				if j == "" or i == "" then
					continue
				end
				V[i] = true
				table.insert(G, {
					id = i,
					name = j;
					rarity = tostring(q.SeedRarity[j] or "Unknown"),
					score = E.SmartSeedProgression.GetSeedScoreSmartSeedProgression(j);
					data = Z,
					physical = E.SmartSeedProgression.GetPhysicalPlantSmartSeedProgression(i)
