			end
		end
		for y, Z in ipairs(E.Farm.GetPlants()) do
			local j = tostring(Z.Name or "")
			if j == "" or V[j] then
				continue
			end
			local i = tostring(Z:GetAttribute("SeedName") or "")
			if i == "" then
				continue
			end
			V[j] = true
			table.insert(G, {
				id = j;
				name = i,
				rarity = tostring(q.SeedRarity[i] or "Unknown");
				score = E.SmartSeedProgression.GetSeedScoreSmartSeedProgression(i);
				data = nil;
				physical = Z
