	HasPlantMutationOrVariantSmartSeedProgression = function(G)
		if type(G) ~= "table" then
			return true, "unknown trait"
		end
		local V = G.data
		local y = {}
		if type(V) == "table" then
			table.insert(y, V.Mutation or V.mutation or V.PlantMutation)
			table.insert(y, V.Variant or V.variant or V.PlantVariant or V.Type)
		end
		local Z = G.physical
		if typeof(Z) == "Instance" and Z.Parent then
			for G, V in ipairs({
				"Mutation",
				"Mutations",
				"PlantMutation";
				"Variant",
				"PlantVariant";
				"Type"
			}) do
				table.insert(y, Z:GetAttribute(V))
			end
		end
		for G, V in ipairs(y) do
			local y = E.SmartSeedProgression.CleanPlantTraitSmartSeedProgression(V)
			if y ~= "" then
				return true, y
			end
		end
		return false, ""
	end;
	GetShovelPlantIdSmartSeedProgression = function(G)
		if type(G) ~= "table" then
			return ""
		end
		local V = tostring(G.id or "")
		if V ~= "" then
			return V
		end
		local y = G.data
		if type(y) == "table" then
			V = tostring(y.Id or y.PlantId or y.PlantID or y.ID or "")
			if V ~= "" then
				return V
			end
		end
		local Z = G.physical
		if typeof(Z) == "Instance" and Z.Parent then
			return tostring(Z.Name or "")
		end
		return ""
	end;
	HasFruitSmartSeedProgression = function(G)
		if type(G) ~= "table" then
			return true
		end
		local V = G.data
		if type(V) == "table" then
			if E.FruitFiltersDataSync.IsSingleHarvestPlant(G.name) and E.FruitFiltersDataSync.IsPlantReady(V) then
				return true
			end
			for G, V in pairs(V.Fruits or {}) do
				if type(V) == "table" and not V.Removed then
					return true
				end
			end
		end
		local y = G.physical
		if typeof(y) == "Instance" and y.Parent then
			for G, V in ipairs(y:GetDescendants()) do
				if V:GetAttribute("Fruit") ~= nil or V:GetAttribute("FruitName") ~= nil or V:GetAttribute("HarvestedFruit") == true then
					return true
				end
			end
		end
		return false
	end,
	CanShovelPlantSmartSeedProgression = function(G, V)
		if type(G) ~= "table" or type(V) ~= "table" then
			return false, "invalid"
		end
		local y = tonumber(G.score)
		local Z = tonumber(V.score)
		if not y or not Z or Z <= y then
			return false, "not better"
		end
		if E.SmartSeedProgression.GetShovelPlantIdSmartSeedProgression(G) == "" then
			return false, "missing id"
		end
		local j = E.SmartSeedProgression.HasPlantMutationOrVariantSmartSeedProgression(G)
		if j then
			return false, "mutation/variant"
		end
		if E.SmartSeedProgression.IsProtectedPlantSmartSeedProgression(G.name) then
			return false, "protected plant"
		end
		if E.SmartSeedProgression.IsProtectedRaritySmartSeedProgression(G.rarity) then
			return false, "protected rarity"
		end
		if E.SmartSeedProgression.HasFruitSmartSeedProgression(G) then
			return false, "has fruit"
		end
		return true, "ok"
	end;
	GetWorstReplaceablePlantSmartSeedProgression = function(G)
		local V = E.SmartSeedProgression.GetGardenPlantsSmartSeedProgression()
		local y = {}
		local Z = {}
		for V, j in ipairs(V) do
			local i, c = E.SmartSeedProgression.CanShovelPlantSmartSeedProgression(j, G)
			if i then
				table.insert(y, j)
			else
				Z[c] = ((Z[c] or 0)) + 1
			end
		end
		table.sort(y, function(G, V)
			if ((G.score or 0)) ~= ((V.score or 0)) then
				return ((G.score or 0)) < ((V.score or 0))
			end
			local y = q.RarityRank[tostring(G.rarity or "")] or 0
			local Z = q.RarityRank[tostring(V.rarity or "")] or 0
			if y ~= Z then
				return y < Z
			end
			return tostring(G.name or "") < tostring(V.name or "")
		end)
		return y[1], V, Z
	end,
	GetGridPositionSmartSeedProgression = function(G)
		local V = E.Farm.GetPermanentCenterPosition()
		if typeof(V) ~= "Vector3" then
			return nil, "Farm middle not found"
		end
		local y = E.FarmGrid.GetOpenSpotFarmGrid(V, E.ControlMode.RightCol, function(V)
			return typeof(V.position) == "Vector3" and E.Seeder.IsPositionOpen(V.position, G)
		end)
		if not y or typeof(y.position) ~= "Vector3" then
			return nil, "No open position near farm middle"
		end
		return y.position
	end,
	EquipSeedToolSmartSeedProgression = function(G)
		G = tostring(G or "")
		local V = E.Seeder.GetSeedTool(G)
		if not V then
			for y, Z in ipairs(E.Backpack.GetBackpackAllItems()) do
				local j = E.SmartSeedProgression.GetToolCountSmartSeedProgression(Z)
				if E.SmartSeedProgression.GetSeedNameFromToolSmartSeedProgression(Z) == G and (j > 0 and not E.StackKeepOverrides.ShouldSkipItemStackKeepOverrides("Seed", G, j)) then
					V = Z
					break
				end
			end
		end
		if not V then
			return nil, false
		end
		if E.Player.IsToolHeld(V) then
			return V, false
		end
		if not E.Player.EquipTool(V) then
			return nil, false
		end
		task.wait(.3)
		if not E.Player.IsToolHeld(V) then
			return nil, false
		end
		return V, true
	end;
	PlaceSeedAtPositionSmartSeedProgression = function(G, V)
		if typeof(V) ~= "Vector3" then
			return false, "Placement position missing"
		end
		local y = E.SmartSeedProgression.EquipSeedToolSmartSeedProgression(G)
		if not y then
			return false, "Seed tool missing"
		end
		if not y.Parent or not E.Player.IsToolHeld(y) then
			return false, "Seed tool unequipped"
		end
		local Z = E.SmartSeedProgression.GetToolCountSmartSeedProgression(y)
		if Z <= 0 then
			return false, "No seeds left"
		end
		local j, i = E.Seeder.PlaceSeed(G, V, y)
		if j then
			return true, i
		end
		task.wait(.4)
		local c = E.SmartSeedProgression.GetToolCountSmartSeedProgression(y)
		if c < Z then
			return true, c
		end
		return false, "Placement not confirmed"
	end;
	PlantBestSeedSmartSeedProgression = function(G)
		G = G or E.SmartSeedProgression.GetBestOwnedSeedSmartSeedProgression()
		if type(G) ~= "table" then
			E.SmartSeedProgression.SetStatusSmartSeedProgression("No seed tools found", "#FFCC66")
			return false
		end
		local V = E.Seeder.GetOccupiedPositions()
		local y = math.max(math.floor(tonumber(E.SmartSeedProgression.MaxSpotAttemptsSmartSeedProgression) or 10), 1)
		local Z = "Placement failed"
		for y = 1, y, 1 do
			local j, i = E.SmartSeedProgression.GetGridPositionSmartSeedProgression(V)
			if not j then
				E.SmartSeedProgression.SetStatusSmartSeedProgression(i or "Planting position unavailable", "#FF6666")
				return false
			end
			local c, J = E.SmartSeedProgression.PlaceSeedAtPositionSmartSeedProgression(G.name, j)
			if c then
				u.PositionGrid.Add(V, j)
				E.SmartSeedProgression.SetStatusSmartSeedProgression("Planted " .. tostring(G.name), "#7CFC00", string.format("best=%s | mode=grid | attempts=%d", tostring(G.name), y))
				task.wait(E.Seeder.GetDelay())
				return true
			end
			Z = tostring(J or "Placement failed")
			u.PositionGrid.Add(V, j)
			task.wait(.05)
		end
		E.SmartSeedProgression.SetStatusSmartSeedProgression(Z, "#FF6666")
		return false
	end,
	WaitForGardenCountBelowSmartSeedProgression = function(G, V)
		G = math.max(math.floor(tonumber(G) or 0), 0)
		V = tonumber(V) or 3
		local y = os.clock()
		repeat
			if E.GardenSeedLimit.GetCurrentCountGardenSeedLimit() < G then
				return true
			end
			task.wait(.1)
		until os.clock() - y >= V
		return false
	end,
	WaitForPlantRemovalSmartSeedProgression = function(G, V, y)
		V = math.max(math.floor(tonumber(V) or 0), 0)
		y = tonumber(y) or 3
		local Z = type(G) == "table" and G.physical or nil
		local j = os.clock()
		repeat
			if typeof(Z) == "Instance" and not Z.Parent then
				return true
			end
			if E.GardenSeedLimit.GetCurrentCountGardenSeedLimit() < V then
				return true
			end
			task.wait(.1)
		until os.clock() - j >= y
