	end,
	ReplaceWorstPlantSmartSeedProgression = function(G, V)
		local y, Z, j = E.SmartSeedProgression.GetWorstReplaceablePlantSmartSeedProgression(G)
		if not y then
			local G = tonumber(j and j["protected rarity"] or 0) + tonumber(j and j["protected plant"] or 0)
			local V = string.format("plants=%d | protected=%d | fruit=%d | traits=%d | missingId=%d", # ((Z or {})), G, tonumber(j and j["has fruit"] or 0), tonumber(j and j["mutation/variant"] or 0), tonumber(j and j["missing id"] or 0))
			E.SmartSeedProgression.SetStatusSmartSeedProgression("No safe plant to replace", "#FFCC66", V)
			return false
		end
		local i = E.SmartSeedProgression.GetShovelPlantIdSmartSeedProgression(y)
		if i == "" then
			E.SmartSeedProgression.SetStatusSmartSeedProgression("Plant id not found", "#FF6666")
			return false
		end
		local c, J = E.ShovelTool.Equip()
		if not c then
			E.SmartSeedProgression.SetStatusSmartSeedProgression("Shovel tool not found", "#FF6666")
			return false
		end
		E.SmartSeedProgression.SetStatusSmartSeedProgression(string.format("Replacing %s \226\134\146 %s", tostring(y.name), tostring(G.name)), "#FFCC66", string.format("worstScore=%.1f | bestScore=%.1f", tonumber(y.score) or 0, tonumber(G.score) or 0))
		local T = E.ShovelTool.Use(i, "", c)
		E.ShovelTool.Cleanup(J)
		if not T then
			E.SmartSeedProgression.SetStatusSmartSeedProgression("Shovel request failed", "#FF6666")
			return false
		end
		local d = E.SmartSeedProgression.GetBestOwnedSeedSmartSeedProgression()
		if not d then
			E.SmartSeedProgression.SetStatusSmartSeedProgression("Plant removed, no seed left", "#FFCC66")
			return true
		end
		return E.SmartSeedProgression.PlantBestSeedSmartSeedProgression(d)
	end;
	GardenDataReadySmartSeedProgression = function()
		local G = E.FruitFiltersDataSync
		if not G then
			return true
		end
		if not G.Started and type(G.StartSync) == "function" then
			G.StartSync()
		end
		local V = type(G.CountLocalPlantsFruitFiltersDataSync) == "function" and G.CountLocalPlantsFruitFiltersDataSync() or 0
		local y = type(G.CountWorkspacePlantsFruitFiltersDataSync) == "function" and G.CountWorkspacePlantsFruitFiltersDataSync() or 0
		if y > 0 and V <= 0 then
			if type(G.RequestGardenDataFruitFiltersDataSync) == "function" then
				G.RequestGardenDataFruitFiltersDataSync()
			end
			return false
		end
		return true
	end;
	RunSmartSeedProgression = function()
		local G = E.TotalControl.ResolveSmartSeedingEnabledTotalControl()
		if G ~= nil then
			if G ~= true then
				E.SmartSeedProgression.ClearStatusSmartSeedProgression()
				return false
			end
			E.TotalControl.SetStatusTotalControl("Using smart seeding", "#66CCFF")
		elseif X.smart_seed_progression_enabled ~= true then
			E.SmartSeedProgression.ClearStatusSmartSeedProgression()
			return false
		end
		if E.SmartSeedProgression.BusySmartSeedProgression then
			return false
		end
		if G == nil and X.auto_seedplace == true then
			E.SmartSeedProgression.SetStatusSmartSeedProgression("Paused: Seed Placer is enabled", "#FFCC66")
			return false
		end
		if G == nil and X.auto_shovel_plants == true then
			E.SmartSeedProgression.SetStatusSmartSeedProgression("Paused: Plant Shovel is enabled", "#FFCC66")
			return false
		end
		if not u.IsLoadingCompleted() then
			E.SmartSeedProgression.SetStatusSmartSeedProgression("Waiting for garden load", "#FFCC66")
			return false
		end
		if not E.SmartSeedProgression.GardenDataReadySmartSeedProgression() then
			E.SmartSeedProgression.SetStatusSmartSeedProgression("Waiting for garden data", "#FFCC66")
			return false
		end
		local V, y = E.SmartSeedProgression.GetBestOwnedSeedSmartSeedProgression()
		if not V then
			E.SmartSeedProgression.SetStatusSmartSeedProgression("Waiting for seed tools", "#FFCC66", "owned=0")
			return false
		end
		local Z = E.GardenSeedLimit.GetCurrentCountGardenSeedLimit()
		local j = E.GardenSeedLimit.GetCurrentLimitGardenSeedLimit()
		local i = E.GardenSeedLimit.GetMaximumLimitGardenSeedLimit()
		local c = string.format("best=%s x%d | garden=%d/%d | max=%d | owned=%d", tostring(V.name), tonumber(V.count) or 0, Z, j, i, # ((y or {})))
		E.SmartSeedProgression.BusySmartSeedProgression = true
		local J, T = pcall(function()
			if Z < j then
				E.SmartSeedProgression.SetStatusSmartSeedProgression("Planting " .. tostring(V.name), "#66CCFF", c)
				return E.SmartSeedProgression.PlantBestSeedSmartSeedProgression(V)
			end
			return E.SmartSeedProgression.ReplaceWorstPlantSmartSeedProgression(V, j)
		end)
		E.SmartSeedProgression.BusySmartSeedProgression = false
		if not J then
			E.Player.UnequipTools()
			E.SmartSeedProgression.SetStatusSmartSeedProgression("Smart seeding error", "#FF4444")
			warn("[SmartSeedProgression]", T)
			return false
		end
		return T == true
	end,
	LoopSmartSeedProgression = function()
		return E.SmartSeedProgression.RunSmartSeedProgression()
	end
}
