			return nil
		end
		local Z = E.SellManager and (E.SellManager.BuildBackpackFruitData and E.SellManager.BuildBackpackFruitData(G)) or nil
		if type(Z) ~= "table" then
			return nil
		end
		Z.ob = G
		Z.id = tostring(Z.id or G:GetAttribute("Id") or "")
		Z.name = tostring(Z.name or Z.n or G:GetAttribute("FruitName") or G:GetAttribute("Fruit") or "")
		Z.n = Z.name
		if Z.id == "" or Z.name == "" then
			return nil
		end
		local j, i = E.FruitFilters.GetMutationLookup(Z)
		Z.v = E.FruitFilters.GetFruitVariant(Z, i)
		return Z
	end;
	IsFavouriteFruitGiftSystem = function(G)
		local V = type(G) == "table" and G.ob or nil
		if typeof(V) ~= "Instance" then
			return false
		end
		return V:GetAttribute("IsFavorite") == true or V:GetAttribute("Favorite") == true or V:GetAttribute("Favourite") == true or V:GetAttribute("Favorited") == true or V:GetAttribute("Favourited") == true
	end;
	GetBackpackFruitsGiftSystem = function()
		local G = {}
		for V, y in ipairs(E.Backpack.GetBackpackAllItems()) do
			local Z = E.GiftSystem.BuildBackpackFruitDataGiftSystem(y)
			if Z then
				table.insert(G, Z)
			end
		end
		return G
	end,
	GetFruitCountsGiftSystem = function(G)
		local V = {}
		for G, y in ipairs(type(G) == "table" and G or {}) do
			local Z = tostring(y.name or y.n or "")
			if Z ~= "" then
				V[Z] = ((V[Z] or 0)) + 1
			end
		end
		return V
	end;
	PassesFruitFiltersGiftSystem = function(G)
		if type(G) ~= "table" then
			return false
		end
		local V = tostring(G.name or G.n or "")
		if V == "" or tostring(G.id or "") == "" then
			return false
		end
		if X.gift_protect_favourites and E.GiftSystem.IsFavouriteFruitGiftSystem(G) then
			return false
		end
		if not E.FruitFilters.IsSelectionEmpty(X.gift_fruit_list) then
			if not E.FruitFilters.IsSelected(X.gift_fruit_list, V) then
				return false
			end
		end
		if G.has_weight == false or tonumber(G.w) == nil or ((tonumber(G.w) or 0)) <= 0 then
			return false
		end
		if not E.FruitFilters.PassesWeightRange(G.w, X.gift_min_weight, X.gift_max_weight) then
			return false
		end
		local y, Z = E.FruitFilters.GetMutationLookup(G)
		if not E.FruitFilters.PassesMutationSelection(Z, X.gift_mutation_whitelist, X.gift_mutation_blacklist) then
			return false
		end
		local j = E.FruitFilters.GetFruitVariant(G, Z)
		if not E.FruitFilters.PassesVariantSelection(j, X.gift_variant_whitelist, X.gift_variant_blacklist) then
			return false
		end
		return true
	end;
	SortFruitsGiftSystem = function(G)
		local V = tostring(X.gift_send_order or "Lowest Weight First")
		table.sort(G, function(G, y)
			local Z = tonumber(G.w) or 0
			local j = tonumber(y.w) or 0
			if V == "Highest Weight First" then
				if Z ~= j then
					return Z > j
				end
			elseif V == "Name A-Z" then
				if tostring(G.name or "") ~= tostring(y.name or "") then
					return tostring(G.name or "") < tostring(y.name or "")
				end
			elseif V == "Mutation First" then
				local V = tostring(G.m or "") ~= ""
				local Z = tostring(y.m or "") ~= ""
				if V ~= Z then
					return V
				end
			elseif V == "Normal First" then
				local V = tostring(G.v or "Normal") == "Normal"
				local Z = tostring(y.v or "Normal") == "Normal"
				if V ~= Z then
					return V
				end
			else
				if Z ~= j then
					return Z < j
				end
			end
			return tostring(G.id or "") < tostring(y.id or "")
		end)
	end;
	GetFilteredFruitsGiftSystem = function()
		local G = E.GiftSystem.GetBackpackFruitsGiftSystem()
		local V = {}
		local y = E.GiftSystem.GetFruitCountsGiftSystem(G)
		local Z = {}
		local j = math.max(math.floor(tonumber(X.gift_keep_amount_per_fruit) or 0), 0)
		E.GiftSystem.SortFruitsGiftSystem(G)
		for G, i in ipairs(G) do
			if not E.GiftSystem.PassesFruitFiltersGiftSystem(i) then
				continue
			end
			local c = tostring(i.name or i.n or "")
			local J = y[c] or 0
			local T = Z[c] or 0
			if j > 0 and T >= math.max(J - j, 0) then
				continue
			end
			Z[c] = T + 1
			table.insert(V, i)
		end
		return V, # G
	end;
	FruitStillExistsGiftSystem = function(G)
		G = tostring(G or "")
		if G == "" then
			return false
		end
		for V, y in ipairs(E.GiftSystem.GetBackpackFruitsGiftSystem()) do
			if tostring(y.id or "") == G then
				return true
			end
		end
		return false
	end;
	WaitForFruitGoneGiftSystem = function(G, V)
		G = tostring(G or "")
		V = math.max(tonumber(V) or 8, 1)
		if G == "" then
			return false
		end
		local y = os.clock()
		repeat
			if not E.GiftSystem.FruitStillExistsGiftSystem(G) then
				return true
			end
			task.wait(.2)
		until os.clock() - y >= V
		return false
	end,
	SendFruitGiftSystem = function(G, V)
		if not G or not G:IsDescendantOf(y.Players) then
			return false, "Target left server"
		end
		if type(V) ~= "table" or tostring(V.id or "") == "" then
			return false, "Invalid fruit"
		end
		local Z = y.Networking and (y.Networking.Gifting and y.Networking.Gifting.Send)
		if not Z or type(Z.Fire) ~= "function" then
			return false, "Gift remote missing"
		end
		if X.gift_preview_only then
			return true, "Preview"
		end
		local j = V.ob
		if typeof(j) == "Instance" and j.Parent then
			E.Player.EquipTool(j)
			task.wait(.1)
		end
		local i, c = pcall(function()
			Z:Fire(G.UserId, "HarvestedFruits", tostring(V.id))
		end)
		if not i then
			return false, tostring(c or "Gift failed")
		end
		if not E.GiftSystem.WaitForFruitGoneGiftSystem(V.id, X.gift_wait_timeout) then
			return false, "Not accepted yet"
		end
		return true, "Sent"
	end,
	ProcessSenderGiftSystem = function()
		if not X.gift_send_enabled then
			return false
		end
		if E.GiftSystem.SenderBusyGiftSystem then
			return false
		end
		if not u.IsLoadingCompleted() then
			E.GiftSystem.SetStatusGiftSystem("Waiting for loading", "#FFCC66")
			return false
		end
		local G = math.clamp(tonumber(X.gift_delay) or 1.25, .35, 30)
		if os.clock() - E.GiftSystem.LastSendAtGiftSystem < G then
			return false
		end
		local V = E.GiftSystem.GetSelectedPlayerGiftSystem(X.gift_send_targets)
		if not V then
			E.GiftSystem.SetStatusGiftSystem("Waiting for selected alt", "#FFCC66")
			return false
		end
		local y, Z = E.GiftSystem.GetFilteredFruitsGiftSystem()
		local j = math.max(math.floor(tonumber(X.gift_only_when_backpack_over) or 0), 0)
		if j > 0 and Z <= j then
			E.GiftSystem.SetStatusGiftSystem("Paused: backpack below limit", "#CFCFCF")
			return false
		end
		if # y == 0 then
			E.GiftSystem.SetStatusGiftSystem("No fruits match filters", "#FFCC66")
			return false
		end
		local i = math.clamp(math.floor(tonumber(X.gift_max_per_cycle) or 1), 1, 25)
		E.GiftSystem.SenderBusyGiftSystem = true
		local c, J = pcall(function()
			local Z = 0
			local j = 0
			for y, c in ipairs(y) do
				if Z >= i then
					break
				end
				if not X.gift_send_enabled then
					break
				end
				local J = E.GiftSystem.BuildBackpackFruitDataGiftSystem(c.ob)
				if not J or not E.GiftSystem.PassesFruitFiltersGiftSystem(J) then
					continue
				end
				j += 1
				local T, d = E.GiftSystem.SendFruitGiftSystem(V, J)
				if T then
					Z += 1
					E.GiftSystem.SetStatusGiftSystem(string.format("%s %s to %s", tostring(d), tostring(J.name), V.Name), X.gift_preview_only and "#CFCFCF" or "#66FF99")
				else
					E.GiftSystem.SetStatusGiftSystem(tostring(d or "Gift failed"), "#FF6666")
					break
				end
				E.GiftSystem.LastSendAtGiftSystem = os.clock()
				task.wait(G)
			end
			if Z == 0 and j == 0 then
				E.GiftSystem.SetStatusGiftSystem("No safe fruit ready", "#FFCC66")
			end
			return Z
		end)
		E.GiftSystem.SenderBusyGiftSystem = false
		if not c then
			E.GiftSystem.SetStatusGiftSystem("Sender error", "#FF6666")
			warn("[GiftSystem Sender]", J)
			return false
		end
		return J and J > 0
	end;
	IsTrustedGiftSenderGiftSystem = function(G)
		if not G or not G:IsDescendantOf(y.Players) then
			return false
		end
		local V = tostring(X.gift_receive_mode or "Trusted Only")
		if V == "Anyone" then
			return true
		end
		local Z = tostring(G.UserId or "")
		local j = tostring(G.Name or "")
		return E.GiftSystem.IsSelectedGiftSystem(X.gift_receive_trusted, Z) or E.GiftSystem.IsSelectedGiftSystem(X.gift_receive_trusted, j)
	end;
