			V.Enabled = false
		end
	end,
	ProcessPromptGiftSystem = function(G, V)
		if not X.gift_receive_enabled then
			return false
		end
		if not E.GiftSystem.IsTrustedGiftSenderGiftSystem(G) then
			E.GiftSystem.SetStatusGiftSystem("Ignored gift from untrusted player", "#FFCC66")
			return false
		end
		if not E.GiftSystem.CanAcceptItemNameGiftSystem(V) then
			E.GiftSystem.SetStatusGiftSystem("Ignored gift item", "#FFCC66")
			return false
		end
		local Z = y.Networking and (y.Networking.Gifting and y.Networking.Gifting.Response)
		if not Z or type(Z.Fire) ~= "function" then
			E.GiftSystem.SetStatusGiftSystem("Accept remote missing", "#FF6666")
			return false
		end
		task.spawn(function()
			task.wait(.15)
			local V, y = pcall(function()
				Z:Fire(G, true)
			end)
			if V then
				E.GiftSystem.HideGiftPromptGiftSystem()
				E.GiftSystem.SetStatusGiftSystem("Accepted from " .. tostring(G.Name or "player"), "#66FF99")
			else
				E.GiftSystem.SetStatusGiftSystem("Accept failed", "#FF6666")
