	ClaimDroppedItemGiftSystem = function(G)
		if not X.gift_drop_pickup_enabled or E.GiftSystem.DropBusyGiftSystem then
			return false
		end
		if not E.GiftSystem.IsAllowedDropCategoryGiftSystem(G) or not E.GiftSystem.IsAllowedDropSourceGiftSystem(G) then
			return false
		end
		local V = E.ProximityPrompt.FindProximityPromptByClass(G)
		if not V or not V.Enabled then
			return false
		end
		E.GiftSystem.DropBusyGiftSystem = true
		local y = q.TeleportLockNames.GiftDropPickup
		local Z = E.Teleport.LockTeleport(y, X.gift_drop_pickup_use_player_walk and 35 or 2, X.gift_drop_pickup_use_player_walk == true)
		if not Z then
			E.GiftSystem.DropBusyGiftSystem = false
			return false
		end
		local j, i = pcall(function()
			if X.gift_drop_pickup_use_player_walk then
				if not E.Movement.WalkPathToTarget(G, 30, y, 10) then
					return false
				end
			else
				if not E.Teleport.TeleportTo(G, true, y) then
					return false
				end
			end
			task.wait(.05)
			if not V.Parent or not E.GiftSystem.IsAllowedDropCategoryGiftSystem(G) or not E.GiftSystem.IsAllowedDropSourceGiftSystem(G) then
				return false
			end
			E.ProximityPrompt.ActivateProximityPrompt(V)
			E.GiftSystem.SetStatusGiftSystem("Picked dropped item", "#66FF99")
			return true
		end)
		E.Teleport.UnlockTeleport(y)
		E.GiftSystem.DropBusyGiftSystem = false
		if not j then
			E.GiftSystem.SetStatusGiftSystem("Drop pickup failed", "#FF6666")
			warn("[GiftSystem Drop]", i)
			return false
		end
		return i == true
	end,
