	StartGiftSystem = function()
		if E.GiftSystem.StartedGiftSystem then
			return false
		end
		E.GiftSystem.StartedGiftSystem = true
		local G = y.Networking and (y.Networking.Gifting and y.Networking.Gifting.Prompted)
		if G and G.OnClientEvent then
			G.OnClientEvent:Connect(function(G, V)
				E.GiftSystem.ProcessPromptGiftSystem(G, V)
			end)
		end
		y.Players.PlayerAdded:Connect(function()
			task.defer(E.GiftSystem.RefreshPlayerDropdownsGiftSystem)
		end)
		y.Players.PlayerRemoving:Connect(function()
			task.defer(E.GiftSystem.RefreshPlayerDropdownsGiftSystem)
		end)
		if y.DroppedItems then
			y.DroppedItems.ChildAdded:Connect(function(G)
				task.wait(.1)
				E.GiftSystem.ClaimDroppedItemGiftSystem(G)
			end)
		end
		task.spawn(function()
			while not q.is_forced_stop do
				task.wait(3)
				local G, V = pcall(E.GiftSystem.ProcessSenderGiftSystem)
				if not G then
					E.GiftSystem.SenderBusyGiftSystem = false
					E.GiftSystem.SetStatusGiftSystem("Sender loop error", "#FF6666")
					warn("[GiftSystem Loop]", V)
				end
				if X.gift_drop_pickup_enabled and (y.DroppedItems and not E.GiftSystem.DropBusyGiftSystem) then
					for G, V in ipairs(y.DroppedItems:GetChildren()) do
						if E.GiftSystem.ClaimDroppedItemGiftSystem(V) then
							task.wait(.5)
						end
					end
				end
			end
		end)
		return true
	end
}
E.GiftSystem.StartGiftSystem()
