		q.AutoDropItemsStatusText = string.format("<stroke color=\'#000000\' thickness=\'1\'><font color=\'#FFFFFF\'>\240\159\147\164 [Auto Drop]</font> <font color=\'%s\'>%s</font></stroke>", tostring(V or "#FFFFFF"), G)
