	GetItemDisplayNameAutoDropItems = function(G, V, y, Z)
		local j = G and G:GetAttribute("ItemName")
		if type(j) == "string" and j ~= "" then
			return j
		end
		if type(y) == "string" and y ~= "" then
			return y
		end
		if typeof(G) == "Instance" and tostring(G.Name or "") ~= "" then
			return tostring(G.Name)
		end
		return tostring(Z or V or "Item")
	end;
	BuildFruitDataAutoDropItems = function(G)
		if typeof(G) ~= "Instance" or not G.Parent then
			return nil
		end
		local V = G:IsA("Tool") and G:GetAttribute("HarvestedFruit") == true
		local y = G:IsA("Configuration") and (G:GetAttribute("FruitProxy") == true and G:GetAttribute("HarvestedFruit") == true)
		if not V and not y then
			return nil
		end
		local Z = E.SellManager and (E.SellManager.BuildBackpackFruitData and E.SellManager.BuildBackpackFruitData(G)) or nil
		if type(Z) ~= "table" then
			return nil
		end
		Z.ob = G
		Z.id = tostring(Z.id or G:GetAttribute("Id") or "")
		Z.name = tostring(Z.name or Z.n or G:GetAttribute("FruitName") or G:GetAttribute("Fruit") or "")
		Z.n = Z.name
		if Z.id == "" or Z.name == "" then
			return nil
		end
		local j, i = E.FruitFilters.GetMutationLookup(Z)
		Z.v = E.FruitFilters.GetFruitVariant(Z, i)
		return Z
	end;
	BuildPetDataAutoDropItems = function(G)
		if typeof(G) ~= "Instance" or not G.Parent or not G:IsA("Tool") then
			return nil
		end
		local V = G:GetAttribute("PetId")
		V = type(V) == "string" and V or tostring(V or "")
		if V == "" then
			return nil
		end
		local Z = E.PetSeller and (E.PetSeller.FindLivePetInfo and E.PetSeller.FindLivePetInfo(V)) or nil
		if type(Z) == "table" then
			Z.tool = G
			return Z
		end
		local j = G:GetAttribute("PetName") or G:GetAttribute("Species") or G:GetAttribute("Name")
		j = type(j) == "string" and j or tostring(j or "")
		if j == "" then
			j = tostring(G.Name or "Pet")
		end
		local i = E.PetSeller and (E.PetSeller.GetBaseData and E.PetSeller.GetBaseData(j)) or nil
		local c = E.PetSeller and (E.PetSeller.GetDisplayName and E.PetSeller.GetDisplayName(j, i)) or j
		local J = E.PetSeller and (E.PetSeller.GetRarity and E.PetSeller.GetRarity(j, i, {})) or "Unknown"
		local T = tostring(G:GetAttribute("Size") or "Normal")
		local d = tostring(G:GetAttribute("Type") or G:GetAttribute("Variant") or "Normal")
		return {
			id = V;
			key = V,
			name = j;
			displayName = c,
			rarity = J,
			rarityRank = q.RarityRank[J] or 999,
			size = T ~= "" and T or "Normal";
			variant = d ~= "" and d or "Normal";
			equipped = G.Parent == y.Character,
			known = type(i) == "table",
			tool = G
		}
	end;
	BuildDropDataAutoDropItems = function(G)
		if typeof(G) ~= "Instance" or not G.Parent then
			return nil
		end
		local V = E.AutoDropItems.BuildFruitDataAutoDropItems(G)
		if V then
			return {
				tool = G,
				category = "HarvestedFruits";
				id = tostring(V.id),
				name = tostring(V.name),
				fruitData = V,
				weight = tonumber(V.w) or 0
			}
		end
		if not G:IsA("Tool") then
			return nil
		end
		local y = E.AutoDropItems.BuildPetDataAutoDropItems(G)
		if y then
			return {
				tool = G;
				category = "Pets";
				id = tostring(y.id);
				name = tostring(y.displayName or y.name or "Pet"),
				petInfo = y;
				rarityRank = tonumber(y.rarityRank) or 999
			}
		end
		for V, y in pairs(E.AutoDropItems.DropToolAttributesAutoDropItems) do
			local Z = G:GetAttribute(V)
			if Z ~= nil and tostring(Z or "") ~= "" then
				return {
					tool = G;
					category = y,
					id = tostring(Z),
					name = E.AutoDropItems.GetItemDisplayNameAutoDropItems(G, V, Z, y),
					attributeName = V
				}
			end
		end
		return nil
	end,
	IsFavouriteFruitAutoDropItems = function(G)
		local V = type(G) == "table" and G.ob or nil
		if typeof(V) ~= "Instance" then
			return false
		end
		return V:GetAttribute("IsFavorite") == true or V:GetAttribute("Favorite") == true or V:GetAttribute("Favourite") == true or V:GetAttribute("Favorited") == true or V:GetAttribute("Favourited") == true
	end,
	PassesFruitFiltersAutoDropItems = function(G)
		local V = type(G) == "table" and G.fruitData or nil
		if type(V) ~= "table" then
			return false
		end
		local y = tostring(V.name or V.n or "")
		if y == "" or tostring(V.id or "") == "" then
			return false
		end
		if X.auto_drop_protect_favourites and E.AutoDropItems.IsFavouriteFruitAutoDropItems(V) then
			return false
		end
		if not E.AutoDropItems.PassesOptionalSelectionAutoDropItems(X.auto_drop_fruit_list, y) then
			return false
		end
		if V.has_weight == false or tonumber(V.w) == nil or ((tonumber(V.w) or 0)) <= 0 then
			return false
		end
		if not E.FruitFilters.PassesWeightRange(V.w, X.auto_drop_min_weight, X.auto_drop_max_weight) then
			return false
		end
		local Z, j = E.FruitFilters.GetMutationLookup(V)
		if not E.FruitFilters.PassesMutationSelection(j, X.auto_drop_mutation_whitelist, X.auto_drop_mutation_blacklist) then
			return false
		end
		local i = E.FruitFilters.GetFruitVariant(V, j)
		if not E.FruitFilters.PassesVariantSelection(i, X.auto_drop_variant_whitelist, X.auto_drop_variant_blacklist) then
			return false
		end
		return true
	end;
	PassesSeedFiltersAutoDropItems = function(G)
		if type(G) ~= "table" or G.category ~= "Seeds" then
			return false
		end
		return E.AutoDropItems.PassesOptionalSelectionAutoDropItems(X.auto_drop_seed_list, G.name) or E.AutoDropItems.PassesOptionalSelectionAutoDropItems(X.auto_drop_seed_list, G.id)
	end;
	PassesPetFiltersAutoDropItems = function(G)
		local V = type(G) == "table" and G.petInfo or nil
		if type(V) ~= "table" then
			return false
		end
		if X.auto_drop_pet_protect_equipped and V.equipped then
			return false
		end
		if E.AutoDropItems.IsSelectedAutoDropItems(X.auto_drop_pet_protected, V.name) or E.AutoDropItems.IsSelectedAutoDropItems(X.auto_drop_pet_protected, V.displayName) then
			return false
		end
		if not E.AutoDropItems.PassesOptionalSelectionAutoDropItems(X.auto_drop_pet_selected, V.name) and not E.AutoDropItems.PassesOptionalSelectionAutoDropItems(X.auto_drop_pet_selected, V.displayName) then
			return false
		end
		if not E.AutoDropItems.PassesOptionalSelectionAutoDropItems(X.auto_drop_pet_rarity_whitelist, V.rarity) then
			return false
		end
		if E.AutoDropItems.IsSelectedAutoDropItems(X.auto_drop_pet_rarity_blacklist, V.rarity) then
			return false
		end
		if not E.AutoDropItems.PassesOptionalSelectionAutoDropItems(X.auto_drop_pet_size_whitelist, V.size) then
			return false
		end
		if E.AutoDropItems.IsSelectedAutoDropItems(X.auto_drop_pet_size_blacklist, V.size) then
			return false
		end
		if not E.AutoDropItems.PassesOptionalSelectionAutoDropItems(X.auto_drop_pet_variant_whitelist, V.variant) then
			return false
		end
		if E.AutoDropItems.IsSelectedAutoDropItems(X.auto_drop_pet_variant_blacklist, V.variant) then
			return false
		end
		return true
	end;
	PassesOtherItemFiltersAutoDropItems = function(G)
		if type(G) ~= "table" then
