		local Z = E.AutoDropItems.GetPetCountsAutoDropItems(G)
		local j = {}
		local i = {}
		local c = math.max(math.floor(tonumber(X.auto_drop_keep_amount_per_fruit) or 0), 0)
		local J = math.max(math.floor(tonumber(X.auto_drop_pet_keep_amount) or 0), 0)
		for G, T in ipairs(G) do
			if not E.AutoDropItems.PassesFiltersAutoDropItems(T) then
				continue
			end
			if T.category == "HarvestedFruits" and c > 0 then
				local G = tostring(T.name or "")
				local V = j[G] or 0
				if V >= math.max(((y[G] or 0)) - c, 0) then
					continue
				end
				j[G] = V + 1
			elseif T.category == "Pets" and J > 0 then
				local G = T.petInfo
				local V = E.PetSeller and (E.PetSeller.GetBucketKey and E.PetSeller.GetBucketKey(G)) or tostring(G and G.name or "")
				local y = i[V] or 0
				if y >= math.max(((Z[V] or 0)) - J, 0) then
					continue
				end
				i[V] = y + 1
			end
			table.insert(V, T)
		end
		return V, # G
	end;
	FindFruitToolByIdAutoDropItems = function(G)
		G = tostring(G or "")
		if G == "" then
			return nil
		end
		for V, y in ipairs(E.Backpack.GetBackpackAllItems()) do
			if y and (y.Parent and (y:IsA("Tool") and (y:GetAttribute("HarvestedFruit") == true and tostring(y:GetAttribute("Id") or "") == G))) then
				return y
			end
		end
		return nil
	end,
	PromoteFruitProxyAutoDropItems = function(G)
		G = tostring(G or "")
		if G == "" then
			return nil, "Invalid fruit"
		end
		local V = E.AutoDropItems.FindFruitToolByIdAutoDropItems(G)
		if V then
			return V, "Ready"
		end
		local Z = y.Networking and (y.Networking.Backpack and y.Networking.Backpack.PromoteFruit)
		if not Z or type(Z.Fire) ~= "function" then
			return nil, "Fruit hold remote missing"
		end
		local j = pcall(function()
			Z:Fire(G)
		end)
		if not j then
			return nil, "Could not hold fruit"
		end
		local i = os.clock()
		repeat
			local V = E.AutoDropItems.FindFruitToolByIdAutoDropItems(G)
			if V then
				return V, "Ready"
			end
			task.wait(.05)
		until os.clock() - i >= 2
		return nil, "Fruit did not appear"
	end;
	DropOneAutoDropItems = function(G)
		if type(G) ~= "table" or not G.tool or not G.tool.Parent then
			return false, "Item missing"
		end
		local V = tostring(G.category or "")
		local Z = tostring(G.id or "")
		if V == "" or Z == "" then
			return false, "Invalid item"
		end
		if X.auto_drop_preview_only == true then
			return true, "Preview"
		end
		local j = y.Networking and (y.Networking.DroppedItem and y.Networking.DroppedItem.RequestDrop)
		if not j or type(j.Fire) ~= "function" then
			return false, "Drop remote missing"
		end
		local i = E.Player.GetTool_Holding()
		local c = G.tool
		if V == "HarvestedFruits" and (not c:IsA("Tool")) then
			local V, y = E.AutoDropItems.PromoteFruitProxyAutoDropItems(Z)
			if not V then
				return false, y or "Could not hold fruit"
			end
			c = V
			G.tool = V
		end
		if c.Parent ~= y.Character then
			if not E.Player.EquipTool(c) then
				return false, "Could not equip item"
			end
			task.wait(.1)
		end
		local J, T = pcall(function()
			j:Fire(V, Z)
		end)
		if i and (i.Parent and (i ~= G.tool and i.Parent ~= y.Character)) then
			pcall(function()
				E.Player.EquipTool(i)
			end)
		end
		if not J then
			return false, tostring(T or "Drop failed")
		end
		return true, "Dropped"
	end;
	LoopAutoDropItems = function()
		if X.auto_drop_items_enabled ~= true then
			E.AutoDropItems.ClearStatusAutoDropItems()
			return false
		end
		if E.AutoDropItems.BusyAutoDropItems then
			return false
		end
		if not u.IsLoadingCompleted() then
			E.AutoDropItems.SetStatusAutoDropItems("Waiting for loading", "#FFCC66")
			return false
		end
		if E.AutoDropItems.IsSelectionEmptyAutoDropItems(X.auto_drop_categories) then
			E.AutoDropItems.SetStatusAutoDropItems("Select categories first", "#FFCC66")
			return false
		end
		local G = math.clamp(tonumber(X.auto_drop_delay) or .75, .35, 30)
		if os.clock() < E.AutoDropItems.NextRunAtAutoDropItems then
			return false
		end
		local V, y = E.AutoDropItems.GetDropItemsAutoDropItems()
		if # V == 0 then
			E.AutoDropItems.SetStatusAutoDropItems(y > 0 and "No items match filters" or "No droppable tools", "#FFCC66")
			E.AutoDropItems.NextRunAtAutoDropItems = os.clock() + 2
			return false
		end
		local Z = math.clamp(math.floor(tonumber(X.auto_drop_max_per_cycle) or 1), 1, 25)
		E.AutoDropItems.BusyAutoDropItems = true
		local j, i = pcall(function()
			local y = 0
			for V, j in ipairs(V) do
				if y >= Z or X.auto_drop_items_enabled ~= true then
					break
				end
				local i = E.AutoDropItems.BuildDropDataAutoDropItems(j.tool)
				if not i or not E.AutoDropItems.PassesFiltersAutoDropItems(i) then
					continue
				end
				local c, J = E.AutoDropItems.DropOneAutoDropItems(i)
				if c then
					y += 1
					E.AutoDropItems.SetStatusAutoDropItems(string.format("%s %s", tostring(J), tostring(i.name or i.category)), X.auto_drop_preview_only and "#CFCFCF" or "#66FF99")
				else
					E.AutoDropItems.SetStatusAutoDropItems(tostring(J or "Drop failed"), "#FF6666")
					break
				end
				E.AutoDropItems.NextRunAtAutoDropItems = os.clock() + G
				task.wait(G)
			end
			return y
		end)
		E.AutoDropItems.BusyAutoDropItems = false
		if not j then
			E.AutoDropItems.SetStatusAutoDropItems("System error", "#FF6666")
			warn("[AutoDropItems]", i)
			return false
		end
		if not i or i <= 0 then
			E.AutoDropItems.SetStatusAutoDropItems("No safe item ready", "#FFCC66")
			E.AutoDropItems.NextRunAtAutoDropItems = os.clock() + 2
		end
		return i and i > 0
	end,
