		end
		local V = tostring(G.category or "")
		local y = Y.Auctioneer and (Y.Auctioneer.GetDisplayNameAuctioneer and Y.Auctioneer.GetDisplayNameAuctioneer(G)) or tostring(G.item or "")
		local Z = string.lower(tostring(G.item or "") .. (" " .. (tostring(y or "") .. (" " .. V))))
		local j = q.RarityRank[tostring(Y.Auctioneer.ResolveRarityAuctioneer(G) or "")] or 0
		if V == "Seeds" or Z:find("seed", 1, true) ~= nil then
			return j >= ((q.RarityRank.Legendary or 5))
		end
		if V == "Pets" or Z:find("pet", 1, true) ~= nil then
			return j >= ((q.RarityRank.Super or 7)) or Z:find("big", 1, true) ~= nil or Z:find("huge", 1, true) ~= nil or Z:find("rainbow", 1, true) ~= nil
		end
		local i = Z:find("watering can", 1, true) ~= nil or Z:find("wateringcan", 1, true) ~= nil or Z:find(" can", 1, true) ~= nil
		local c = Z:find("sprinkler", 1, true) ~= nil
		local J = i or c or Z:find("trowel", 1, true) ~= nil or Z:find("power hose", 1, true) ~= nil
		if J then
			return j >= ((q.RarityRank.Legendary or 5)) or Z:find("super", 1, true) ~= nil
		end
		return j >= ((q.RarityRank.Super or 7))
	end,
