		if y ~= nil then
			return y
		end
		if G == "" or X[G .. "_min_sheckles_enabled"] ~= true then
			return V
		end
		local Z = tonumber(X[G .. "_min_sheckles"]) or 0
		if Z <= 0 then
			return V
		end
		return math.max(0, V - Z)
	end;
	GetAllSelectionShopBuyer = function(G)
		local V = {}
		if type(G) ~= "table" then
			return V
		end
		for G, y in pairs(G) do
			local Z = ""
			if type(G) == "string" then
				Z = G
			elseif type(y) == "table" then
				Z = tostring(y.name or y.ItemName or y.SeedName or "")
			elseif type(y) == "string" then
				Z = y
			end
			if Z ~= "" then
				V[Z] = true
			end
		end
		return V
	end
}
Y.SeedShop = {
