	BuildCandidateAuctioneer = function(G)
		if type(G) ~= "table" or type(G.lotId) ~= "string" then
			return nil
		end
		if G.robuxPrice ~= nil then
			return nil
		end
		if not Y.Auctioneer.IsActiveLotAuctioneer(G) then
			return nil
		end
		if not Y.Auctioneer.PassesSelectedItemAuctioneer(G) then
			return nil
		end
		local V = Y.Auctioneer.GetCurrentPriceAuctioneer(G)
		if V <= 0 then
			return nil
		end
		local y = tonumber(E.Money.GetSheckles()) or 0
		local Z = E.TotalControl.ResolveAuctioneerAffordableTotalControl(G, V, y)
		if Z ~= nil then
			if Z ~= true then
				return nil
			end
		elseif y < V then
			return nil
		else
			local G = math.max(tonumber(X.auctioneer_min_sheckles) or 0, 0)
			if G > 0 and y < G then
				return nil
			end
		end
		local j = Y.Auctioneer.GetDiscountPercentAuctioneer(G, V)
		local i = Y.Auctioneer.PassesPriceAuctioneer(G, V, j)
		if not i then
			return nil
		end
		local c = Y.Auctioneer.GetDisplayNameAuctioneer(G)
		local J = tostring(G.item or c)
		local T = Y.Auctioneer.GetBuyLimitAuctioneer(G)
		local d = tonumber(Y.Auctioneer.BoughtByItemAuctioneer[J]) or 0
		if d >= T then
			return nil
		end
		local u = Y.Auctioneer.GetStockAuctioneer(G)
		if u ~= nil and u <= 0 then
			return nil
		end
		return {
			lot = G;
			displayName = c;
			itemName = J;
			currentPrice = V;
			discountPercent = j;
			stock = u,
			ticks = Y.Auctioneer.GetTicksElapsedAuctioneer(G)
		}
	end;
	GetBestCandidateAuctioneer = function()
		local G = {}
		for V, y in ipairs(Y.Auctioneer.LiveLotsAuctioneer) do
			local Z = Y.Auctioneer.BuildCandidateAuctioneer(y)
			if Z then
				table.insert(G, Z)
			end
		end
		if # G == 0 then
			return nil
		end
		table.sort(G, function(G, V)
			local y = E.TotalControl.ResolveAuctionCandidateScoreTotalControl(G)
			local Z = E.TotalControl.ResolveAuctionCandidateScoreTotalControl(V)
			if y ~= nil and (Z ~= nil and y ~= Z) then
				return y > Z
			end
			if G.discountPercent ~= V.discountPercent then
				return G.discountPercent > V.discountPercent
			end
			if G.currentPrice ~= V.currentPrice then
				return G.currentPrice < V.currentPrice
			end
			return tostring(G.displayName) < tostring(V.displayName)
		end)
		return G[1]
	end,
	PurchaseLotAuctioneer = function(G)
		if type(G) ~= "table" or type(G.lot) ~= "table" then
			return false
		end
		local V = tostring(G.lot.lotId or "")
		if V == "" then
			Y.Auctioneer.SetStatusAuctioneer("Invalid auction lot", "#FF6666")
			return false
		end
		local Z = y.Networking and (y.Networking.Auctioneer and y.Networking.Auctioneer.PurchaseLot)
		if not Z or type(Z.Fire) ~= "function" then
			Y.Auctioneer.SetStatusAuctioneer("Purchase unavailable", "#FF6666")
			return false
		end
		local j = E.TotalControl.ResolveAuctioneerPreviewOnlyTotalControl()
		local i = j ~= nil and j == true or X.auctioneer_preview_only == true
		if i then
			local y = table.concat({
				V,
				tostring(math.floor(tonumber(G.currentPrice) or 0)),
				tostring(math.floor(tonumber(G.discountPercent) or 0))
			}, "|")
			Y.Auctioneer.SetStatusAuctioneer(string.format("Preview: %s at %d%%", G.displayName, G.discountPercent), "#66CCFF")
			if Y.Auctioneer.PreviewLogKeysAuctioneer[y] ~= true then
				Y.Auctioneer.PreviewLogKeysAuctioneer[y] = true
				Y.Auctioneer.AddLogAuctioneer(string.format("Would buy %s | $%s | %d%%", G.displayName, u.formatShecklesNumber(G.currentPrice), G.discountPercent), "#66CCFF")
			end
			Y.Auctioneer.PendingCandidateAuctioneer = nil
			return false
		end
		Y.Auctioneer.PendingCandidateAuctioneer = G
		Y.Auctioneer.PurchaseBusyAuctioneer = true
		Y.Auctioneer.NextPurchaseAtAuctioneer = os.clock() + Y.Auctioneer.GetPurchaseCooldownAuctioneer()
		Y.Auctioneer.PurchaseTimeoutAtAuctioneer = os.clock() + math.max(Y.Auctioneer.GetPurchaseCooldownAuctioneer() + 5, 12)
		Y.Auctioneer.SetStatusAuctioneer(string.format("Buying %s", G.displayName), "#FFCC66")
		Y.Auctioneer.AddLogAuctioneer(string.format("Buying %s | $%s | %d%%", G.displayName, u.formatShecklesNumber(G.currentPrice), G.discountPercent), "#FFCC66")
		local c, J = pcall(function()
			Z:Fire(V, G.currentPrice)
		end)
		if not c then
			Y.Auctioneer.PurchaseBusyAuctioneer = false
			Y.Auctioneer.PurchaseTimeoutAtAuctioneer = 0
			Y.Auctioneer.PendingCandidateAuctioneer = nil
			Y.Auctioneer.SetStatusAuctioneer("Buy failed", "#FF6666")
			Y.Auctioneer.AddLogAuctioneer("Buy failed: " .. tostring(J), "#FF6666")
			return false
		end
		return true
	end;
	CheckPurchaseTimeoutAuctioneer = function()
		if Y.Auctioneer.PurchaseBusyAuctioneer ~= true then
			return false
		end
		local G = tonumber(Y.Auctioneer.PurchaseTimeoutAtAuctioneer) or 0
		if G <= 0 or os.clock() < G then
			return false
		end
		local V = Y.Auctioneer.PendingCandidateAuctioneer
		Y.Auctioneer.PurchaseBusyAuctioneer = false
		Y.Auctioneer.PurchaseTimeoutAtAuctioneer = 0
		Y.Auctioneer.PendingCandidateAuctioneer = nil
		local y = type(V) == "table" and tostring(V.displayName or "Unknown") or "Unknown"
		Y.Auctioneer.SetStatusAuctioneer("Buy timed out", "#FF6666")
		Y.Auctioneer.AddLogAuctioneer("Buy timed out: " .. y, "#FF6666")
		Y.Auctioneer.SendWebhookAuctioneer(false, "Auction purchase timed out.", V)
		return true
	end,
