		end
		if E.Mail.IsSavedManualOrderValid(X.mail_manual_order) then
			local G = E.Mail.RunManualOrder(X.mail_manual_order)
			return G, G and "Resumed " .. tostring(X.mail_manual_order.id) or "Could not resume the saved order"
		end
