		end
		local V, y = E.Mail.LookupRecipient(G)
		if not V then
			return false, y
		end
		local Z = {
			version = 1,
			id = E.Mail.MakeId("EXO"),
			recipient = V;
			items = E.Mail.CloneDraftItems();
			pending = {};
			startedAt = os.time();
			state = "running";
