				E.Mail.SetStatus("Simple mail user error: " .. tostring(u), "#FF5555")
				return 0, true
			end
			E.Mail.SetStatus(string.format("Simple mail | Sending %d items to @%s", T, d.username), "#66CCFF")
			local q, g = E.Mail.SendBatch(d, c, "Simple mail", nil, true)
