				recipient = d.username;
				items = J
			})
			E.Mail.SetStatus(string.format("Simple mail | Sent %d items to @%s", T, d.username), "#7CFC00")
			return T, true
		end
		return 0, false
	end;
	ProcessCombinedAutoRules = function(G, V)
