			if y and y.userId ~= q then
				continue
			end
			local g = tostring(d.category) .. ("::" .. (tostring(d.itemName) .. ("::" .. tostring(d.filterKey or ""))))
			local H = math.max(math.floor(tonumber(d.triggerAmount) or 1), 1)
			local r = math.max(math.floor(tonumber(d.sendAmount) or 1), 1)
			local Y = E.Mail.GetAvailableCount(d.category, d.itemName, d.petTypes, d.petSizes, nil, d.fruitMinKg, d.fruitMaxKg, d.fruitMutations, d.fruitVariants, d.fruitMutationBlacklist, d.fruitVariantBlacklist)
