		local g = {}
		for G, V in ipairs(j) do
			local y = V.rule
			local Z = math.max(math.floor(tonumber(V.count) or 0), 0)
			local j = tostring(y.category) .. ("::" .. (tostring(y.itemName) .. ("::" .. tostring(y.filterKey or ""))))
