		local i = E.Webhooks.GetRequestFunction()
		if i then
			local G, y = pcall(function()
				return i({
					Url = V,
					Method = "POST",
					Headers = {
						["Content-Type"] = "application/json"
					};
					Body = j
				})
			end)
			if not G then
				return false, tostring(y)
			end
			if type(y) == "table" then
				local G = tonumber(y.StatusCode or y.Status or y.status_code)
				if G then
					return G >= 200 and G < 300, tostring(G)
				end
				if y.Success ~= nil then
					return y.Success == true, tostring(y.StatusMessage or "")
				end
			end
			return true
		end
		local c, J = pcall(function()
			y.HttpService:PostAsync(V, j, Enum.HttpContentType.ApplicationJson, false)
		end)
		if not c then
			return false, tostring(J)
		end
		return true
	end;
	GetPendingCount = function()
		local G = 0
		if X.webhook_pet_buys and type(q.PetFinder_WebhookData) == "table" then
			G += # q.PetFinder_WebhookData
		end
		if type(q.Mail_WebhookData) == "table" then
			for V, y in ipairs(q.Mail_WebhookData) do
				if type(y) == "table" and E.Webhooks.IsMailTypeEnabled(y.webhookType) then
					G += 1
				end
			end
		end
		if X.webhook_event_seeds and type(q.EventSeed_WebhookData) == "table" then
			G += # q.EventSeed_WebhookData
		end
		return G
	end,
	GetNextWebhook = function()
		if X.webhook_pet_buys and type(q.PetFinder_WebhookData) == "table" then
			while # q.PetFinder_WebhookData > 0 do
				local G = q.PetFinder_WebhookData[1]
				if type(G) ~= "table" then
					table.remove(q.PetFinder_WebhookData, 1)
					continue
				end
				local V = E.Webhooks.BuildPetBuyPayload(G)
				if not V then
					table.remove(q.PetFinder_WebhookData, 1)
					continue
				end
				return q.PetFinder_WebhookData, 1, V, "pet purchase"
			end
		end
		if X.webhook_event_seeds and type(q.EventSeed_WebhookData) == "table" then
			while # q.EventSeed_WebhookData > 0 do
				local G = q.EventSeed_WebhookData[1]
				if type(G) ~= "table" then
					table.remove(q.EventSeed_WebhookData, 1)
					continue
				end
				local V = E.Webhooks.BuildEventSeedPayload(G)
				if not V then
					table.remove(q.EventSeed_WebhookData, 1)
					continue
				end
				return q.EventSeed_WebhookData, 1, V, "event seed"
			end
		end
		if type(q.Mail_WebhookData) ~= "table" then
			q.Mail_WebhookData = {}
		end
		while # q.Mail_WebhookData > 0 do
			local G = q.Mail_WebhookData[1]
			if type(G) ~= "table" or not E.Webhooks.IsMailTypeEnabled(G.webhookType) then
				table.remove(q.Mail_WebhookData, 1)
				continue
			end
			local V = E.Webhooks.BuildMailPayload(G)
			if not V then
				table.remove(q.Mail_WebhookData, 1)
				continue
			end
			local y = {
				manual = "manual order",
				automatic = "automatic mail",
				claim = "claimed mail"
			}
			return q.Mail_WebhookData, 1, V, y[G.webhookType] or "mail notification"
		end
		return nil
	end;
	ProcessNext = function()
		local G = X.webhook_pet_buys or X.webhook_event_seeds or X.webhook_mail_manual or X.webhook_mail_auto or X.webhook_mail_claims
		if not G then
			E.Webhooks.ClearStatus()
			return false
		end
		local V = E.Webhooks.GetPendingCount()
		if not E.Webhooks.IsValidUrl(X.webhook_url) then
			if V > 0 then
				E.Webhooks.SetStatus(string.format("Add webhook URL | Pending: %d", V), "#FFCC66")
			else
				E.Webhooks.SetStatus("Add webhook URL", "#FFCC66")
			end
			return false
		end
		if V == 0 then
			E.Webhooks.SetStatus("Ready", "#CFCFCF")
			return false
		end
		local y, Z, j, i = E.Webhooks.GetNextWebhook()
		if not y or not j then
			E.Webhooks.SetStatus("Ready", "#CFCFCF")
			return false
		end
		E.Webhooks.SetStatus(string.format("Sending %s | Pending: %d", i, V), "#66CCFF")
		local c, J = E.Webhooks.Post(j)
		if not c then
			E.Webhooks.SetStatus(string.format("Send failed | Pending: %d", V), "#FF5555")
			warn("[Webhooks]", J)
			return false
		end
		table.remove(y, Z)
		E.Webhooks.SetStatus(string.format("%s sent | Pending: %d", i, E.Webhooks.GetPendingCount()), "#7CFC00")
		return true
	end;
	Loop = function()
		if not X.webhook_enabled then
			E.Webhooks.ClearStatus()
			return
		end
		local G, V = pcall(function()
			E.Webhooks.ProcessNext()
		end)
		if not G then
			E.Webhooks.SetStatus("Webhook loop error", "#FF5555")
			warn("[Webhooks] Loop error:", V)
		end
	end
}
