q.MoonPredictorStatusText = ""
E.MoonPredictor = {
	Started = false;
	DebugBusy = false;
	Label = nil;
	RollMode = "number",
	ValidationText = "Waiting for a night to validate";
	Colours = {
		Moon = "#B7C9FF",
		Goldmoon = "#FFD700";
		["Rainbow Moon"] = "#FF66FF";
		Bloodmoon = "#FF4444"
	},
	GetNight = function()
		local G = y.TimeCycleData and (y.TimeCycleData.Data and y.TimeCycleData.Data.Night)
		if type(G) ~= "table" or type(G.Weathers) ~= "table" then
			return nil
		end
		return G
	end,
	GetServerTime = function()
		local G, V = pcall(function()
			return y.Workspace:GetServerTimeNow()
		end)
		return G and tonumber(V) or os.time()
	end,
	Pick = function(G, V)
		local y = E.MoonPredictor.GetNight()
		if not y then
			return nil
		end
		local Z = 0
		for G, V in y.Weathers do
			if type(V) == "table" then
				Z += tonumber(V.Chance) or 0
			end
		end
		if Z <= 0 then
			return nil
		end
		local j = math.floor(tonumber(G) or 0) * 1000 + 3
		local i = Random.new(j)
		local c = V == "integer" and i:NextInteger(1, math.floor(Z)) or i:NextNumber(0, Z)
		local J = 0
		for G, V in y.Weathers do
			if type(V) ~= "table" then
				continue
			end
			J += tonumber(V.Chance) or 0
			if c <= J then
				return tostring(G), c, j
			end
		end
		return "Moon", c, j
	end;
	ValidateCurrent = function()
		if tostring(y.Workspace:GetAttribute("ActivePhase") or "") ~= "Night" then
			return false
		end
		local G = tostring(y.Workspace:GetAttribute("ActiveWeather") or "")
		local V = E.MoonPredictor.GetNight()
		if not V or type(V.Weathers[G]) ~= "table" then
			return false
		end
		local Z = math.floor(os.time() / 600)
		local j = E.MoonPredictor.Pick(Z, "number")
		local i = E.MoonPredictor.Pick(Z, "integer")
		if j == G and i ~= G then
			E.MoonPredictor.RollMode = "number"
			E.MoonPredictor.ValidationText = "NextNumber confirmed by live moon"
			return true
		end
		if i == G and j ~= G then
			E.MoonPredictor.RollMode = "integer"
			E.MoonPredictor.ValidationText = "NextInteger confirmed by live moon"
			return true
		end
		if j == G and i == G then
			E.MoonPredictor.ValidationText = "Both methods match the live moon"
			return true
		end
		E.MoonPredictor.ValidationText = "Live moon differs; it may be forced"
		return false
	end;
	GetNextNightAt = function()
		local G = E.MoonPredictor.GetServerTime()
		local V = tostring(y.Workspace:GetAttribute("ActivePhase") or "")
		local Z = tonumber(y.Workspace:GetAttribute("PhaseDuration"))
		local j = y.TimeCycleData and y.TimeCycleData.Data
		local i = j and (j.Day and tonumber(j.Day.Lasts)) or 450
		local c = j and (j.Sunset and tonumber(j.Sunset.Lasts)) or 30
		if Z then
			if V == "Night" then
				return (Z + i) + c
			elseif V == "Day" then
				return Z + c
			elseif V == "Sunset" then
				return Z
			end
		end
		local J = math.floor(G / 600) * 600
		local T = (J + i) + c
		return G < T and T or T + 600
	end,
	GetRare = function(G, V)
		G = math.clamp(math.floor(tonumber(G) or 1), 1, 20)
		V = V == "integer" and "integer" or "number"
		local y = E.MoonPredictor.GetNextNightAt()
		local Z = math.floor(y / 600)
		local j = {}
		for i = 0, 999, 1 do
			local c, J, T = E.MoonPredictor.Pick(Z + i, V)
			if c and c ~= "Moon" then
				table.insert(j, {
					Name = c,
					At = y + i * 600;
					Roll = J,
					Seed = T
				})
				if # j >= G then
					break
				end
			end
		end
		return j
	end,
	FormatTime = function(G)
		G = math.max(math.floor(tonumber(G) or 0), 0)
		local V = math.floor(G / 3600)
		local y = math.floor(((G % 3600)) / 60)
		local Z = G % 60
		if V > 0 then
			return string.format("%dh %02dm", V, y)
		end
		if y > 0 then
			return string.format("%dm %02ds", y, Z)
		end
		return string.format("%ds", Z)
	end;
	GetLines = function(G, V, y)
		local Z = E.MoonPredictor.GetServerTime()
		local j = {}
		for G, V in ipairs(E.MoonPredictor.GetRare(V, G)) do
			if y then
				table.insert(j, string.format("%d. **%s** \226\128\148 <t:%d:R> (`%d`)", G, V.Name, math.floor(V.At), V.Seed))
			else
				local G = E.MoonPredictor.Colours[V.Name] or "#FFFFFF"
				table.insert(j, string.format("<font color=\'%s\'>%s</font> <font color=\'#7CFC00\'>in %s</font>", G, V.Name, E.MoonPredictor.FormatTime(V.At - Z)))
			end
		end
		return j
	end;
	Update = function()
		if not X.moon_predictor_enabled then
			q.MoonPredictorStatusText = ""
			if E.MoonPredictor.Label and type(E.MoonPredictor.Label.SetText) == "function" then
