			local Z = E.Teleport.LockTeleport(y, X.garden_items_use_player_walk and 35 or 2, X.garden_items_use_player_walk == true)
			if not Z then
				E.GardenItems.Busy = false
				return false
			end
			local j, i = pcall(function()
				if X.garden_items_use_player_walk then
					if not E.Movement.WalkPathToTarget(G, 30, y, 10) then
						return false
					end
