	PotPlantPottedPlantWeatherGuard = function(G, V)
		if type(G) ~= "table" or G.id == "" then
			return false
		end
		if G.isPotted == true then
			return true
		end
		local Z = y.Networking and (y.Networking.Garden and y.Networking.Garden.PotPlant)
		if not Z or type(Z.Fire) ~= "function" then
			return false, "Pot action unavailable"
		end
		if not V or not V.Parent then
			V = E.GardenItems.PottedPlantWeatherGuard.GetEmptyPotToolPottedPlantWeatherGuard()
		end
		if not V or not V.Parent then
			return false, "Basic Pot not found"
		end
		local j = E.StackKeepOverrides.GetGearNameFromToolStackKeepOverrides(V, "Basic Pot")
		local i = E.StackKeepOverrides.GetToolCountStackKeepOverrides(V)
		if E.StackKeepOverrides.ShouldSkipItemStackKeepOverrides("Gear", j, i) then
			return false, "Basic Pot not found"
		end
		if not E.Player.IsToolHeld(V) and not E.Player.EquipTool(V) then
			return false, "Could not equip Basic Pot"
		end
		local c = false
		local J
		local T = y.Networking and (y.Networking.Garden and y.Networking.Garden.PlantPotted)
		if T and T.OnClientEvent then
			J = T.OnClientEvent:Connect(function(V)
				if E.GardenItems.PottedPlantWeatherGuard.CleanPlantIdPottedPlantWeatherGuard(V) == G.id then
					c = true
				end
			end)
		end
		local d, u = pcall(function()
			Z:Fire(G.id)
		end)
		if not d then
			if J then
				J:Disconnect()
			end
			return false, tostring(u or "Pot action failed")
		end
		local q = os.clock()
		repeat
			task.wait(.05)
		until c or os.clock() - q >= 1.5
		if J then
			J:Disconnect()
			if not c then
				return false, "Pot not confirmed"
			end
		else
			task.wait(.35)
		end
		return true
	end,
	PickUpPlantPottedPlantWeatherGuard = function(G)
		if type(G) ~= "table" or G.id == "" then
			return false
		end
		local V = y.Networking and (y.Networking.PotPlacement and y.Networking.PotPlacement.PickUpPottedPlant)
		if not V or type(V.Fire) ~= "function" then
