			V:Fire(G.id)
		end)
		if not Z then
			return false, tostring(j or "Pickup failed")
		end
		return true
	end,
	ProtectMatchingPlantsPottedPlantWeatherGuard = function(G)
		local V = E.GardenItems.PottedPlantWeatherGuard
		local y = V.GetMatchingPlantsPottedPlantWeatherGuard()
		if # y == 0 then
			V.SetStatusPottedPlantWeatherGuard("No matching plants or pots", "#CFCFCF")
			return false
		end
		local Z = V.GetEmptyPotToolPottedPlantWeatherGuard()
		local j = math.clamp(math.floor(tonumber(X.potted_weather_guard_max_per_cycle) or 3), 1, 25)
		local i = math.clamp(tonumber(X.potted_weather_guard_action_delay) or .35, .1, 5)
		local c = 0
		local J = ""
		for y, T in ipairs(y) do
			if c >= j or X.potted_weather_guard_enabled ~= true then
				break
			end
			local d = "plant:" .. tostring(T.id)
			if os.clock() < ((q.PottedPlantWeatherGuardRetryAt[d] or 0)) then
				continue
			end
			if not T.isPotted then
				local G, y = V.PotPlantPottedPlantWeatherGuard(T, Z)
				if not G then
					J = tostring(y or "Pot failed")
					q.PottedPlantWeatherGuardRetryAt[d] = os.clock() + 3
					V.SetStatusPottedPlantWeatherGuard(J, "#FF6666")
					continue
				end
			end
			local u, g = V.PickUpPlantPottedPlantWeatherGuard(T)
			if u then
				c += 1
				q.PottedPlantWeatherGuardRetryAt[d] = os.clock() + 2
				V.SetStatusPottedPlantWeatherGuard(string.format("Stored %s during %s", T.plantName, tostring(G or "weather")), "#7CFC00")
				task.wait(i)
			else
				J = tostring(g or "Pickup failed")
				q.PottedPlantWeatherGuardRetryAt[d] = os.clock() + 3
				V.SetStatusPottedPlantWeatherGuard(J, "#FF6666")
			end
		end
		if c == 0 and J == "" then
			V.SetStatusPottedPlantWeatherGuard("Waiting for matching plants", "#CFCFCF")
		end
		return c > 0
	end;
	RestoreMatchingPotsPottedPlantWeatherGuard = function()
		local G = E.GardenItems.PottedPlantWeatherGuard
		local V = X.potted_weather_guard_selected_plants
		if G.IsSelectionEmptyPottedPlantWeatherGuard(V) then
			G.SetStatusPottedPlantWeatherGuard("Select plants", "#FFCC66")
			return false
		end
		local Z = G.GetPottedPlantToolsPottedPlantWeatherGuard()
		local j = math.clamp(math.floor(tonumber(X.potted_weather_guard_max_per_cycle) or 3), 1, 25)
		local i = math.clamp(tonumber(X.potted_weather_guard_action_delay) or .35, .1, 5)
		local c = E.Seeder.GetOccupiedPositions()
		local J = 0
		for Z, T in ipairs(Z) do
			if J >= j or X.potted_weather_guard_enabled ~= true then
				break
			end
			if not G.IsSelectedPottedPlantWeatherGuard(V, T.plantName) then
				continue
			end
			local d = "tool:" .. tostring(T.id)
			if os.clock() < ((q.PottedPlantWeatherGuardRetryAt[d] or 0)) then
				continue
			end
			local g, a, H = G.GetSavedPlacementPottedPlantWeatherGuard(q.PottedPlantWeatherGuardNextStackIndex, c)
			if not g then
				G.SetStatusPottedPlantWeatherGuard(H or "Copy a stack CFrame", "#FFCC66")
				return false
			end
			if not E.Player.IsToolHeld(T.tool) and not E.Player.EquipTool(T.tool) then
				q.PottedPlantWeatherGuardRetryAt[d] = os.clock() + 2
				G.SetStatusPottedPlantWeatherGuard("Could not equip potted plant", "#FF6666")
				continue
			end
			local r = y.Networking and (y.Networking.PotPlacement and y.Networking.PotPlacement.PlacePottedPlant)
			if not r or type(r.Fire) ~= "function" then
				G.SetStatusPottedPlantWeatherGuard("Place action unavailable", "#FF6666")
				return false
			end
			local Y, e = pcall(function()
				r:Fire(g, a, T.id)
			end)
			if Y then
				J += 1
				q.PottedPlantWeatherGuardNextStackIndex += 1
				u.PositionGrid.Add(c, g)
				q.PottedPlantWeatherGuardRetryAt[d] = os.clock() + 2
				G.SetStatusPottedPlantWeatherGuard("Restored " .. tostring(T.plantName), "#7CFC00")
				task.wait(i)
			else
				u.PositionGrid.Add(c, g)
				q.PottedPlantWeatherGuardRetryAt[d] = os.clock() + 3
				G.SetStatusPottedPlantWeatherGuard(tostring(e or "Place failed"), "#FF6666")
			end
		end
		if J == 0 then
			G.SetStatusPottedPlantWeatherGuard("Waiting for stored matching pots", "#CFCFCF")
		end
		return J > 0
	end;
	LoopPottedPlantWeatherGuard = function()
		local G = E.GardenItems.PottedPlantWeatherGuard
		if X.potted_weather_guard_enabled ~= true then
			G.SetStatusPottedPlantWeatherGuard("")
