E.PlantModelCleaner = {
	StartedPlantModelCleaner = false,
	ConnectionsPlantModelCleaner = {};
	FolderConnectionsPlantModelCleaner = {};
	DestroyedPlantModelCleaner = 0;
	IsActivePlantModelCleaner = function()
		local G = E.TotalControl
		local V = G and (type(G.ResolveFruitCollectPreventDestroyPlantsTotalControl) == "function" and G.ResolveFruitCollectPreventDestroyPlantsTotalControl()) or nil
		local y = V == nil and X.fruit_collect_prevent_destroy_plants or V == true
		if y then
			return false
		end
		local Z = G and (type(G.ResolveHighModeEnabledTotalControl) == "function" and G.ResolveHighModeEnabledTotalControl()) or nil
		local j = Z == nil and X.high_mode or Z == true
		if j and q.GetCheckIfPro() == true then
			return true
		end
		return false
	end,
	SetStatusPlantModelCleaner = function(G, V)
		q.PlantModelCleanerStatusText = string.format("<stroke color=\'#000000\' thickness=\'1\'><font color=\'#FFFFFF\'>\240\159\140\177 [Plant Models]</font> <font color=\'%s\'>%s</font></stroke>", tostring(V or "#FFFFFF"), tostring(G or ""))
	end;
	DestroyObjectPlantModelCleaner = function(G)
		if not E.PlantModelCleaner.IsActivePlantModelCleaner() then
			return false
		end
		if typeof(G) ~= "Instance" or not G.Parent then
			return false
		end
		local V = pcall(function()
			G:Destroy()
		end)
		if V then
			E.PlantModelCleaner.DestroyedPlantModelCleaner += 1
		end
		return V
	end;
	CleanFolderPlantModelCleaner = function(G)
		if not E.PlantModelCleaner.IsActivePlantModelCleaner() then
			return false
		end
		if typeof(G) ~= "Instance" or not G.Parent then
			return false
		end
		local V = G:GetChildren()
		for G, V in ipairs(V) do
			if not E.PlantModelCleaner.IsActivePlantModelCleaner() then
				break
			end
			E.PlantModelCleaner.DestroyObjectPlantModelCleaner(V)
			if G % 50 == 0 then
				task.wait()
			end
		end
		return true
	end,
	HookFolderPlantModelCleaner = function(G)
		if typeof(G) ~= "Instance" or not G.Parent then
			return false
		end
		if E.PlantModelCleaner.FolderConnectionsPlantModelCleaner[G] then
			return true
		end
		local V = G.ChildAdded:Connect(function(G)
			if not E.PlantModelCleaner.IsActivePlantModelCleaner() then
				return
			end
			task.defer(function()
				E.PlantModelCleaner.DestroyObjectPlantModelCleaner(G)
			end)
		end)
		E.PlantModelCleaner.FolderConnectionsPlantModelCleaner[G] = V
		table.insert(E.PlantModelCleaner.ConnectionsPlantModelCleaner, V)
		if E.PlantModelCleaner.IsActivePlantModelCleaner() then
			E.PlantModelCleaner.CleanFolderPlantModelCleaner(G)
		end
		return true
	end,
	HookOwnPlantsFolderPlantModelCleaner = function()
		local G = E.Farm.GetMyPlantsFolder()
		if not G or not G.Parent then
			return false
		end
		return E.PlantModelCleaner.HookFolderPlantModelCleaner(G)
	end,
	HookOtherPlantsFoldersPlantModelCleaner = function()
		for G, V in ipairs(E.Farm.GetMyPlantsFoldersNotMine()) do
			if not V or not V.Parent then
				continue
			end
			local y = V:FindFirstChild("Plants")
			if y then
				E.PlantModelCleaner.HookFolderPlantModelCleaner(y)
			end
		end
		return true
	end;
	HookGardenPlotsPlantModelCleaner = function()
		local G = y.Workspace:FindFirstChild("Gardens")
		if not G then
			return false
		end
		local V = G.ChildAdded:Connect(function(G)
			task.defer(function()
				if not G or not G.Parent then
					return
				end
				local V = G:FindFirstChild("Plants")
				if V then
					E.PlantModelCleaner.HookFolderPlantModelCleaner(V)
					return
				end
				local y
				y = G.ChildAdded:Connect(function(G)
					if G and G.Name == "Plants" then
						E.PlantModelCleaner.HookFolderPlantModelCleaner(G)
						if y then
							y:Disconnect()
						end
					end
				end)
				table.insert(E.PlantModelCleaner.ConnectionsPlantModelCleaner, y)
			end)
		end)
		table.insert(E.PlantModelCleaner.ConnectionsPlantModelCleaner, V)
		return true
	end;
	RemovePlantByIdPlantModelCleaner = function(G)
		if not E.PlantModelCleaner.IsActivePlantModelCleaner() then
			return false
		end
		G = tostring(G or "")
		if G == "" then
			return false
		end
		local V = E.Farm.GetMyPlantsFolder()
		if not V or not V.Parent then
			return false
		end
		local y = V:FindFirstChild(G)
		if y then
			return E.PlantModelCleaner.DestroyObjectPlantModelCleaner(y)
		end
		for V, y in ipairs(V:GetChildren()) do
			if tostring(y:GetAttribute("PlantId") or y:GetAttribute("PlantID") or y:GetAttribute("Id") or y.Name or "") == G then
				return E.PlantModelCleaner.DestroyObjectPlantModelCleaner(y)
			end
		end
		return false
	end;
	ApplyPlantModelCleaner = function()
		E.PlantModelCleaner.HookOwnPlantsFolderPlantModelCleaner()
		E.PlantModelCleaner.HookOtherPlantsFoldersPlantModelCleaner()
		if E.PlantModelCleaner.IsActivePlantModelCleaner() then
			E.PlantModelCleaner.SetStatusPlantModelCleaner("Removing live plant models", "#7CFC00")
		else
			E.PlantModelCleaner.SetStatusPlantModelCleaner("Idle", "#CFCFCF")
		end
		return true
	end,
	StartPlantModelCleaner = function()
		if E.PlantModelCleaner.StartedPlantModelCleaner then
			return false
		end
		E.PlantModelCleaner.StartedPlantModelCleaner = true
		E.PlantModelCleaner.HookGardenPlotsPlantModelCleaner()
		task.spawn(function()
			while not q.is_forced_stop do
				task.wait(3)
				local G = E.TotalControl
				local V = G and (type(G.ResolveHighModeEnabledTotalControl) == "function" and G.ResolveHighModeEnabledTotalControl()) or nil
				local y = V == nil and X.high_mode or V == true
				if not y then
					continue
				end
				pcall(E.PlantModelCleaner.ApplyPlantModelCleaner)
			end
		end)
		return true
	end;
	RemoveAllPlants = function()
		local G = y.Workspace:FindFirstChild("Gardens")
		if G then
			for G, V in ipairs(G:GetChildren()) do
				local y = V:FindFirstChild("Plants")
				if y then
					for G, V in ipairs(y:GetChildren()) do
						if V then
							V:Destroy()
						end
					end
				end
			end
		end
	end,
	StartPlantRemovelSys = function()
		task.spawn(function()
			while true do
				task.wait(5)
				if not E.PlantModelCleaner.IsActivePlantModelCleaner() then
					continue
				end
				E.PlantModelCleaner.RemoveAllPlants()
			end
		end)
	end
}
E.PlantModelCleaner.StartPlantRemovelSys()
