q.AutoUi = function()
	local G = T:AddTab({
		Name = "Seed Placer",
		Description = "Places selected seeds",
		Icon = "sprout"
	})
	local V = G:AddLeftGroupbox("Seed Placement", "sprout")
	local y = G:AddRightGroupbox("Seed Target Overrides", "list-plus")
	if y then
		local G = ""
		local V = math.max(math.floor(tonumber(X.seed_place_default_target) or 10), 1)
		local Z = false
		local j = {}
		local i = 0
		local c
		local J
		y:AddLabel({
			Text = "\240\159\146\161 Set a different planting target for individual seeds.",
			DoesWrap = true
		})
		local function T()
			for G, V in ipairs(j) do
				if V.Holder and typeof(V.Holder) == "Instance" then
					V.Holder:Destroy()
				end
			end
			table.clear(j)
			if y.Resize then
				y:Resize()
			end
		end
		local function d()
			local V = E.Seeder.GetOverrideTarget(G)
			if V ~= nil then
				return V
			end
			return math.max(math.floor(tonumber(X.seed_place_default_target) or 10), 1)
		end
		local function u()
			if G == "" then
				return
			end
			V = d()
			Z = true
			if c then
				c:SetValue(tostring(V))
				c:SetText(string.format("\240\159\142\175 Target Amount: <font color=\'#7CFC00\'>%d</font>", V))
			end
			if J then
				J:SetValue(E.Seeder.GetOverrideTarget(G) ~= nil)
			end
			Z = false
		end
		local g
		g = function()
			T()
			i += 1
			local V = {}
			if type(X.seed_place_overrides) == "table" then
				for G in pairs(X.seed_place_overrides) do
					if E.Seeder.GetOverrideTarget(G) ~= nil then
						table.insert(V, G)
					end
				end
			end
			table.sort(V)
			if # V == 0 then
				local G = y:AddLabel({
					Text = "<font color=\'#888888\'>No active seed overrides</font>",
					DoesWrap = true
				})
				table.insert(j, G)
			else
				for V, Z in ipairs(V) do
					local c = E.Seeder.GetOverrideTarget(Z)
					local J
					J = y:AddToggle(string.format("seed_active_override_%d_%d", i, V), {
						Text = string.format("\240\159\140\177 %s <font color=\'#7CFC00\'>Target: %d</font>", Z, c);
						Default = true;
						Tooltip = "Disable this seed override.",
						Callback = function(V)
							if V then
								return
							end
							E.Seeder.RemoveOverrideTarget(Z)
							a.Save.SaveDataSync()
							if G == Z then
								u()
							end
							task.defer(g)
						end
					})
					table.insert(j, J)
				end
			end
			if y.Resize then
				y:Resize()
			end
		end
		local H
		H = y:AddValueDropdown("seed_placer_override_seed", {
			Values = {},
			Default = "",
			Multi = false,
			Searchable = true,
			MaxVisibleDropdownItems = 10;
			Text = "\240\159\140\177 Select Seed",
			Tooltip = "Select a seed to configure its target.";
			Changed = function(V)
				if type(V) ~= "string" or V == "" then
					return
				end
				G = V
				u()
			end
		})
		H:SetValues(E.SeedData.GetSeedDataListDropDown())
		c = y:AddInput("seed_placer_override_target", {
			Text = "\240\159\142\175 Target Amount";
			Default = tostring(V),
			Numeric = true,
			AllowEmpty = true,
			Finished = true,
			ClearTextOnFocus = false,
			Placeholder = "Enter target amount";
			Tooltip = "Sets how many of this seed should remain planted.";
			Callback = function(y)
				if Z then
					return
				end
				if G == "" then
					q.Notify("Select a seed first", 3)
					return
				end
				local j = S(y)
				if not j or j <= 0 then
					q.Notify("Target must be above 0", 3)
					u()
					return
				end
				V = j
				c:SetText(string.format("\240\159\142\175 Target Amount: <font color=\'#7CFC00\'>%d</font>", V))
				if E.Seeder.GetOverrideTarget(G) ~= nil then
					E.Seeder.SetOverrideTarget(G, V)
					a.Save.SaveDataSync()
					g()
				end
			end
		})
		J = y:AddToggle("seed_placer_enable_selected_override", {
			Text = "\240\159\146\165 Enable Override";
			Default = false,
			Tooltip = "Use the custom target for the selected seed.";
			Callback = function(y)
				if Z then
					return
				end
