E.GardenSyncDebug = {
	GetGardenSyncDebug = function()
		local G = y.GardenSyncController
		if type(G) ~= "table" or type(G.GetGarden) ~= "function" then
			return nil, "GardenSyncController unavailable"
		end
		local V, Z = pcall(function()
			return G:GetGarden(q.player_userid)
		end)
		if not V or type(Z) ~= "table" then
			return nil, "No garden sync data"
		end
		return Z, nil
	end;
	GetSavePathGardenSyncDebug = function()
		local G = "exotichub99"
		local V = G .. "/debug"
		if type(isfolder) == "function" and type(makefolder) == "function" then
			if not isfolder(G) then
				makefolder(G)
			end
			if not isfolder(V) then
				makefolder(V)
			end
		end
		local y = os.date("%Y%m%d_%H%M%S")
		return V .. ("/garden_sync_" .. (tostring(q.player_userid or "player") .. ("_" .. (y .. ".json"))))
	end,
	SaveGardenSyncJsonDebug = function(G)
		if type(writefile) ~= "function" then
			if G then
				G:SetText("writefile is not supported by this executor")
			end
			q.Notify("writefile is not supported", 3)
			return false
		end
		local V, Z = E.GardenSyncDebug.GetGardenSyncDebug()
		if not V then
			if G then
				G:SetText(tostring(Z or "No garden sync data"))
			end
			q.Notify(tostring(Z or "No garden sync data"), 3)
			return false
		end
		local j, i = pcall(function()
			return y.HttpService:JSONEncode(V)
		end)
		if not j or type(i) ~= "string" or i == "" then
			if G then
				G:SetText("JSON encode failed")
			end
			q.Notify("JSON encode failed", 3)
			return false
		end
		local c = E.GardenSyncDebug.GetSavePathGardenSyncDebug()
		local J, T = pcall(function()
			writefile(c, i)
		end)
		if not J then
			if G then
				G:SetText("Save failed: " .. tostring(T))
			end
			q.Notify("Garden sync save failed", 3)
			return false
		end
		if G then
			G:SetText("Saved Garden Sync JSON\n" .. (c .. ("\nLength: " .. tostring(# i))))
		end
		q.Notify("Garden sync JSON saved", 2)
		return true
	end;
	BuildGardenSyncDebugUi = function(G)
		if not G then
			return false
		end
		local V = nil
		G:AddDivider()
		G:AddButton({
			Text = "Save Garden Sync JSON",
			Func = function()
				E.GardenSyncDebug.SaveGardenSyncJsonDebug(V)
			end
		})
		V = G:AddLabel({
			Text = "Press save to write live garden sync JSON to file.",
			DoesWrap = true
		})
		return true
	end
}
E.FarmGridDebug = {
	FolderNameFarmGridDebug = "ExoFarmGridDebug",
	DotSizeFarmGridDebug = .18,
	GridSpacingFarmGridDebug = .5;
	EdgePaddingFarmGridDebug = 0;
	PlantBlockDistanceFarmGridDebug = .5,
	ShowLabelsFarmGridDebug = false,
	ClearFarmGridDebug = function()
		local G = E.Farm.GetOwnPlot()
		local V = G and G:FindFirstChild(E.FarmGridDebug.FolderNameFarmGridDebug)
		if V then
			V:Destroy()
		end
		return true
	end,
	GetPlantBlockPositionsFarmGridDebug = function()
		local G = {}
		local V = E.FruitFiltersDataSync
		local y = E.Farm.GetSpawnPoint()
		if not V or type(V.Plants) ~= "table" or typeof(y) ~= "Instance" or not y:IsA("BasePart") then
			return G
		end
		if not V.Started and type(V.StartSync) == "function" then
			V.StartSync()
		end
		for V, Z in pairs(V.Plants) do
			local j = type(Z) == "table" and (not Z.Removed and Z.Positions) or nil
			local i = type(j) == "table" and tonumber(j.PosX) or nil
			local c = type(j) == "table" and tonumber(j.PosY) or nil
			local J = type(j) == "table" and tonumber(j.PosZ) or nil
			if i and (c and J) then
				table.insert(G, y.CFrame:PointToWorldSpace(Vector3.new(i, c, J)))
			end
		end
		return G
	end;
	GetSprinklerBlockPositionsFarmGridDebug = function()
		local G = {}
		local V = E.SprinklerPlacer.GetSprinklersFolder()
		if not V then
			return G
		end
		for V, y in ipairs(V:GetChildren()) do
			local Z = nil
			if y:IsA("Model") then
				local G, V = pcall(function()
					return y:GetPivot()
				end)
				Z = G and (typeof(V) == "CFrame" and V.Position) or nil
			elseif y:IsA("BasePart") then
				Z = y.Position
			end
			if typeof(Z) == "Vector3" then
				table.insert(G, Z)
			end
		end
		return G
	end,
	IsBlockedFarmGridDebug = function(G, V, y)
		if typeof(G) ~= "Vector3" then
			return false
		end
		for V, y in ipairs(V or {}) do
			if typeof(y) == "Vector3" and (Vector3.new(G.X - y.X, 0, G.Z - y.Z)).Magnitude < E.FarmGridDebug.PlantBlockDistanceFarmGridDebug then
				return true
			end
		end
		for V, y in ipairs(y or {}) do
			if typeof(y) == "Vector3" and (Vector3.new(G.X - y.X, 0, G.Z - y.Z)).Magnitude < E.FarmGridDebug.GridSpacingFarmGridDebug then
				return true
			end
		end
		return false
	end;
	GetColourFarmGridDebug = function(G, V, y)
		if y then
			return Color3.fromRGB(35, 145, 255)
		end
		local Z = V > 0 and math.clamp(G / V, 0, 1) or 0
		return Color3.fromRGB(math.floor(255 * Z), math.floor(255 * ((1 - Z))), 0)
	end,
	CreateDotFarmGridDebug = function(G, V, y, Z)
		local j = Instance.new("Part")
		j.Name = string.format("FarmGrid_%04d_%s_X%.1f_Z%.1f", V.index, V.areaName, V.localPosition.X, V.localPosition.Z)
		j.Shape = Enum.PartType.Ball
		j.Size = Vector3.new(E.FarmGridDebug.DotSizeFarmGridDebug, E.FarmGridDebug.DotSizeFarmGridDebug, E.FarmGridDebug.DotSizeFarmGridDebug)
		j.Anchored = true
		j.CanCollide = false
		j.CanQuery = false
		j.CanTouch = false
		j.Material = Enum.Material.Neon
		j.Color = y
		j.Position = V.position + Vector3.new(0, .08, 0)
		j:SetAttribute("SpotIndex", V.index)
		j:SetAttribute("AreaName", V.areaName)
		j:SetAttribute("LocalX", V.localPosition.X)
		j:SetAttribute("LocalZ", V.localPosition.Z)
		j:SetAttribute("DistanceFromCenter", math.floor(((V.distance or 0)) * 100) / 100)
		j:SetAttribute("SquareRing", tonumber(V.squareRing) or 0)
		j:SetAttribute("Blocked", Z == true)
		j.Parent = G
		local i = Instance.new("BillboardGui")
		i.Name = "SpotNumber"
		i.Enabled = E.FarmGridDebug.ShowLabelsFarmGridDebug == true
		i.AlwaysOnTop = true
		i.Size = UDim2.fromOffset(36, 14)
		i.StudsOffset = Vector3.new(0, .45, 0)
		i.Parent = j
		local c = Instance.new("TextLabel")
		c.BackgroundTransparency = 1
		c.Size = UDim2.fromScale(1, 1)
		c.Text = tostring(V.index)
		c.TextColor3 = Color3.new(1, 1, 1)
		c.TextScaled = true
		c.TextStrokeTransparency = 0
		c.Parent = i
	end,
	SetLabelsVisibleFarmGridDebug = function(G)
		E.FarmGridDebug.ShowLabelsFarmGridDebug = G == true
		local V = E.Farm.GetOwnPlot()
		local y = V and V:FindFirstChild(E.FarmGridDebug.FolderNameFarmGridDebug)
		if not y then
			return false
		end
		for G, V in ipairs(y:GetChildren()) do
			local y = V:FindFirstChild("SpotNumber")
			if y then
				y.Enabled = E.FarmGridDebug.ShowLabelsFarmGridDebug
			end
		end
		return true
	end;
	GenerateFarmGridDebug = function()
		local G = E.Farm.GetOwnPlot()
		local V = E.Farm.GetPermanentCenterPosition()
		if not G or typeof(V) ~= "Vector3" then
			return false, "Farm grid unavailable"
		end
		local y = E.FarmGrid.GetSortedSpotsFarmGrid(V, "BothCol")
		if # y == 0 then
			return false, "Farm grid unavailable"
		end
		E.FarmGridDebug.ClearFarmGridDebug()
		local Z = Instance.new("Folder")
		Z.Name = E.FarmGridDebug.FolderNameFarmGridDebug
		Z.Parent = G
		local j = 0
		for G, V in ipairs(y) do
			j = math.max(j, tonumber(V.squareRing) or tonumber(V.distance) or 0)
		end
		local i = E.FarmGridDebug.GetPlantBlockPositionsFarmGridDebug()
		local c = E.FarmGridDebug.GetSprinklerBlockPositionsFarmGridDebug()
		local J = 0
		local T = E.FarmGrid.GetAreaCountsFarmGrid(y)
		for G, V in ipairs(y) do
			local y = E.FarmGridDebug.IsBlockedFarmGridDebug(V.position, i, c)
			if y then
				J += 1
			end
			E.FarmGridDebug.CreateDotFarmGridDebug(Z, V, E.FarmGridDebug.GetColourFarmGridDebug(V.squareRing or V.distance, j, y), y)
		end
		local d = {}
		for G, V in pairs(T) do
			table.insert(d, tostring(G) .. (": " .. tostring(V)))
		end
		table.sort(d)
		return true, string.format("Generated %d spots | %d blocked | %s", # y, J, table.concat(d, " | "))
	end
}
q.TestGardenSync = {
	Started = false;
	RenderLoopRunning = false;
	Connections = {},
	Plants = {};
	Fruits = {};
	RemovedFruits = {};
	BaseWeightCache = {};
	GenerationModuleCache = {};
	WeightFormatCache = nil;
	OvertimeFlagsCache = nil;
	CalculateOvertimeGrowthCache = nil,
	GrowRateDataCache = nil,
	Label = nil,
	Dropdown = nil;
	WatchPlantId = "";
	RenderInterval = .35,
	MaxPlants = 3;
	MaxFruitsPerPlant = 12;
	Colours = {
		Title = "#7CFC00";
		Plant = "#6EE7FF";
		Fruit = "#FFFFFF",
		Ready = "#7CFC00",
		Growing = "#FFD166",
		Removed = "#FF5C5C";
		Muted = "#AAAAAA";
		Gold = "#FFD700";
		Rainbow = "#FF66FF",
		Normal = "#DADADA";
		Kg = "#7CFC00",
		Id = "#888888";
		Bad = "#FF5C5C"
	},
	Now = function()
		return os.clock()
	end,
	WallNow = function()
		return os.time()
	end,
	S = function(G)
		return tostring(G or "")
	end;
	N = function(G, V)
		local y = tonumber(G)
		if y == nil then
			return V or 0
		end
		return y
	end,
	Round2 = function(G)
		G = tonumber(G) or 0
		return math.floor((G * 100) + .5) / 100
	end,
	Round4 = function(G)
		G = tonumber(G) or 0
		return math.floor((G * 10000) + .5) / 10000
	end,
	ShortId = function(G)
		G = tostring(G or "")
		if # G <= 8 then
			return G
		end
		return string.sub(G, 1, 8)
	end;
	Html = function(G)
		G = tostring(G or "")
		G = G:gsub("&", "&amp;")
		G = G:gsub("<", "&lt;")
		G = G:gsub(">", "&gt;")
		G = G:gsub("\"", "&quot;")
		return G
	end;
	C = function(G, V)
		return string.format("<font color=\"%s\">%s</font>", G or "#FFFFFF", q.TestGardenSync.Html(V))
	end;
	Key = function(G, V)
		return tostring(G or "") .. ("\031" .. tostring(V or ""))
	end;
	IsMine = function(G)
		return tonumber(G) == tonumber(q.player_userid)
	end;
	SafeRequire = function(G)
		if not G then
			return nil
		end
		local V, Z = pcall(function()
			if type(y.safeRequire) == "function" then
				return y.safeRequire(G)
			end
			return require(G)
		end)
		if V then
			return Z
		end
		return nil
	end;
	GetGarden = function()
		local G = y.GardenSyncController
		if type(G) ~= "table" or type(G.GetGarden) ~= "function" then
			return nil
		end
		local V, Z = pcall(function()
			return G:GetGarden(q.player_userid)
		end)
		if V and type(Z) == "table" then
			return Z
		end
		return nil
	end,
	CopyFields = function(G, V)
		if type(G) ~= "table" or type(V) ~= "table" then
			return V
		end
		for G, y in pairs(G) do
			if type(y) ~= "table" then
				V[G] = y
			elseif G == "Positions" then
				V[G] = {
					PosX = y.PosX,
					PosY = y.PosY;
					PosZ = y.PosZ,
					Rotation = y.Rotation
				}
			end
		end
		return V
	end;
	MutationText = function(G)
		if type(G) ~= "string" then
			return ""
		end
		return G
	end;
	GetVariant = function(G, V)
		G = q.TestGardenSync.MutationText(G)
		if G:find("Rainbow", 1, true) then
			return "Rainbow"
		end
		if G:find("Gold", 1, true) then
			return "Gold"
		end
		V = tostring(V or "")
		if V == "Rainbow" or V == "Gold" then
			return V
		end
		return "Normal"
	end;
	GetVariantColour = function(G)
		if G == "Gold" then
			return q.TestGardenSync.Colours.Gold
		end
		if G == "Rainbow" then
			return q.TestGardenSync.Colours.Rainbow
		end
		return q.TestGardenSync.Colours.Normal
	end,
	GetSharedModules = function()
		return y.SharedModules or (y.ReplicatedStorage and y.ReplicatedStorage:FindFirstChild("SharedModules"))
	end,
	GetWeightFormat = function()
		if q.TestGardenSync.WeightFormatCache ~= nil then
			return q.TestGardenSync.WeightFormatCache ~= false and q.TestGardenSync.WeightFormatCache or nil
		end
		q.TestGardenSync.WeightFormatCache = false
		if type(y.WeightFormat) == "table" then
			q.TestGardenSync.WeightFormatCache = y.WeightFormat
			return y.WeightFormat
		end
		local G = q.TestGardenSync.GetSharedModules()
		local V = G and G:FindFirstChild("WeightFormat")
		local Z = q.TestGardenSync.SafeRequire(V)
