			return V
		end
		local Z = q.TestGardenSync.N(G.FinishedGrowingAt, 0)
		local j = q.TestGardenSync.N(G.GrowRate or G.StableGrowthAmount or G.GrowthRate, 0)
		if Z > 0 then
			local G = q.TestGardenSync.WallNow()
			if G >= Z then
				return y
			end
			if j > 0 then
				V = math.max(V, y - (((Z - G)) * j))
			end
		end
		return math.clamp(V, 0, y)
	end,
	GetPlantGrowthRate = function(G)
