			y.StableGrowthAmount = q.TestGardenSync.N(V.StableGrowthAmount or V.GrowRate or V.GrowthRate, T)
			y.PostBoostRate = q.TestGardenSync.N(y.PostBoostRate, y.StableGrowthAmount)
