	OnPlantGrowthUpdated = function(G, V, y, Z, j, i, c)
		if not q.TestGardenSync.IsMine(G) then
			return
		end
		local J = q.TestGardenSync.EnsurePlant(V)
		if J then
			q.TestGardenSync.AdvancePlant(J)
			local G = q.TestGardenSync.N(J.MaxAge, 0)
			local V = q.TestGardenSync.N(y, 0)
			local T = q.TestGardenSync.N(J.CurrentAge, 0)
			J.CurrentAge = G > 0 and math.min(math.max(V, T), G) or math.max(V, T)
			J.Age = J.CurrentAge
			J.StableGrowthAmount = q.TestGardenSync.N(Z, J.StableGrowthAmount or 0)
			local d = q.TestGardenSync.N(j, 0)
			J.BoostExpiresClock = d > 0 and (q.TestGardenSync.Now() + d) or 0
			J.PostBoostRate = q.TestGardenSync.N(i, J.StableGrowthAmount or 0)
			J.BoostSources = c or J.BoostSources or 0
			J.LastClock = q.TestGardenSync.Now()
			J.LastUpdate = q.TestGardenSync.Now()
		end
		q.TestGardenSync.Render()
	end;
	OnPlantAgeSync = function(G, V)
		if not q.TestGardenSync.IsMine(G) or type(V) ~= "table" then
			return
		end
		for G, V in pairs(V) do
			local y = q.TestGardenSync.EnsurePlant(G)
			if y then
				q.TestGardenSync.AdvancePlant(y)
				local G = q.TestGardenSync.N(y.MaxAge, 0)
				local Z = q.TestGardenSync.N(V, 0)
				if G > 0 and (q.TestGardenSync.N(y.CurrentAge, 0) >= G and Z < G) then
					Z = G
				end
				y.CurrentAge = G > 0 and math.min(math.max(Z, y.CurrentAge or 0), G) or math.max(Z, y.CurrentAge or 0)
				y.Age = y.CurrentAge
				y.LastClock = q.TestGardenSync.Now()
				y.LastUpdate = q.TestGardenSync.Now()
			end
		end
		q.TestGardenSync.Render()
	end;
	OnPlantMutationUpdated = function(G, V, y)
