	OnFruitRemoved = function(G, V, y)
		if not q.TestGardenSync.IsMine(G) then
			return
		end
		V = tostring(V or "")
		y = tostring(y or "")
		local Z = q.TestGardenSync.Key(V, y)
		local j = q.TestGardenSync.Fruits[Z]
		if j then
			j.Removed = true
			j.RemovedAt = q.TestGardenSync.Now()
			q.TestGardenSync.RemovedFruits[Z] = true
		end
		local i = q.TestGardenSync.Plants[V]
		if i and i.Fruits then
			i.Fruits[y] = nil
		end
		q.TestGardenSync.Render()
	end;
	OnFruitGrowthUpdated = function(G, V, y, Z, j)
		if not q.TestGardenSync.IsMine(G) then
			return
		end
		local i = q.TestGardenSync.EnsureFruit(V, y)
		if not i then
			return
		end
		q.TestGardenSync.AdvanceFruit(i)
		local c = q.TestGardenSync.N(i.MaxAge, 0)
		local J = q.TestGardenSync.N(Z, 0)
		local T = q.TestGardenSync.N(i.CurrentAge, 0)
		i.GrowthRate = q.TestGardenSync.N(j, i.GrowthRate or 0)
		i.CurrentAge = c > 0 and math.min(math.max(J, T), c) or math.max(J, T)
		i.Age = i.CurrentAge
		i.LastClock = q.TestGardenSync.Now()
		i.LastUpdate = q.TestGardenSync.Now()
		q.TestGardenSync.Render()
	end,
	OnFruitAgeSync = function(G, V, y)
		if not q.TestGardenSync.IsMine(G) or type(y) ~= "table" then
			return
		end
		for G, y in pairs(y) do
			local Z = q.TestGardenSync.EnsureFruit(V, G)
			if Z then
				q.TestGardenSync.AdvanceFruit(Z)
				local G = q.TestGardenSync.N(Z.MaxAge, 0)
				local V = q.TestGardenSync.N(y, 0)
				if G > 0 and (q.TestGardenSync.N(Z.CurrentAge, 0) >= G and V < G) then
					V = G
				end
				Z.CurrentAge = G > 0 and math.min(math.max(V, Z.CurrentAge or 0), G) or math.max(V, Z.CurrentAge or 0)
				Z.Age = Z.CurrentAge
				Z.LastClock = q.TestGardenSync.Now()
				Z.LastUpdate = q.TestGardenSync.Now()
			end
		end
		q.TestGardenSync.Render()
	end,
	OnFruitOvertimeGrowthUpdated = function(G, V, y, Z)
		if not q.TestGardenSync.IsMine(G) then
			return
		end
		local j = q.TestGardenSync.EnsureFruit(V, y)
		if j then
			j.OvertimeGrowth = q.TestGardenSync.N(Z, j.OvertimeGrowth or 1)
			j.LastUpdate = q.TestGardenSync.Now()
		end
		q.TestGardenSync.Render()
	end,
	OnFruitMutationUpdated = function(G, V, y, Z)
		if not q.TestGardenSync.IsMine(G) then
			return
		end
		local j = q.TestGardenSync.EnsureFruit(V, y)
		if j then
			j.Mutation = Z ~= "" and Z or nil
			j.LastUpdate = q.TestGardenSync.Now()
		end
		q.TestGardenSync.Render()
	end;
	ConnectGardenRemote = function(G, V)
		local Z = y.Networking and y.Networking.Garden
		local j = Z and Z[G]
		if not j or not j.OnClientEvent or type(V) ~= "function" then
			return false
		end
		local i, c = pcall(function()
			return j.OnClientEvent:Connect(V)
		end)
		if i and c then
			table.insert(q.TestGardenSync.Connections, c)
			return true
		end
		return false
	end,
	Start = function()
		if q.TestGardenSync.Started then
			q.TestGardenSync.Render()
			return true
		end
		q.TestGardenSync.Started = true
		q.TestGardenSync.SyncFromGarden()
		q.TestGardenSync.ConnectGardenRemote("PlantAdded", q.TestGardenSync.OnPlantAdded)
		q.TestGardenSync.ConnectGardenRemote("PlantRemoved", q.TestGardenSync.OnPlantRemoved)
		q.TestGardenSync.ConnectGardenRemote("PlantGrowthUpdated", q.TestGardenSync.OnPlantGrowthUpdated)
		q.TestGardenSync.ConnectGardenRemote("PlantAgeSync", q.TestGardenSync.OnPlantAgeSync)
		q.TestGardenSync.ConnectGardenRemote("PlantMutationUpdated", q.TestGardenSync.OnPlantMutationUpdated)
		q.TestGardenSync.ConnectGardenRemote("FruitAdded", q.TestGardenSync.OnFruitAdded)
		q.TestGardenSync.ConnectGardenRemote("FruitRemoved", q.TestGardenSync.OnFruitRemoved)
		q.TestGardenSync.ConnectGardenRemote("FruitGrowthUpdated", q.TestGardenSync.OnFruitGrowthUpdated)
		q.TestGardenSync.ConnectGardenRemote("FruitAgeSync", q.TestGardenSync.OnFruitAgeSync)
		q.TestGardenSync.ConnectGardenRemote("FruitOvertimeGrowthUpdated", q.TestGardenSync.OnFruitOvertimeGrowthUpdated)
		q.TestGardenSync.ConnectGardenRemote("FruitMutationUpdated", q.TestGardenSync.OnFruitMutationUpdated)
		q.TestGardenSync.RefreshPlantDropdown()
		q.TestGardenSync.StartRenderLoop()
		q.TestGardenSync.Render()
		return true
	end;
	Stop = function()
		q.TestGardenSync.Started = false
		for G, V in ipairs(q.TestGardenSync.Connections) do
			pcall(function()
				V:Disconnect()
			end)
		end
		table.clear(q.TestGardenSync.Connections)
		if q.TestGardenSync.Label then
			q.TestGardenSync.Label:SetText(q.TestGardenSync.C(q.TestGardenSync.Colours.Bad, "Garden sync test stopped."))
		end
		return true
	end,
	Reset = function()
		table.clear(q.TestGardenSync.Plants)
		table.clear(q.TestGardenSync.Fruits)
		table.clear(q.TestGardenSync.RemovedFruits)
		q.TestGardenSync.SyncFromGarden()
		q.TestGardenSync.RefreshPlantDropdown()
		q.TestGardenSync.Render()
	end,
	StartRenderLoop = function()
		if q.TestGardenSync.RenderLoopRunning then
			return
		end
		q.TestGardenSync.RenderLoopRunning = true
		task.spawn(function()
			while q.TestGardenSync.Started do
				q.TestGardenSync.Render()
				task.wait(q.TestGardenSync.RenderInterval)
			end
			q.TestGardenSync.RenderLoopRunning = false
		end)
	end,
	GetPlantList = function()
		local G = {}
		for V, y in pairs(q.TestGardenSync.Plants) do
			if type(y) == "table" and not y.Removed then
				table.insert(G, y)
			end
		end
		table.sort(G, function(G, V)
			return tostring(G.PlantName or "") < tostring(V.PlantName or "")
		end)
		return G
	end;
	BuildFruitResult = function(G, V, y)
		if type(G) ~= "table" then
			return nil
		end
		local Z = tostring(G.PlantName or "")
		local j = tostring(G.Id or G.PlantId or "")
		if Z == "" or j == "" then
			return nil
		end
		local i = y and G or V
		if type(i) ~= "table" then
			return nil
		end
		if y then
			q.TestGardenSync.AdvancePlant(G)
		else
			q.TestGardenSync.AdvanceFruit(V)
		end
		local c = y and q.TestGardenSync.IsPlantReady(G) or q.TestGardenSync.IsFruitReady(V)
		if not c then
			return nil
		end
		local J = tostring(i.Mutation or G.Mutation or "")
		local T = q.TestGardenSync.GetVariant(J, i.Variant or G.Variant)
		local d = q.TestGardenSync.GetWeightData(Z, i, y)
		return {
			name = Z;
			plantId = j,
			fruitId = y and "" or tostring(V.FruitId or ""),
			w = d.kg;
			kg = d.kg;
			kg_text = d.text;
			grams = d.grams;
			base_weight = d.base;
			size_multiplier = d.size,
			overtime_growth = d.overtime;
			has_weight = d.has_weight;
			r = (type(q.SeedRarity) == "table" and q.SeedRarity[Z]) or "Common";
			m = J;
			v = T,
			age = y and q.TestGardenSync.N(G.CurrentAge, G.Age or 0) or q.TestGardenSync.N(V.CurrentAge, 0);
			max_age = y and q.TestGardenSync.N(G.MaxAge, 0) or q.TestGardenSync.N(V.MaxAge, 0);
			grow_rate = y and q.TestGardenSync.GetPlantGrowthRate(G) or q.TestGardenSync.N(V.GrowthRate, 0);
			ready = true,
			sync = true;
			single_harvest = y == true,
			raw = i,
			plant_raw = G
		}
	end,
	GetFruits = function()
		if not q.TestGardenSync.Started then
			q.TestGardenSync.Start()
		else
			q.TestGardenSync.SyncFromGarden()
		end
		local G = {}
		for V, y in pairs(q.TestGardenSync.Plants) do
			if type(y) ~= "table" or y.Removed then
				continue
			end
			local Z = tostring(y.PlantName or "")
			if Z == "" then
				continue
			end
			if q.TestGardenSync.IsSingleHarvestPlant(Z) then
				local V = q.TestGardenSync.BuildFruitResult(y, nil, true)
				if V and V.has_weight then
					table.insert(G, V)
				end
			else
				for V, Z in pairs(y.Fruits or {}) do
					if type(Z) == "table" and not Z.Removed then
						local V = q.TestGardenSync.BuildFruitResult(y, Z, false)
						if V and V.has_weight then
							table.insert(G, V)
						end
					end
				end
			end
		end
		table.sort(G, function(G, V)
			local y = type(q.RarityRank) == "table" and q.RarityRank or {}
			local Z = y[G.r] or 0
			local j = y[V.r] or 0
			if Z ~= j then
				return Z > j
			end
			local i = type(G.m) == "string" and G.m ~= ""
			local c = type(V.m) == "string" and V.m ~= ""
			if i ~= c then
				return i
			end
			return ((tonumber(G.kg) or 0)) > ((tonumber(V.kg) or 0))
		end)
		return G
	end;
	GetReadyFruits = function()
		return q.TestGardenSync.GetFruits()
	end;
	GetPlantDropdownValues = function()
		local G = {}
		for V, y in ipairs(q.TestGardenSync.GetPlantList()) do
			local Z = tostring(y.PlantName or "Plant")
			local j = 0
			local i = 0
			local c = q.TestGardenSync.IsSingleHarvestPlant(Z)
			if c then
				j = 1
				if q.TestGardenSync.IsPlantReady(y) then
					i = 1
				end
			else
				for G, V in pairs(y.Fruits or {}) do
					if type(V) == "table" and not V.Removed then
						j += 1
						if q.TestGardenSync.IsFruitReady(V) then
							i += 1
						end
					end
				end
			end
			table.insert(G, {
				Text = string.format("%s <font color=\"#888888\">%s</font> <font color=\"#7CFC00\">%d ready</font><font color=\"#AAAAAA\">/%d</font>%s", q.TestGardenSync.Html(Z), q.TestGardenSync.Html(q.TestGardenSync.ShortId(y.Id)), i, j, c and " <font color=\"#FFD166\">Single</font>" or "");
				Value = y.Id
			})
		end
		return G
	end;
	RefreshPlantDropdown = function()
		if q.TestGardenSync.Dropdown and type(q.TestGardenSync.Dropdown.SetValues) == "function" then
			q.TestGardenSync.Dropdown:SetValues(q.TestGardenSync.GetPlantDropdownValues())
		end
	end,
	SetWatchPlant = function(G)
		q.TestGardenSync.WatchPlantId = tostring(G or "")
