	end;
	FormatFruitLine = function(G, V, y, Z)
		local j = q.TestGardenSync.Colours
		local i = Z and V or y
		local c = tostring(V.PlantName or "")
		if Z then
			q.TestGardenSync.AdvancePlant(V)
		else
			q.TestGardenSync.AdvanceFruit(y)
		end
		local J = Z and q.TestGardenSync.IsPlantReady(V) or q.TestGardenSync.IsFruitReady(y)
		local T = tostring(i and i.Mutation or V.Mutation or "")
		local d = q.TestGardenSync.GetVariant(T, i and i.Variant or V.Variant)
		local u = q.TestGardenSync.GetVariantColour(d)
		local g = q.TestGardenSync.GetWeightData(c, i, Z)
		local E = Z and q.TestGardenSync.N(V.CurrentAge, V.Age or 0) or q.TestGardenSync.N(y.CurrentAge, 0)
		local a = Z and q.TestGardenSync.N(V.MaxAge, 0) or q.TestGardenSync.N(y.MaxAge, 0)
		local H = Z and q.TestGardenSync.GetPlantGrowthRate(V) or q.TestGardenSync.N(y.GrowthRate, 0)
		return string.format("   %s %s %s %s %s %s %s %s %s", q.TestGardenSync.C(J and j.Ready or j.Growing, J and "READY" or "GROWING"), q.TestGardenSync.C(j.Fruit, Z and "Single Harvest" or ("Fruit " .. tostring(G))), q.TestGardenSync.C(j.Id, "[" .. (q.TestGardenSync.ShortId(Z and V.Id or y.FruitId) .. "]")), q.TestGardenSync.C(j.Muted, "Age: " .. (tostring(q.TestGardenSync.Round2(E)) .. ("/" .. tostring(q.TestGardenSync.N(a, 0))))), q.TestGardenSync.C(j.Muted, "Rate: " .. tostring(q.TestGardenSync.Round4(H))), q.TestGardenSync.C(j.Kg, "KG: " .. g.text), q.TestGardenSync.C(j.Muted, "Base: " .. tostring(q.TestGardenSync.Round2(g.base))), q.TestGardenSync.C(j.Muted, "Size: " .. (tostring(q.TestGardenSync.Round2(g.size)) .. (" OT: " .. tostring(q.TestGardenSync.Round2(g.overtime))))), T ~= "" and q.TestGardenSync.C(u, "Mutation: " .. (T .. (" / " .. d))) or q.TestGardenSync.C(j.Normal, "Mutation: none / Normal"))
	end,
	FormatPlant = function(G)
		if type(G) ~= "table" then
			return ""
		end
		q.TestGardenSync.AdvancePlant(G)
		local V = q.TestGardenSync.Colours
		local y = {}
		local Z = tostring(G.PlantName or "Unknown")
		local j = q.TestGardenSync.IsSingleHarvestPlant(Z)
		local i = q.TestGardenSync.MutationText(G.Mutation)
		local c = q.TestGardenSync.GetVariant(i, G.Variant)
		local J = q.TestGardenSync.GetVariantColour(c)
		local T = j and q.TestGardenSync.GetWeightData(Z, G, true) or nil
		table.insert(y, string.format("%s %s %s %s %s %s", q.TestGardenSync.C(V.Plant, "Plant: " .. Z), q.TestGardenSync.C(V.Id, "[" .. (q.TestGardenSync.ShortId(G.Id) .. "]")), q.TestGardenSync.C(J, "Variant: " .. c), q.TestGardenSync.C(V.Muted, "Age: " .. (tostring(q.TestGardenSync.Round2(q.TestGardenSync.N(G.CurrentAge, G.Age or 0))) .. ("/" .. tostring(q.TestGardenSync.N(G.MaxAge, 0))))), j and q.TestGardenSync.C("#FFD166", "Single Harvest") or q.TestGardenSync.C(V.Muted, "Multi Harvest"), T and q.TestGardenSync.C(V.Kg, "KG: " .. T.text) or q.TestGardenSync.C(V.Muted, "KG: fruit-based")))
		if i ~= "" then
			table.insert(y, "   " .. q.TestGardenSync.C(J, "Plant Mutation: " .. i))
		end
		if j then
			table.insert(y, q.TestGardenSync.FormatFruitLine(1, G, nil, true))
			return table.concat(y, "\n")
		end
		local d = {}
		for G, V in pairs(G.Fruits or {}) do
			if type(V) == "table" and not V.Removed then
				q.TestGardenSync.AdvanceFruit(V)
				table.insert(d, V)
			end
		end
		table.sort(d, function(G, V)
			local y = q.TestGardenSync.IsFruitReady(G)
			local Z = q.TestGardenSync.IsFruitReady(V)
			if y ~= Z then
				return y
			end
			return q.TestGardenSync.N(G.CurrentAge, 0) > q.TestGardenSync.N(V.CurrentAge, 0)
		end)
		for Z, j in ipairs(d) do
			if Z > q.TestGardenSync.MaxFruitsPerPlant then
				table.insert(y, q.TestGardenSync.C(V.Muted, "   ... +" .. (tostring(# d - q.TestGardenSync.MaxFruitsPerPlant) .. " more fruits")))
				break
			end
			table.insert(y, q.TestGardenSync.FormatFruitLine(Z, G, j, false))
		end
		if # d == 0 then
			table.insert(y, q.TestGardenSync.C(V.Muted, "   No fruits stored for this plant yet."))
		end
		return table.concat(y, "\n")
	end;
	BuildText = function()
		local G = q.TestGardenSync.Colours
		local V = q.TestGardenSync.GetPlantList()
		local y = 0
		local Z = 0
		local j = 0
		for G, V in ipairs(V) do
			local i = tostring(V.PlantName or "")
			if q.TestGardenSync.IsSingleHarvestPlant(i) then
				j += 1
				y += 1
				if q.TestGardenSync.IsPlantReady(V) then
					Z += 1
				end
			else
				for G, V in pairs(V.Fruits or {}) do
					if type(V) == "table" and not V.Removed then
						y += 1
						if q.TestGardenSync.IsFruitReady(V) then
							Z += 1
						end
					end
				end
			end
		end
		local i = {
			q.TestGardenSync.C(G.Title, "DATA GARDEN SYNC TEST"),
			q.TestGardenSync.C(G.Muted, "Plants: " .. (tostring(# V) .. (" | Single: " .. (tostring(j) .. (" | Fruits: " .. (tostring(y) .. (" | Ready: " .. (tostring(Z) .. (" | Events: " .. tostring(# q.TestGardenSync.Connections))))))))));
			""
		}
		local c = tostring(q.TestGardenSync.WatchPlantId or "")
		if c ~= "" and q.TestGardenSync.Plants[c] then
			table.insert(i, q.TestGardenSync.FormatPlant(q.TestGardenSync.Plants[c]))
			return table.concat(i, "\n")
		end
		local J = 0
		for y, Z in ipairs(V) do
			J += 1
			if J > q.TestGardenSync.MaxPlants then
				table.insert(i, q.TestGardenSync.C(G.Muted, "... +" .. (tostring(# V - q.TestGardenSync.MaxPlants) .. " more plants. Select one from dropdown to watch live.")))
				break
			end
			table.insert(i, q.TestGardenSync.FormatPlant(Z))
			table.insert(i, "")
		end
		if # V == 0 then
			table.insert(i, q.TestGardenSync.C(G.Bad, "No plants loaded yet. Press Start / Refresh."))
		end
		return table.concat(i, "\n")
	end,
	Render = function()
		if not q.TestGardenSync.Label then
			return false
		end
		local G = q.TestGardenSync.BuildText()
		q.TestGardenSync.Label:SetText(G)
		return true
	end,
