q.SaveManagerUi = function()
	local G = T:AddTab({
		Name = "Save Manager",
		Description = "Online saves and account sync",
		Icon = "cloud-cog"
	})
	local V = G:AddLeftGroupbox("Save Online", "cloud-upload")
	local y = G:AddRightGroupbox("Real Time Sync", "refresh-cw")
	local Z = G:AddLeftGroupbox("Share Launcher", "copy")
	q.SaveSyncUiRefs = q.SaveSyncUiRefs or {}
	if V then
		V:AddLabel({
			Text = "Save your settings online and use your code on other accounts.";
			DoesWrap = true
		})
		q.SaveSyncUiRefs.CodeLabel = V:AddLabel({
			Text = "Your code: <font color=\'#FFCC66\'>Enable Save Online to create one</font>";
			DoesWrap = true
		})
		q.SaveSyncUiRefs.SaveOnlineStatusLabel = V:AddLabel({
			Text = q.SaveSyncStatusText ~= "" and q.SaveSyncStatusText or "<font color=\'#888888\'>Ready</font>",
			DoesWrap = true
		})
		V:AddButton({
			Text = "Load Saved Data",
			Tooltip = "Loads this account\'s online save after confirmation.",
			Func = function()
				if not E.SaveSync.GuardPremiumSaveSync("Premium required to load online save") then
					return
				end
				if not J or type(J.Confirm) ~= "function" then
					E.SaveSync.PullSaveSync("", true)
					return
				end
				J:Confirm({
					Title = "Load saved data?";
					Description = "This will apply the online save for this account and update your local settings.";
					Callback = function(G)
						if G then
							E.SaveSync.PullSaveSync("", true)
						end
					end
				})
			end
		})
		V:AddToggle("save_sync_online_enabled_ui", {
			Text = "Enable Save Online";
			Default = X.save_sync_online_enabled,
			Tooltip = "Saves this account\'s settings online when they change.",
			Callback = function(G)
				if G == true and not E.SaveSync.GuardPremiumSaveSync("Premium required for online saving") then
					return
				end
				X.save_sync_online_enabled = G == true
				a.Save.SaveDataSync()
				if X.save_sync_online_enabled then
					E.SaveSync.SendPushSaveSync("manual")
				else
					E.SaveSync.SetStatusSaveSync("Online saving disabled", "#CFCFCF")
					E.SaveSync.RefreshUiSaveSync()
				end
			end
		})
		V:AddButton({
			Text = "Save Now",
			Tooltip = "Uploads your current settings now.";
			Func = function()
				if not E.SaveSync.GuardPremiumSaveSync("Premium required for online saving") then
					return
				end
				E.SaveSync.SendPushSaveSync("manual")
			end
		})
	end
	if y then
		y:AddLabel({
			Text = "Enter another account\'s code to copy its saved settings.";
			DoesWrap = true
		})
		q.SaveSyncUiRefs.ShareCodeLabel = y:AddLabel({
			Text = tostring(X.save_sync_share_code or "") ~= "" and "Saved sync code: <font color=\'#7CFC00\'>" .. (tostring(X.save_sync_share_code or "") .. "</font>") or "No sync code saved. Type a code and press Enter to save it.",
			DoesWrap = true
		})
		q.SaveSyncUiRefs.RealtimeSyncStatusLabel = y:AddLabel({
			Text = q.SaveSyncStatusText ~= "" and q.SaveSyncStatusText or "<font color=\'#888888\'>Ready</font>";
			DoesWrap = true
		})
		y:AddInput("save_sync_share_code_ui", {
			Text = "Share Code";
			Default = X.save_sync_share_code;
			Numeric = false,
			AllowEmpty = true;
			Finished = true;
			ClearTextOnFocus = false;
			Placeholder = "Enter code then press Enter",
			Tooltip = "Type the account code and press Enter to save it.";
			Callback = function(G)
				local V = E.SaveSync.CleanShareCodeSaveSync(G)
				X.save_sync_share_code = V
				X.save_sync_pull_revision = 0
				X.save_sync_pull_hash = ""
				a.Save.SaveDataSync()
				E.SaveSync.SetStatusSaveSync(V ~= "" and "Sync code updated" or "No code entered. Type a code and press Enter to save it.", V ~= "" and "#CFCFCF" or "#FFCC66")
				E.SaveSync.RefreshUiSaveSync()
			end
		})
		y:AddToggle("save_sync_auto_pull_enabled_ui", {
			Text = "Enable Sync";
			Default = X.save_sync_auto_pull_enabled,
			Tooltip = "Checks the entered code every few seconds and applies new settings.",
			Callback = function(G)
				if G == true and not E.SaveSync.GuardPremiumSaveSync("Premium required for online sync") then
					return
				end
				X.save_sync_auto_pull_enabled = G == true
				a.Save.SaveDataSync()
				if X.save_sync_auto_pull_enabled then
					local G = E.SaveSync.CleanShareCodeSaveSync(X.save_sync_share_code)
					if G == "" then
						E.SaveSync.SetStatusSaveSync("Enter a share code", "#FFCC66")
						E.SaveSync.RefreshUiSaveSync()
						return
					end
					E.SaveSync.PullSaveSync(G, false)
				else
					E.SaveSync.SetStatusSaveSync("Real time sync disabled", "#CFCFCF")
					E.SaveSync.RefreshUiSaveSync()
				end
			end
		})
		y:AddButton({
			Text = "Pull Now";
			Tooltip = "Checks the entered code now.",
			Func = function()
				if not E.SaveSync.GuardPremiumSaveSync("Premium required for online sync") then
					return
				end
				local G = E.SaveSync.CleanShareCodeSaveSync(X.save_sync_share_code)
				if G == "" then
					E.SaveSync.SetStatusSaveSync("Enter a share code", "#FFCC66")
					E.SaveSync.RefreshUiSaveSync()
					return
				end
				E.SaveSync.PullSaveSync(G, true)
			end
		})
	end
	if Z then
		Z:AddLabel({
			Text = "Copy a small launcher for your other accounts. It only sets your key, mode and sync code.",
			DoesWrap = true
		})
		Z:AddButton({
			Text = "Copy Share Launcher",
			Tooltip = "Copies a launcher that connects another account to this saved code.";
			Func = function()
				local G = a.Config.BuildShareLauncherText()
				if type(G) ~= "string" or G == "" then
					q.Notify("Failed to create launcher", 3)
					return
				end
				u.CopyToClipBoard(G)
				q.Notify("Share launcher copied. Add your key before using it.", 3)
			end
		})
	end
	E.SaveSync.RefreshUiSaveSync()
end
