q.SimulateRealMobileTap = function()
	if not E.PlayerData.GetLoadingScreenActive() then
		return
	end
	if not u.UserDevice.IsMobile() then
		return
	end
	local G = game:GetService("VirtualInputManager")
	local V = workspace.CurrentCamera
	if not V then
		return false
	end
	local y = V.ViewportSize
	if y.X <= 0 or y.Y <= 0 then
		return false
	end
	local Z = 35
	local j = Z
	local i = y.Y - Z
	return pcall(function()
		G:SendTouchEvent(1, 0, j, i)
		task.wait(.08)
		G:SendTouchEvent(1, 2, j, i)
	end)
end
q.SimulateScreenTapWithGui = function()
	if not E.PlayerData.GetLoadingScreenActive() then
		return
	end
	if not u.UserDevice.IsPC() then
		return
	end
	local G = game:GetService("VirtualInputManager")
	local V = workspace.CurrentCamera
	if not V then
		return false
	end
	local y = V.ViewportSize
	if y.X <= 0 or y.Y <= 0 then
		return false
	end
	local Z = 35
	local j = Z
	local i = y.Y - Z
	return pcall(function()
		G:SendMouseButtonEvent(j, i, 0, true, game, 1)
		task.wait(.05)
		G:SendMouseButtonEvent(j, i, 0, false, game, 1)
	end)
end
q.loading_check_started = time() + 90
while time() < q.loading_check_started do
	if E.PlayerData.GetLoadingScreenActive() == false then
		break
	end
	q.SimulateRealMobileTap()
	q.SimulateScreenTapWithGui()
	task.wait(10)
end
